-- Poems batch 252
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1be817ec-88e9-40e7-a296-81299bf8b8c9','新春','真山民','宋','宋诗','song-poetry','','[]','餘凍雪初乾，初晴日驟暄。',48,'全唐诗/poet.song.227000.json','["餘凍雪初乾，初晴日驟暄。", "人心新歲月，春意舊乾坤。", "煙碧柳生色，燒青草返魂。", "東風無厚薄，隨例到衡門。"]'),
('6663ac57-0949-4c41-bf2a-3855e9a0b981','光霽閣晚望','真山民','宋','宋诗','song-poetry','','[]','一閣納萬象，危闌俯渺茫。',48,'全唐诗/poet.song.227000.json','["一閣納萬象，危闌俯渺茫。", "白沙難認月，黄葉易爲霜。", "宿鳥投烟嶼，歸樵趁野航。", "孤吟誰是伴，漁笛起滄浪。"]'),
('94ba2b0b-a8dd-44ca-8ab8-e89a8466defb','興福寺','真山民','宋','宋诗','song-poetry','','[]','爲厭市喧雜，携詩來此吟。',48,'全唐诗/poet.song.227000.json','["爲厭市喧雜，携詩來此吟。", "鳥聲山路靜，花影寺門深。", "樓閣莊嚴界，池塘清浄心。", "松風亦好事，送客出前林。"]'),
('4d5288ea-5461-4dc9-9362-5f0e995a8140','夏晚江行','真山民','宋','宋诗','song-poetry','','[]','行盡山頭路，江空带夕暉。',48,'全唐诗/poet.song.227000.json','["行盡山頭路，江空带夕暉。", "風蟬聲不定，水鳥影同飛。", "蕭散烏藤杖，輕鬖白苧衣。", "試呼垂釣者，分我半苔磯。"]'),
('e69e8ff9-300f-4e93-89a0-05b97d8e2d90','修真院訪崔道士','真山民','宋','宋诗','song-poetry','','[]','竹扉蒼蘚牆，林下小丹房。',48,'全唐诗/poet.song.227000.json','["竹扉蒼蘚牆，林下小丹房。", "風定香烟直，月斜簾影長。", "瀹茶泉味別，點易露痕香。", "安得棲塵外，求師却老方。"]'),
('5ce53203-3f99-47ef-b302-2ae8e49410b0','春遊和胡叔芳韻','真山民','宋','宋诗','song-poetry','','[]','春光潑眼明，占勝得新亭。',48,'全唐诗/poet.song.227000.json','["春光潑眼明，占勝得新亭。", "棠醉風扶起，柳眠鶑喚醒。", "非無盃泛綠，安得鬢皆青。", "且事日爲樂，歌聲莫暫停。"]'),
('334a1335-65bb-4a19-a0ac-c8039bcbdbd3','山亭避暑','真山民','宋','宋诗','song-poetry','','[]','怕礙清風入，丁寧莫下簾。',48,'全唐诗/poet.song.227000.json','["怕礙清風入，丁寧莫下簾。", "地皆宜避暑，人自要趨炎。", "竹色水千頃，松聲風四簷。", "此中有幽致，多取未傷廉。"]'),
('83607b33-43ac-4526-b239-f682d0aaa5a3','三山旅夜','真山民','宋','宋诗','song-poetry','','[]','獨坐本無况，凄凉更旅中。',48,'全唐诗/poet.song.227000.json','["獨坐本無况，凄凉更旅中。", "檻低簷礙月，窗破紙吟風。", "鄰館笛三弄，譙樓鼓二通。", "半觴聊自適，新荔擘輕紅。"]'),
('3b8d83f2-970f-4e05-a3e4-8cdcfe61dd78','枕上偶成','真山民','宋','宋诗','song-poetry','','[]','長夜更難曉，天寒吟思清。',48,'全唐诗/poet.song.227000.json','["長夜更難曉，天寒吟思清。", "夢魂山館枕，燈影雪窗檠。", "守拙踈生理，安貧識世情。", "凄風響簷竹，豈是不平聲。"]'),
('166fbfe1-91ee-4136-bbcf-07241bc646a1','泊白沙渡','真山民','宋','宋诗','song-poetry','','[]','日暮片帆落，渡頭生暝烟。',48,'全唐诗/poet.song.227000.json','["日暮片帆落，渡頭生暝烟。", "與鷗分渚泊，邀月共船眠。", "燈影漁舟外，湍聲客枕邊。", "離懷正無奈，況復聽啼鵑。"]'),
('628b2026-9811-42d9-a828-baad32c5542c','夜話無上人房','真山民','宋','宋诗','song-poetry','','[]','蒲團一榻上，坐到夜將分。',48,'全唐诗/poet.song.227000.json','["蒲團一榻上，坐到夜將分。", "窗月燈昏見，巖泉雨歇聞。", "茶甌勝飲酒，禪語當論文。", "只恐紅塵跡，涴師松下雲。"]'),
('fe1c7a63-6b82-4cd1-add4-4c9dc2f73372','獨坐','真山民','宋','宋诗','song-poetry','','[]','寒齋淡無味，孤坐思悠悠。',48,'全唐诗/poet.song.227000.json','["寒齋淡無味，孤坐思悠悠。", "時事三緘口，年光一轉頭。", "有書遮老眼，無藥療閒愁。", "假使丹心在，衰遲也合休。"]'),
('02e8b047-2d3d-4266-8880-df49b383d0a8','春日','真山民','宋','宋诗','song-poetry','','[]','韶光今幾許，我欲問流鶑。',48,'全唐诗/poet.song.227000.json','["韶光今幾許，我欲問流鶑。", "花影掃不去，草根鋤又生。", "心空諸妄息，身老萬緣輕。", "正是春風好，幽蘭不肯爭。"]'),
('ce24900b-b314-4386-9b2b-0972eaecf391','曉行山間','真山民','宋','宋诗','song-poetry','','[]','出門誰是伴，只約瘦藤行。',48,'全唐诗/poet.song.227000.json','["出門誰是伴，只約瘦藤行。", "一二里山徑，兩三聲曉鶑。", "亂峰相出沒，初日乍陰晴。", "僧舍在何許，隔林鐘磬清。"]'),
('62d2e10f-af48-4410-8542-f81bad4fef66','山間次季芳韻','真山民','宋','宋诗','song-poetry','','[]','好山多在眼，塵事少關心。',48,'全唐诗/poet.song.227000.json','["好山多在眼，塵事少關心。", "風竹有聲畫，石泉無操琴。", "許猿分野果，留鶴守雲林。", "不是閒邊客，誰來此地吟。"]'),
('db13ea50-fe9e-4131-8296-97e8fa87c84b','春感','真山民','宋','宋诗','song-poetry','','[]','春光元自好，我却爲春愁。',48,'全唐诗/poet.song.227000.json','["春光元自好，我却爲春愁。", "但見柳青眼，不知人白頭。", "一身浮似寄，百歲去如流。", "頼有芳樽在，花前日醉遊。"]'),
('620fc2f9-2527-4f62-9e4b-74688ff4510c','春曉園中','真山民','宋','宋诗','song-poetry','','[]','綠陰留我立，清曉小闌東。',48,'全唐诗/poet.song.227000.json','["綠陰留我立，清曉小闌東。", "林外一鳩雨，柳邊雙燕風。", "吟懷愁渺渺，春事去匆匆。", "莫恨芳菲盡，葵榴花又紅。"]'),
('1ee468f6-4a38-4175-8b64-9eed3504beab','溪行','真山民','宋','宋诗','song-poetry','','[]','春暖溪西路，行吟又幾迴。',48,'全唐诗/poet.song.227000.json','["春暖溪西路，行吟又幾迴。", "水清明白鷺，花落失青苔。", "雲過日吞吐，樹摇風往來。", "漁歌聽未了，欲去又徘徊。"]'),
('1b4cc762-893c-46e5-86e1-d346679efd9e','除夜約張梅境飲','真山民','宋','宋诗','song-poetry','','[]','今日又除夕，君能爲我來。',48,'全唐诗/poet.song.227000.json','["今日又除夕，君能爲我來。", "燭光紅照席，酒浪綠摇杯。", "臘带愁吟去，春隨笑臉回。", "相看俱健在，莫管歲華催。"]'),
('e39a6425-c39b-4430-945c-232c9ffcf903','渡江之越宿蕭山縣','真山民','宋','宋诗','song-poetry','','[]','昨夜大江舟，今宵小驛樓。',48,'全唐诗/poet.song.227000.json','["昨夜大江舟，今宵小驛樓。", "隻身千里客，孤枕一燈秋。", "市酒難成醉，鄉書莫寄愁。", "胸中無史記，浪作會稽游。"]'),
('1f168fa3-1dc2-48b7-bdfe-3bf25aacdcdd','宿寶勝寺','真山民','宋','宋诗','song-poetry','','[]','苦吟吟未了，只向兩廊行。',48,'全唐诗/poet.song.227000.json','["苦吟吟未了，只向兩廊行。", "月去塔無影，風來鐸有聲。", "禪心隨水凈，佛眼共燈明。", "安得雲邊住，與僧分此情。"]'),
('ef0b273e-de73-4023-85e7-ab532dfe8eea','閒居','真山民','宋','宋诗','song-poetry','','[]','虛明兩竹窗，濟楚一書房。',48,'全唐诗/poet.song.227000.json','["虛明兩竹窗，濟楚一書房。", "風動鳥移樹，花香蝶過牆。", "身安知病少，晝靜覺春長。", "未必全無事，終焉也勝忙。"]'),
('fdf55d5d-ba89-4285-ba1d-6796b468f9c1','兵後寓舍送春','真山民','宋','宋诗','song-poetry','','[]','觸景多懷舊，憑欄易愴神。',48,'全唐诗/poet.song.227000.json','["觸景多懷舊，憑欄易愴神。", "飛花游蕩子，古木老成人。", "世換山如醉，田荒草自新。", "鄉關渺何處，回首暗風塵。"]'),
('5247504a-f55c-4875-9d0a-88c0c960d27e','樓居','真山民','宋','宋诗','song-poetry','','[]','携書來過此，便覺少塵埃。',48,'全唐诗/poet.song.227000.json','["携書來過此，便覺少塵埃。", "簷冷留雲宿，窗明報月來。", "閒愁山隔斷，幽夢鳥呼回。", "湖海元龍氣，從渠俗子猜。"]'),
('9d50bc4b-80e1-4309-8b1b-34db38c6c49d','蘭溪舟中','真山民','宋','宋诗','song-poetry','','[]','一舸下中流，西風兩岸秋。',48,'全唐诗/poet.song.227000.json','["一舸下中流，西風兩岸秋。", "櫓聲摇客夢，帆影挂離愁。", "落日魚蝦市，長煙蘆荻洲。", "篙人夜相語，明發又嚴州。"]'),
('cb249f6a-33f9-47f0-a115-6db735bce61c','兵後劉秀寬見過','真山民','宋','宋诗','song-poetry','','[]','冉冉歲云暮，閒居安所之。',48,'全唐诗/poet.song.227000.json','["冉冉歲云暮，閒居安所之。", "途窮身是累，痛定語猶悲。", "衰鬢數莖雪，空囊一卷詩。", "儒衣例如此，惜也不逢時。"]'),
('50b441bd-3453-480b-81bc-f20840c65741','清明','真山民','宋','宋诗','song-poetry','','[]','清明今日是，原上一經過。',48,'全唐诗/poet.song.227000.json','["清明今日是，原上一經過。", "新葬塚無數，未來人更多。", "此生曾悟否，不樂復如何。", "莫待澆墳土，樽前且醉歌。"]'),
('993d07d5-ae14-47d4-a7a4-16da4d43b0ec','臨江曉行','真山民','宋','宋诗','song-poetry','','[]','茅舍亂雞聲，疎林淡見星。',48,'全唐诗/poet.song.227000.json','["茅舍亂雞聲，疎林淡見星。", "霜輕留草綠，霧暗失山青。", "蹤跡去來燕，交游聚散萍。", "浮生原是客，不必恨飄零。"]'),
('800dcdf7-94b6-4c7f-b9ef-43bd6a177b53','寄郭月篷','真山民','宋','宋诗','song-poetry','','[]','煙波秋草外，活計一漁篷。',48,'全唐诗/poet.song.227000.json','["煙波秋草外，活計一漁篷。", "淡月明寒葦，新霜醉曉楓。", "身雖殊出處，道豈有窮通。", "俯仰看人面，何如數過鴻。"]'),
('fe516620-559c-460a-b997-56fb4db47eac','舟中峽口','真山民','宋','宋诗','song-poetry','','[]','亂山如碧玉，處處見鵑花。',48,'全唐诗/poet.song.227000.json','["亂山如碧玉，處處見鵑花。", "水漲傍分港，舟行倒走沙。", "宿依沽酒市，飯過釣魚家。", "喜脫風波險，推篷數暝鴉。"]'),
('545512c0-5b2e-4655-a1d6-b4464540fd7f','次韻章劍溪山居','真山民','宋','宋诗','song-poetry','','[]','想無書赴隴，林鶴莫驚猜。',48,'全唐诗/poet.song.227000.json','["想無書赴隴，林鶴莫驚猜。", "曳杖雲同出，開簾山自來。", "池堪供洗硯，籬不礙觀梅。", "靜倚長松立，藤花點翠苔。"]'),
('cfc5402c-e991-40ae-a103-c9e9391cb1b5','夏日','真山民','宋','宋诗','song-poetry','','[]','虛窗暑亦凉，境靜晝偏長。',48,'全唐诗/poet.song.227000.json','["虛窗暑亦凉，境靜晝偏長。", "樹色煙明滅，蟬聲風抑揚。", "家貧書是業，身老睡爲鄉。", "赤日黄埃客，紛紛爲底忙。"]'),
('64a83c7e-8c58-4c55-a94f-3fa7f0e0fadd','歲除寄王中齋','真山民','宋','宋诗','song-poetry','','[]','徂歲已匆匆，何人似此翁。',48,'全唐诗/poet.song.227000.json','["徂歲已匆匆，何人似此翁。", "事雖隨世異，道不與冬窮。", "身老心猶壯，髯斑臉自紅。", "椒花一盃酒，明日又春風。"]'),
('007b73c0-0fcf-4e68-a744-cfbd813f2fc0','宋道士同游白雲關','真山民','宋','宋诗','song-poetry','','[]','扶携方外友，來入白雲關。',48,'全唐诗/poet.song.227000.json','["扶携方外友，來入白雲關。", "八九峯如畫，兩三人倚欄。", "棋聲敲竹外，簾影落花間。", "一曲瑶琴罷，翠陰生晝寒。"]'),
('d3af2cf3-595d-411d-9838-bcdb4e20734f','妙因寺次施敬所韻','真山民','宋','宋诗','song-poetry','','[]','松蘿一徑陰，踏破白雲深。',48,'全唐诗/poet.song.227000.json','["松蘿一徑陰，踏破白雲深。", "約客分茶供，逢僧倚竹吟。", "鼠留香篆迹，禽和閣鈴音。", "話久不知晚，新螢照出林。"]'),
('c0565876-e2a2-4ad3-99fb-5ed2e39343ff','晚春','真山民','宋','宋诗','song-poetry','','[]','有恨青春老，無營白晝長。',48,'全唐诗/poet.song.227000.json','["有恨青春老，無營白晝長。", "葉新林換綠，花落地生香。", "雨意一番足，人家百事忙。", "爲儒竟成誤，悔不早農桑。"]'),
('99babd9b-1396-4a52-9446-4b02dd47d8d3','冬雪','真山民','宋','宋诗','song-poetry','','[]','雪凍飛禽少，林深落葉多。',48,'全唐诗/poet.song.227000.json','["雪凍飛禽少，林深落葉多。", "寒塘倒山影，空谷答樵歌。", "不有梅花在，其如詩思何。", "霜風吹落帽，應嘆鬢絲皤。"]'),
('14723c67-9e78-419f-b8cd-1683d8e88af0','新凉','真山民','宋','宋诗','song-poetry','','[]','煙火人幽處，田園秋暮時。',48,'全唐诗/poet.song.227000.json','["煙火人幽處，田園秋暮時。", "深村人到少，閏月稻黄遲。", "旋决渠分水，新編竹補籬。", "地爐煨芋栗，莫遣貴人知。"]'),
('71b37efd-622f-4f5f-974f-08acb8200d73','江樓秋夕','真山民','宋','宋诗','song-poetry','','[]','樓高古城遶，無奈漏聲催。',48,'全唐诗/poet.song.227000.json','["樓高古城遶，無奈漏聲催。", "幽夢風吹斷，新吟月送來。", "江長漁唱遠，雲冷鴈聲哀。", "明日重陽酒，黄花開未開。"]'),
('9c2db37a-a454-47cb-bc37-4f1da7690f54','初夏訪劉道士','真山民','宋','宋诗','song-poetry','','[]','白雲隨杖履，伴我到山房。',48,'全唐诗/poet.song.227000.json','["白雲隨杖履，伴我到山房。", "暑薄疑天別，林深見路長。", "朮芝皆道味，花竹亦詩香。", "更待荷花後，來分半榻凉。"]'),
('597bc8d3-267e-4402-9b54-fbba44b74c6c','春行','真山民','宋','宋诗','song-poetry','','[]','東風物物新，花外步清晨。',48,'全唐诗/poet.song.227000.json','["東風物物新，花外步清晨。", "蕉葉卷舒雨，鳩聲問答春。", "園林三月景，詩酒百年身。", "試數交遊侶，如今有幾人。"]'),
('bf2e09de-a629-4ee7-a463-31cb0b335212','孤標上人留宿','真山民','宋','宋诗','song-poetry','','[]','山僧留我宿，我亦似山僧。',48,'全唐诗/poet.song.227000.json','["山僧留我宿，我亦似山僧。", "香茗半甌雪，寒虀一筯冰。", "廊風響黄葉，壁雨暗青燈。", "參透詩三昧，何須契一乘。"]'),
('20455043-1f0d-412f-84a2-282680ebe2be','秋晚','真山民','宋','宋诗','song-poetry','','[]','暮色入江郊，霜風兩鬢毛。',48,'全唐诗/poet.song.227000.json','["暮色入江郊，霜風兩鬢毛。", "笛聲吹月落，詩興挾秋高。", "謝絕南柯蟻，留連左手螯。", "孤燈竹窗底，危坐一歌騷。"]'),
('5b96e629-19bf-48a7-a094-4396031b709d','李修伯山居  其一','真山民','宋','宋诗','song-poetry','','[]','俗子自不到，幽扉何必扃。',48,'全唐诗/poet.song.227000.json','["俗子自不到，幽扉何必扃。", "苔衣和月卧，山雨雜泉聽。", "有髮徒斑白，無名入汗青。", "未應閒此事，尚可掃玄經。"]'),
('355f6072-67e4-4c6c-ab41-43106635fad4','李修伯山居  其二','真山民','宋','宋诗','song-poetry','','[]','寒燈幾撥盡，借問夜何其。',48,'全唐诗/poet.song.227000.json','["寒燈幾撥盡，借問夜何其。", "舊夢青燈在，新愁白髮知。", "昔爲三遶鵲，今作五藏龜。", "多謝梅梢月，留人得睡遲。"]'),
('227bd258-2252-4b29-8f98-8ada40abb0d8','道逢過軍投宿山寺','真山民','宋','宋诗','song-poetry','','[]','窮途欲焉往，薄暮此相投。',48,'全唐诗/poet.song.227000.json','["窮途欲焉往，薄暮此相投。", "蟋蟀數聲雨，芭蕉一寺秋。", "鄉關來枕畔，時事上眉頭。", "長歎爲僧好，今逢更說愁。"]'),
('866b583d-efe4-46c2-ba0f-4f4d2a27bca2','述懷','真山民','宋','宋诗','song-poetry','','[]','不敢尤人敢怨天，愁來覓酒醉來眠。',64,'全唐诗/poet.song.227000.json','["不敢尤人敢怨天，愁來覓酒醉來眠。", "五窮有鬼徧相虐，九轉無丹別自全。", "遊食懼違新下令，力耕苦乏舊存田。", "靈臺坐受憂兵觸，荏苒霜華剝鬢玄。"]'),
('e08efa80-a2f1-452d-a92c-f8204d1b42eb','春曉雨','真山民','宋','宋诗','song-poetry','','[]','破曉簷花未放乾，披衣和夢倚闌干。',64,'全唐诗/poet.song.227000.json','["破曉簷花未放乾，披衣和夢倚闌干。", "釀成苔暈地猶濕，老盡鶑聲風正寒。", "無客醉敲金鐙響，有人睡怯翠衾單。", "牡丹一夜成消瘦，下却珠簾不忍看。"]'),
('026f9a34-8605-43d5-813c-d0bd075e70e7','西湖圖','真山民','宋','宋诗','song-poetry','','["\u897f\u6e56"]','兩袖春風一杖藜，等閒踏破柳橋西。',64,'全唐诗/poet.song.227000.json','["兩袖春風一杖藜，等閒踏破柳橋西。", "雲開遠嶂碧千疊，雨過落花紅半溪。", "青旆有情邀我醉，黄鶑無恨爲誰啼。", "東城正在桃林外，多少遊人逐馬蹄。"]'),
('33af783f-5130-4d7b-b2ee-eab87aa4b3a4','隠懷','真山民','宋','宋诗','song-poetry','','[]','樣不趨時合便休，都將往事付東流。',64,'全唐诗/poet.song.227000.json','["樣不趨時合便休，都將往事付東流。", "眼看浮世自今古，迹與孤雲同去留。", "泉石定非騎馬路，功名不上釣魚舟。", "有時但得句無問，只與漁歌互唱酬。"]'),
('ae1532fb-3263-452e-92b1-1c6c04d19de0','游鳳棲寺','真山民','宋','宋诗','song-poetry','','[]','十載重游古鳳棲，蓮宮新遶綠楊堤。',64,'全唐诗/poet.song.227000.json','["十載重游古鳳棲，蓮宮新遶綠楊堤。", "欲談世事佛無語，不管客愁禽自啼。", "苔滑空廊妨散步，塵昏老壁失留題。", "僧家田地鄰家種，菜甲春風綠滿畦。"]'),
('8fa21cd2-2674-4981-b91e-40c2b1ac95a6','漁浦晚秋旅懷','真山民','宋','宋诗','song-poetry','','[]','西風吹夢越中游，剪剪輕寒入短裘。',64,'全唐诗/poet.song.227000.json','["西風吹夢越中游，剪剪輕寒入短裘。", "雁字不將鄉信寫，蛩聲空和旅吟愁。", "郵亭冷雨孤燈夜，漁市斜陽一笛秋。", "是處山川即吾土，仲宣何用怯登樓。"]'),
('e546cbd6-5b4d-45e2-a197-f0e2f22618a6','泊舟嚴灘','真山民','宋','宋诗','song-poetry','','[]','天色微茫入暝鐘，嚴陵灘上繫孤篷。',64,'全唐诗/poet.song.227000.json','["天色微茫入暝鐘，嚴陵灘上繫孤篷。", "水禽與我共明月，蘆葉同誰吟晚風。", "隔浦人家漁火外，滿江愁思笛聲中。", "雲開休望飛鴻影，身即天涯一斷鴻。"]'),
('6680b57b-26fa-4cc6-8853-8306941727ea','題永嘉夢草堂','真山民','宋','宋诗','song-poetry','','[]','留得斯堂萬古名，江山不敢閉英靈。',64,'全唐诗/poet.song.227000.json','["留得斯堂萬古名，江山不敢閉英靈。", "池光曾染吟邊墨，草色猶如夢裏青。", "南浦詩香流未歇，東家魂冷喚難醒。", "當時園柳俱塵迹，惟有鳴禽尚可聽。"]'),
('37ca0a0f-db4e-46a3-8687-7d96dd92ff33','連城春夜留別張建溪','真山民','宋','宋诗','song-poetry','','[]','飛絮游絲客子心，連城那忍遽分襟。',64,'全唐诗/poet.song.227000.json','["飛絮游絲客子心，連城那忍遽分襟。", "青燈應見詩情苦，濁酒不如交味深。", "一榻暖風棲竹屋，半闌淡月立花陰。", "離懷今夜先收拾，盡付明朝馬上吟。"]'),
('cc13bb78-91a9-4883-bf4c-f81ae17f39c1','夜坐','真山民','宋','宋诗','song-poetry','','[]','匹馬平生汗漫遊，如今寂寞老林楸。',64,'全唐诗/poet.song.227000.json','["匹馬平生汗漫遊，如今寂寞老林楸。", "小窗半夜青燈雨，幽樹一庭黄葉秋。", "懶看世情寧睡去，怕傷時事莫吟休。", "寒蛩可是知人意，未到莎根只說愁。"]'),
('aab491f2-ac5b-47a2-88ff-c8464526540b','春行','真山民','宋','宋诗','song-poetry','','[]','短帽輕衫步履遲，微暄天氣乍晴時。',64,'全唐诗/poet.song.227000.json','["短帽輕衫步履遲，微暄天氣乍晴時。", "池融嫩碧消殘凍，春剪新紅綴舊枝。", "嵐翠滴衣堪入畫，禽聲到耳足供詩。", "東風苦欲招人醉，頻掉橋西賣酒旗。"]'),
('9d037e91-0864-414e-a214-169c31a26734','初冬','真山民','宋','宋诗','song-poetry','','[]','林葉新經數夜霜，地爐獨擁一山房。',64,'全唐诗/poet.song.227000.json','["林葉新經數夜霜，地爐獨擁一山房。", "塵書邀我共高閣，濁酒勸人歸醉鄉。", "費省家貧還似富，身閒日短亦如長。", "梅花苦欲催吟興，又破梢頭半點香。"]'),
('04b0e61c-ee66-4783-8327-cdab142b6395','東粵廟','真山民','宋','宋诗','song-poetry','','[]','頹闌斜照網蛛絲，陳迹凄凉萬古悲。',64,'全唐诗/poet.song.227000.json','["頹闌斜照網蛛絲，陳迹凄凉萬古悲。", "柘水尚鳴亡國怨，山松曾見受封時。", "碑因苔蝕無完字，城爲田侵失舊基。", "當日東甌知幾戰，如今贏得一荒祠。"]'),
('181bd953-0521-4185-9991-df0645c2ffdc','歲暮','真山民','宋','宋诗','song-poetry','','[]','顔不常朱鬢易斑，流光難駐兩跳丸。',64,'全唐诗/poet.song.227000.json','["顔不常朱鬢易斑，流光難駐兩跳丸。", "一年又是等閒過，百歲只消如此看。", "把酒何曾長在手，種桃能得幾憑欄。", "癡人醉夢不知醒，日夜雙眉抵死攢。"]'),
('5de55129-06be-4869-a223-bc3a2caaadbb','閒居漫賦','真山民','宋','宋诗','song-poetry','','[]','紛紛裘馬走紅塵，頼得閒邊可著身。',64,'全唐诗/poet.song.227000.json','["紛紛裘馬走紅塵，頼得閒邊可著身。", "商嶺定無屠狗客，雲臺豈有釣魚人。", "溪山蕭散青芒履，風月夷猶烏角巾。", "萬事如棋君看取，一番局面一番新。"]'),
('aff5b557-ffcc-4c2f-a736-fbb4e3d856f7','三峰寺','真山民','宋','宋诗','song-poetry','','[]','寂寞烟林噪亂鴉，青鞋步入野僧家。',64,'全唐诗/poet.song.227000.json','["寂寞烟林噪亂鴉，青鞋步入野僧家。", "雲深不礙鐘聲出，日轉還移塔影斜。", "廊下蝸黏沿砌蘚，佛前蜂戀插瓶花。", "竹床紙帳清如水，一枕松風聽煮茶。"]'),
('5c70fd8d-0fb9-422d-9710-5ab3ff27318f','江頭春日','真山民','宋','宋诗','song-poetry','','[]','風煖旗亭煮酒香，醉醒始悟是他鄉。',64,'全唐诗/poet.song.227000.json','["風煖旗亭煮酒香，醉醒始悟是他鄉。", "駕言行邁路千里，豈不懷歸天一方。", "春事漸消鶑語老，離愁偏勝柳絲長。", "無聊莫向城南宿，淡月梨花正斷腸。"]'),
('6d583e5c-9d7c-4d53-a967-47b0dfe917c6','次韻潘恕堂見寄','真山民','宋','宋诗','song-poetry','','[]','抱甕區區老漢陰，空齋擁鼻日長吟。',64,'全唐诗/poet.song.227000.json','["抱甕區區老漢陰，空齋擁鼻日長吟。", "青山隔截市朝面，白髮消磨豪傑心。", "書既無成休學劍，貴無可買恥言金。", "情知不入鴛鸞侶，頼有鷗盟尚可尋。"]'),
('84b0aef0-a569-4db5-8046-46605d055fda','初夏','真山民','宋','宋诗','song-poetry','','[]','一葉薰風带暑回，雨添濃翠暗庭槐。',64,'全唐诗/poet.song.227000.json','["一葉薰風带暑回，雨添濃翠暗庭槐。", "不隨春去鶑猶在，好競時妝榴又開。", "剪尺旋栽新白苧，盃盤聊薦舊青梅。", "篋中敝扇投閒久，依舊團團入手來。"]'),
('b71f326e-f20f-4972-bd3f-d4074e2513e2','閒吟初冬','真山民','宋','宋诗','song-poetry','','[]','一架琴書一筆床，杜門荏苒送年光。',64,'全唐诗/poet.song.227000.json','["一架琴書一筆床，杜門荏苒送年光。", "囊空儘可償詩債，脚倦猶能入醉鄉。", "既老菊花偏耐久，未開梅蘂已先香。", "眼邊管領閒風景，不識人間更有忙。"]'),
('b324ad68-69f5-4146-b403-c66360adc258','奉和頗動遊興呈雲耕叔祖','真山民','宋','宋诗','song-poetry','','[]','節遇中和景漸暄，自摩倦眼望前村。',64,'全唐诗/poet.song.227000.json','["節遇中和景漸暄，自摩倦眼望前村。", "雕鎪花柳春無迹，沐浴山川雨有恩。", "憶昔踏青終日醉，如今垂白幾人存。", "未應便作衰翁看，藉草猶堪倒一樽。"]'),
('704575aa-4bde-43e9-b1e2-5f1b39871cb2','夜飲趙園次徐君實韻','真山民','宋','宋诗','song-poetry','','[]','銀臺絳蠟淚成堆，四面軒窗盡放開。',64,'全唐诗/poet.song.227000.json','["銀臺絳蠟淚成堆，四面軒窗盡放開。", "花影忽生知月到，竹梢微響覺風來。", "豪揮彩筆詩千首，醉倚紅妝酒百杯。", "遊玩未闌歸未得，高城漏箭幾相催。"]'),
('5073cc7b-9b4d-414a-9853-8d57529839ac','平章命','真山民','宋','宋诗','song-poetry','','[]','萬甲蟠胸老氣雄，將星光照海雲東。',64,'全唐诗/poet.song.227000.json','["萬甲蟠胸老氣雄，將星光照海雲東。", "聲名宣尉裴中立，地步平章韓魏公。", "大纛高牙山水縣，褒衣博带藻芹宮。", "書生端爲斯文喜，俎豆先行軍旅中。"]'),
('f98fd7f3-7410-43db-beb4-51a4e2e8f985','幽棲','真山民','宋','宋诗','song-poetry','','[]','鶴護松扉久不開，蒲團端坐思悠哉。',64,'全唐诗/poet.song.227000.json','["鶴護松扉久不開，蒲團端坐思悠哉。", "故交只向夢中見，閒事不經心上來。", "雙屐躡雲春採藥，一筇拄月夜觀梅。", "東風似見山童懶，自與幽人掃徑苔。"]'),
('3f1bdfa8-7fd5-47b8-a3de-32b7cbbfea55','讀劉元城言行錄','真山民','宋','宋诗','song-poetry','','[]','一掃權奸九十章，七州不憚歷炎荒。',64,'全唐诗/poet.song.227000.json','["一掃權奸九十章，七州不憚歷炎荒。", "黄粱富貴百年短，青史是非千載長。", "丞相雖存心已死，先生既葬骨猶香。", "向令鐵漢常留在，天下何緣有靖康。"]'),
('46e71f3a-1652-4518-b662-e2374a13a114','次李林居春曉遊園','真山民','宋','宋诗','song-poetry','','[]','滅沒晨曦弄淡晴，追隨杖履竹間亭。',64,'全唐诗/poet.song.227000.json','["滅沒晨曦弄淡晴，追隨杖履竹間亭。", "花逢酒侶容先醉，柳見詩人眼剩青。", "三月光陰半流水，百年身世一浮萍。", "啼鵑只管催春去，不道衰翁已怕聽。"]'),
('195fb8ce-9e7e-468f-8b16-f3f363e66999','聖果院訪忠上人不值','真山民','宋','宋诗','song-poetry','','[]','管領東風入杖藜，落梅香裏已招提。',64,'全唐诗/poet.song.227000.json','["管領東風入杖藜，落梅香裏已招提。", "苔痕一徑白雲濕，花影半窗紅日低。", "欲見高僧聊爾耳，便乘餘興去來兮。", "葛藤有話無人共，付與隔林幽鳥啼。"]'),
('fd52c431-46d3-4710-814e-a52fd8d751a8','山行','真山民','宋','宋诗','song-poetry','','[]','林梢初日弄陰晴，露浥溪花笑欲迎。',64,'全唐诗/poet.song.227000.json','["林梢初日弄陰晴，露浥溪花笑欲迎。", "澗暗只聞泉滴瀝，山青剩見鷺分明。", "遠峰忽轉還如遶，險逕徐行亦似平。", "莫謂詩成無與和，風篁也解作吟聲。"]'),
('faa18397-2425-4b63-bf25-52234b101a98','秋夜次葉一山韻','真山民','宋','宋诗','song-poetry','','[]','自笑秋來似轉蓬，偶然飛落過山中。',64,'全唐诗/poet.song.227000.json','["自笑秋來似轉蓬，偶然飛落過山中。", "一燈幽館菊花雨，孤枕小樓梧葉風。", "涉世悠悠旋磨蟻，懷人杳杳寄書鴻。", "浮生何預光陰事，抵死相催作老翁。"]'),
('a5ce962d-0f63-4fa0-8f7b-368ce6ba59ed','杜鵑花得紅字','真山民','宋','宋诗','song-poetry','','[]','愁鎖巴雲往事空，只將遺恨寄芳叢。',64,'全唐诗/poet.song.227000.json','["愁鎖巴雲往事空，只將遺恨寄芳叢。", "歸心千古終難白，啼血萬山多是紅。", "枝带翠煙深夜月，魂飛錦水舊東風。", "至今染出懷鄉恨，長挂行人望眼中。"]'),
('8d4474e2-eb03-4990-8bdf-19a333e65ee3','客中臨歸仍送游教諭','真山民','宋','宋诗','song-poetry','','[]','建括相望天一涯，快哉此地話襟期。',64,'全唐诗/poet.song.227000.json','["建括相望天一涯，快哉此地話襟期。", "芹邊春煖幾盃酒，門外月高千首詩。", "去去先生此休矣，栖栖遊子暮何之。", "送行折了郵亭柳，歸卧白雲歌紫芝。"]'),
('ed2f1603-5271-4eb7-906d-876544afa481','自適','真山民','宋','宋诗','song-poetry','','[]','年來心迹兩悠悠，若比孤雲儘自由。',64,'全唐诗/poet.song.227000.json','["年來心迹兩悠悠，若比孤雲儘自由。", "既不貪榮安有辱，縱饒無樂亦何憂。", "一絲風月嚴陵釣，千里關山季子裘。", "到底行藏定誰是，試將心事問沙鷗。"]'),
('91bd6298-278c-45fa-b531-32a37fea9488','永嘉秋夕','真山民','宋','宋诗','song-poetry','','[]','風戰枯桐敲紙窗，擁裘無寐夜偏長。',64,'全唐诗/poet.song.227000.json','["風戰枯桐敲紙窗，擁裘無寐夜偏長。", "樵樓三鼓夜將午，雲雁數聲天正霜。", "寓世此身驚逆旅，寬懷何處不吾鄉。", "江頭風景日堪醉，酒美蟹肥橙橘香。"]'),
('00cb7de5-edd2-46a2-9c3c-8d1e3fa2ba34','醉題齋壁','真山民','宋','宋诗','song-poetry','','[]','此是閒中安樂窩，從渠忙處爲奔波。',64,'全唐诗/poet.song.227000.json','["此是閒中安樂窩，從渠忙處爲奔波。", "人心少似秋胡婦，世事多參春夢婆。", "但把功名齊蟻蛭，定無榮辱到漁蓑。", "醉鄉境界偏寬闊，天地都歸一浩歌。"]'),
('0dd84320-85ac-45ec-86db-e097bae911b6','客中遇鄉友季芳遠歸省親','真山民','宋','宋诗','song-poetry','','[]','河梁邂逅話襟期，獵獵西風透裌衣。',64,'全唐诗/poet.song.227000.json','["河梁邂逅話襟期，獵獵西風透裌衣。", "酒臉未隨紅葉醉，鄉心先逐白雲飛。", "客中送客難爲別，山上安山胡不歸。", "借使家書君可寄，此間無復問庭幃。"]'),
('94917bc6-8b6a-47be-9e2e-adcd49f4199e','山人家','真山民','宋','宋诗','song-poetry','','[]','片雲隔斷嶂西峰，三兩山花屋角紅。',64,'全唐诗/poet.song.227000.json','["片雲隔斷嶂西峰，三兩山花屋角紅。", "幾畝桑麻春社後，數家雞犬夕陽中。", "拾薪澗底青裙婦，倚杖簷間白髮翁。", "我亦願來同隠者，種桃早晚趁東風。"]'),
('d5d59804-ce84-4d11-a1d2-14a353ba9eb3','劉伯山寄隠','真山民','宋','宋诗','song-poetry','','[]','寄隠幽蹤何處尋，春風十里薜蘿深。',64,'全唐诗/poet.song.227000.json','["寄隠幽蹤何處尋，春風十里薜蘿深。", "青山不說是非事，黄鳥自賡長短吟。", "百折畏途休著脚，十分明月是知心。", "不應誤放桃花出，惹得漁翁話古今。"]'),
('3567a6a3-68f5-460a-81e7-8b6a3fc76acd','朱溪澗','真山民','宋','宋诗','song-poetry','','[]','路轉峰回又一村，天寒大半掩柴門。',64,'全唐诗/poet.song.227000.json','["路轉峰回又一村，天寒大半掩柴門。", "雲融山脊嵐生翠，水嚼沙洲樹出根。", "任擁重裘風亦冷，未投荒店月先昏。", "今宵只傍梅花宿，贏得清芬入夢魂。"]'),
('6d81ae26-72b0-40ff-855f-7732d87b8ef2','丹山書堂','真山民','宋','宋诗','song-poetry','','[]','作室懸知要肯堂，而翁家學頗增光。',64,'全唐诗/poet.song.227000.json','["作室懸知要肯堂，而翁家學頗增光。", "一朝衿佩儒簪合，千古詩書屋壁香。", "鑑曲烟霞歸羽館，鍾山風月落僧房。", "如何只揭精廬扁，解續斯文氣燄長。"]'),
('eb407dd5-f9a2-4b8d-832d-c5d7395d5746','閒中','真山民','宋','宋诗','song-poetry','','[]','敢咎章縫解誤人，甘於閒處著閒身。',64,'全唐诗/poet.song.227000.json','["敢咎章縫解誤人，甘於閒處著閒身。", "腹中書在溫仍熟，夢裏詩成記不真。", "引鶴徐行三逕曉，約梅同醉一壺春。", "今朝有喜誰知得，新換銜頭號散民。"]'),
('d18c91da-61a3-4833-a947-d6530b47315d','送雲泉入山','真山民','宋','宋诗','song-poetry','','[]','薜蘿叢裏鬰青青，別是幽棲一段清。',64,'全唐诗/poet.song.227000.json','["薜蘿叢裏鬰青青，別是幽棲一段清。", "水色山光皆畫本，蟬聲禽語亦吟情。", "人今不改衣冠古，道重方知富貴輕。", "爲語俗交休見問，已從麋鹿訂新盟。"]'),
('da3e4d3e-4778-4405-a458-e5704331ec73','冬暮小齋','真山民','宋','宋诗','song-poetry','','[]','布襪青鞋敝絮袍，松扉柴几小衡茅。',64,'全唐诗/poet.song.227000.json','["布襪青鞋敝絮袍，松扉柴几小衡茅。", "雲酣纔釀臈三月，梅吐又橫春一梢。", "炭爲驟寒偏索價，酒因不飲懶論交。", "窮年兀兀從人笑，未用多方作解嘲。"]'),
('978ed4e3-7f34-43e5-99eb-0f747cb14127','宿南峰寺','真山民','宋','宋诗','song-poetry','','[]','禪房花木鎖深幽，借與詩人信宿留。',64,'全唐诗/poet.song.227000.json','["禪房花木鎖深幽，借與詩人信宿留。", "幡影分來半廊月，磬聲敲破一林秋。", "僧偏好事能青眼，佛本無心亦白頭。", "試問青松峯外鶴，閒邊曾見幾人遊。"]'),
('c81335d6-3641-4e38-9140-936512824389','歲朝','真山民','宋','宋诗','song-poetry','','[]','畫角聲中舊歲除，新年喜氣滿屠蘇。',64,'全唐诗/poet.song.227000.json','["畫角聲中舊歲除，新年喜氣滿屠蘇。", "陽和忽轉冰霜後，元氣更如天地初。", "晚色催詩歸草夢，春光隨筆上桃符。", "閉門賀客相過少，靜對梅花自看書。"]'),
('0b203276-29a1-411b-aa7e-6fc6571b33a0','春曉山行','真山民','宋','宋诗','song-poetry','','[]','風掃連陰作快晴，瘦筇伴我出山扃。',64,'全唐诗/poet.song.227000.json','["風掃連陰作快晴，瘦筇伴我出山扃。", "路從初日紅邊過，人在野花香裏行。", "古木殊無趨世態，幽禽懶作弄春聲。", "棕鞋踏遍山南北，只與白雲相送迎。"]'),
('cda564ea-518f-4809-81a2-20680bd2e318','王廉使','真山民','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','鼻祖名高三諫官，耳孫玉立又臺端。',64,'全唐诗/poet.song.227000.json','["鼻祖名高三諫官，耳孫玉立又臺端。", "氣增浙左霜威動，面带終南山色寒。", "攬轡肯教狼卧地，歸班便合豸峨冠。", "公餘詩興清於雪，細嚼梅花入肺肝。"]'),
('5b1fbcf8-0b67-47e6-8b51-1c931ff36d1a','幽興','真山民','宋','宋诗','song-poetry','','[]','不賦千鍾賦一簞，天公有意養癡頑。',64,'全唐诗/poet.song.227000.json','["不賦千鍾賦一簞，天公有意養癡頑。", "書猶能看未曾老，詩亦莫吟方是閒。", "寬著庭除貪貯月，少栽竹樹要觀山。", "空階兩日無行迹，又上苔花幾點斑。"]'),
('17915322-254e-4ffd-bc07-3e56b40a5705','梅仙山','真山民','宋','宋诗','song-poetry','','[]','西都不知壽，安用獨長年。',24,'全唐诗/poet.song.227000.json','["西都不知壽，安用獨長年。", "縱有丹爐在，難吹漢火燃。"]'),
('2cf8216f-b48d-4fd9-9758-abb91b3ed896','螢火','真山民','宋','宋诗','song-poetry','','[]','微蹤一腐草，霜重不禁秋。',24,'全唐诗/poet.song.227000.json','["微蹤一腐草，霜重不禁秋。", "想悟浮生短，常爲秉燭遊。"]'),
('7fe9fc1a-3d03-43ea-b4c0-a2975ca0d81a','蜜蜂','真山民','宋','宋诗','song-poetry','','[]','釀成百花脾，聊爾了口腹。',24,'全唐诗/poet.song.227000.json','["釀成百花脾，聊爾了口腹。", "人知口中甘，誰料腹中毒。"]'),
('03c81c54-1e8f-44f5-aa96-ff99959724a7','觀書自歎','真山民','宋','宋诗','song-poetry','','[]','皓首抱遺經，堪憐誤一生。',24,'全唐诗/poet.song.227000.json','["皓首抱遺經，堪憐誤一生。", "空共蠹蟲飽，自作忍饑聲。"]'),
('e177ad9f-825e-46ea-b475-585219991098','吉水夜泊','真山民','宋','宋诗','song-poetry','','[]','入夜始維舟，黄蘆古渡頭。',24,'全唐诗/poet.song.227000.json','["入夜始維舟，黄蘆古渡頭。", "眠鷗知讓客，飛過蓼花洲。"]'),
('2ec58a8f-4bee-4e25-a90e-fc2b487161b6','草','真山民','宋','宋诗','song-poetry','','[]','草枯根不死，春到又敷榮。',24,'全唐诗/poet.song.227000.json','["草枯根不死，春到又敷榮。", "獨有愁根在，非春亦自生。"]'),
('909e04d1-bdf7-40ad-bdf8-cdb07e2a025a','百舌','真山民','宋','宋诗','song-poetry','','[]','花間報曉晴，巧弄百般聲。',24,'全唐诗/poet.song.227000.json','["花間報曉晴，巧弄百般聲。", "未可嫌饒舌，猶勝鴈不鳴。"]'),
('79151dda-3fde-492e-a1ab-a4fba97ef404','秋扇','真山民','宋','宋诗','song-poetry','','[]','人心有炎凉，我心無歡悲。',24,'全唐诗/poet.song.227000.json','["人心有炎凉，我心無歡悲。", "篋中重自珍，會有薰風時。"]'),
('af4cf608-86b9-4b97-af66-ceb5a8509e95','訪李延不值','真山民','宋','宋诗','song-poetry','','[]','白雲滿空山，山空人未歸。',24,'全唐诗/poet.song.227000.json','["白雲滿空山，山空人未歸。", "拄杖莫敲門，恐驚白雲飛。"]'),
('e32d8d7a-b56b-4a66-a550-bfaf20a1a360','七夕','真山民','宋','宋诗','song-poetry','','[]','世上癡兒女，爭趨乞巧筵。',24,'全唐诗/poet.song.227000.json','["世上癡兒女，爭趨乞巧筵。", "婦鳩甘抱拙，不諂鵲橋仙。"]'),
('040cf906-5226-4855-991d-1eeee2ff21ca','楊妃','真山民','宋','宋诗','song-poetry','','[]','三郎掩面馬嵬坡，生死恩深可奈何。',32,'全唐诗/poet.song.227000.json','["三郎掩面馬嵬坡，生死恩深可奈何。", "瘞土驛傍何足恨，潼關戰處骨埋多。"]'),
('1a7b1210-2f54-426e-8827-b69b42068229','水墨海棠','真山民','宋','宋诗','song-poetry','','[]','不將翠袖捲紗紅，怪得陳玄奪化工。',32,'全唐诗/poet.song.227000.json','["不將翠袖捲紗紅，怪得陳玄奪化工。", "想是太真春睡足，夢魂正在黑甜中。"]'),
('b0aede4d-3a60-43b6-94e8-7e0e18e68d19','三月晦日與邵石諸友閒遊東園分得空字','真山民','宋','宋诗','song-poetry','','[]','韶光收拾太匆匆，眼底浮花一掃空。',32,'全唐诗/poet.song.227000.json','["韶光收拾太匆匆，眼底浮花一掃空。", "留得數枝紅藥在，五更分付與東風。"]'),
('4c63480e-5cf2-4a03-adb7-14213dc9bfdd','年少春遊','真山民','宋','宋诗','song-poetry','','[]','錦袍朱带玉花驄，著意追歡紫陌東。',32,'全唐诗/poet.song.227000.json','["錦袍朱带玉花驄，著意追歡紫陌東。", "只道春風屬楊柳，不知楊柳有秋風。"]'),
('6fa96c21-7dc0-4f2c-a89b-43e940345684','山間早春','真山民','宋','宋诗','song-poetry','','[]','小桃枝上認年華，隨分紅開一兩花。',32,'全唐诗/poet.song.227000.json','["小桃枝上認年華，隨分紅開一兩花。", "將謂春風只城市，也吹春色到山家。"]'),
('bfb2bff7-feb2-4a30-9fcf-67560c06cb94','三月晦日','真山民','宋','宋诗','song-poetry','','[]','九十風光能有幾，東風遽作遠行人。',32,'全唐诗/poet.song.227000.json','["九十風光能有幾，東風遽作遠行人。", "樽前莫惜今朝醉，明日鶑聲不是春。"]'),
('00effab6-9224-492c-8400-8d9d05662f9e','高帝','真山民','宋','宋诗','song-poetry','','[]','未央前殿養親時，想記當年俎上危。',32,'全唐诗/poet.song.227000.json','["未央前殿養親時，想記當年俎上危。", "借問杯羹何等語，如今安用玉巵爲。"]'),
('4b539f08-5624-464c-ac27-3597bcf5610f','晚步','真山民','宋','宋诗','song-poetry','','[]','未暝先啼草際蛩，石橋暗度晚花風。',32,'全唐诗/poet.song.227000.json','["未暝先啼草際蛩，石橋暗度晚花風。", "歸鴉不带殘陽老，留得林梢一抹紅。"]'),
('3bb5f5bb-50c6-4b26-82da-6f9b08043114','春閨詞','真山民','宋','宋诗','song-poetry','','[]','愁鎖眉尖未肯消，何心更待兩蛾嬌。',32,'全唐诗/poet.song.227000.json','["愁鎖眉尖未肯消，何心更待兩蛾嬌。", "一春螺黛渾無用，付與東風染柳條。"]'),
('4dd3bf91-80ef-4263-8b40-cd5e6ef977b7','山間秋夜','真山民','宋','宋诗','song-poetry','','[]','夜色秋光共一闌，飽收風露入脾肝。',32,'全唐诗/poet.song.227000.json','["夜色秋光共一闌，飽收風露入脾肝。", "虛簷立盡梧桐影，絡緯數聲山月寒。"]'),
('fd54ad90-4ffe-4e88-ba23-b2de46ab1f71','新年','真山民','宋','宋诗','song-poetry','','[]','妝點春光到眼邊，凍消殘雪暖生烟。',32,'全唐诗/poet.song.227000.json','["妝點春光到眼邊，凍消殘雪暖生烟。", "杏桃催換新顔色，惟有寒梅老一年。"]'),
('43d33e10-4960-4102-af3b-ca13d9fc0d7a','九日','真山民','宋','宋诗','song-poetry','','[]','懶把黄花插滿頭，正緣老大見花羞。',32,'全唐诗/poet.song.227000.json','["懶把黄花插滿頭，正緣老大見花羞。", "年來頗恨儒冠誤，好倩西風吹去休。"]'),
('82e5ace5-38b0-4de5-8db7-592f866a365a','醉餘再賦','真山民','宋','宋诗','song-poetry','','[]','堪歎詩翁酒興豪，醉餘猶復一登高。',32,'全唐诗/poet.song.227000.json','["堪歎詩翁酒興豪，醉餘猶復一登高。", "西風抵死相摇撼，爭奈儒冠裹得牢。"]'),
('61d0b31f-cfbf-4c85-8b22-c76e7f7286de','陳雲岫愛騎馿','真山民','宋','宋诗','song-poetry','','[]','君不學少陵騎馿金華春，一生旅食長悲辛。',134,'全唐诗/poet.song.227000.json','["君不學少陵騎馿金華春，一生旅食長悲辛。", "又不學浪仙騎馿長安市，凄凉落葉秋風裏。", "却學雪中騎馿孟浩然，冷濕銀鐙敲吟鞭。", "梅花溪上日來往，身迹懶散人中仙。", "有時清霜松下路，松風蕭蕭馿耳豎。", "據鞍傲兀四無人，牧子騎牛相爾汝。", "勸君但騎馿，行路穩，姑徐徐。", "九折畏途鞭快馬，年來曾覆幾人車。"]'),
('c64b98c3-e8a7-4b0e-be43-83a9a27f0d9e','留槎閣寓感','真山民','宋','宋诗','song-poetry','','[]','俯仰乾坤爲一嗟，西風原上夕陽斜。',64,'全唐诗/poet.song.227000.json','["俯仰乾坤爲一嗟，西風原上夕陽斜。", "石麟已換延陵塚，銀漢今無博望槎。", "前古英雄俱寂寞，黄昏燈火自諠譁。", "不惟人事年年改，近日靈洲水沒沙。"]'),
('bc8c0513-beab-4fe7-ae5b-76fe381611ac','題濟川橋','真山民','宋','宋诗','song-poetry','','[]','十二闌干百尺臺，登臨洗盡眼中埃。',64,'全唐诗/poet.song.227000.json','["十二闌干百尺臺，登臨洗盡眼中埃。", "沙痕長與水吞吐，橋影不妨船往來。", "兩岸樓臺隨世換，四山圖畫自天開。", "槎邊今古無窮思，都付西風酒一杯。"]'),
('23c5c2ba-6693-40f7-91b7-8e6b650d52a3','吳王夜宴圖','真山民','宋','宋诗','song-poetry','','[]','銀漏迢迢夜未晨，管絃聲裏綺羅春。',32,'全唐诗/poet.song.227000.json','["銀漏迢迢夜未晨，管絃聲裏綺羅春。", "飲闌方擁名娃醉，豈料稽山正卧薪。"]'),
('f9ec324d-947d-4bf5-965f-eb7ff2b19f7c','春遊阻雨次韻','真山民','宋','宋诗','song-poetry','','[]','田里熈熈便是春，追遊何必艷陽辰。',32,'全唐诗/poet.song.227000.json','["田里熈熈便是春，追遊何必艷陽辰。", "打門吏少花村靜，聽雨高眠亦可人。"]'),
('37244da5-f211-48f6-8ce2-05231dc727e9','雨後月明起坐戲成','舒岳祥','宋','宋诗','song-poetry','','[]','雨後月明，如醉而醒。',80,'全唐诗/poet.song.227000.json','["雨後月明，如醉而醒。", "不見其形，但見其影。", "我夢初回，非曙非暝。", "道人無言，起舞弄景。", "水鳥無聲，一鶴自警。", "清風南來，露墜炯炯。", "我病不飲，酌此清泠。", "超然頓悟，九萬俄頃。"]'),
('b1c82f9d-1001-44f3-a695-bce4461026d7','伯夷','舒岳祥','宋','宋诗','song-poetry','','[]','士如圭璋，自然廉隅。',40,'全唐诗/poet.song.227000.json','["士如圭璋，自然廉隅。", "一日無恥，不可以居。", "上帝降衷，毀敗是虞。", "遷史作傳，爰首餓夫。"]'),
('fbfc20fc-ebaa-4e23-83ef-f1818ef9343b','管鮑','舒岳祥','宋','宋诗','song-poetry','','[]','爲管則易，爲鮑則難。',40,'全唐诗/poet.song.227000.json','["爲管則易，爲鮑則難。", "相馬失瘦，相士失寒。", "管貧鮑富，坦然相安。", "于利不疚，于義斯完。"]'),
('191e0730-5e1a-49d2-ba4a-9f9a747056cc','魯二儒','舒岳祥','宋','宋诗','song-poetry','','[]','叔孫事秦，以諛蔽愚。',40,'全唐诗/poet.song.227000.json','["叔孫事秦，以諛蔽愚。", "至於歸漢，薦進狡夫。", "滅我王道，甚於焚書。", "是以二儒，確乎其居。"]'),
('ea7303ff-3ff3-48bd-8b18-83836634c6d0','停雲詩  其一','舒岳祥','宋','宋诗','song-poetry','','[]','我懷同人，如暵望雨。',40,'全唐诗/poet.song.227000.json','["我懷同人，如暵望雨。", "天地崩裂，干戈間阻。", "陳編孤哦，槁梧自撫。", "思而不見，援桂延佇。"]'),
('f99b7b62-d6ea-45ff-9122-0725aeccf771','停雲詩  其二','舒岳祥','宋','宋诗','song-poetry','','[]','千山月白，露氣濛濛。',40,'全唐诗/poet.song.227000.json','["千山月白，露氣濛濛。", "四顧戃慌，素靄成江。", "飛蘿掃屋，懸泉挂窗。", "之子不至，世孰吾從。"]'),
('780c8d23-a491-41f6-a4da-4744c4afdfa8','停雲詩  其三','舒岳祥','宋','宋诗','song-poetry','','[]','小園宛宛，水木鮮榮。',40,'全唐诗/poet.song.227000.json','["小園宛宛，水木鮮榮。", "子念及此，我寧忘情。", "曩歲中都，我歸子征。", "以子出處，用觀我生。"]'),
('48ac74e6-2908-400f-a491-3399a3bd8fab','停雲詩  其四','舒岳祥','宋','宋诗','song-poetry','','[]','俯仰換世，昨夢蟻柯。',40,'全唐诗/poet.song.227000.json','["俯仰換世，昨夢蟻柯。", "故交零落，屈指無多。", "孔時尹任，夷清惠和。", "各言爾志，夫也如何。"]'),
('f66803ea-50b0-41dd-a547-46a9db43a313','寓言  其一','舒岳祥','宋','宋诗','song-poetry','','[]','妾家有高樓，高高入青天。',96,'全唐诗/poet.song.227000.json','["妾家有高樓，高高入青天。", "欲作萬丈梯，倚空無攀援。", "良人在萬里，一去幾經年。", "長路與天接，舉足躡星躔。", "妾欲尋夫壻，解甲投戈鋋。", "携手上雲霓，真到天河壖。", "牽牛與織女，不知妾相憐。", "姮娥惠神藥，燕婉成天仙。"]'),
('52df5de7-8a9d-4b4d-8dd4-2d029e4b217b','寓言  其二','舒岳祥','宋','宋诗','song-poetry','','[]','昔有貴公子，聞鶴九臯禽。',180,'全唐诗/poet.song.227000.json','["昔有貴公子，聞鶴九臯禽。", "其先本胎化，棲止必瑶林。", "遣使三往聘，致之千黄金。", "清唳復善舞，節奏合瑶琴。", "日給費魚米，延之如玳簪。", "銜杯爲主壽，千歲無遐心。", "有客爲主謀，禽荒可傾國。", "此物非潔清，其志本貪冒。", "遺矢玉階陰，吞腥金塘側。", "當以禽養禽，毋令食人食。", "主人頷其言，從此成捐斥。", "蕭條風雨晨，蹭蹬霜雪夕。", "鶴將辭主去，顧視亦悽惻。", "謂客君少留，行當蹈吾迹。", "客亦慘不樂，相看淚霑臆。"]'),
('bf701690-e8fb-4fed-8846-d9276daf4663','十蟲吟  其一','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有促織兒，憂人不憂己。',72,'全唐诗/poet.song.227000.json','["蟲有促織兒，憂人不憂己。", "華身有龍鸞，不出工女指。", "瓦礫爲堂奧，青莎作衣被。", "一身可自了，剌剌不能已。", "白露夜庭空，凄其行去矣。", "金屋白玉床，貴人呼不起。"]'),
('ae9c3ed7-2b01-4470-92ed-4e5880f5ccc7','十蟲吟  其二','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有織絹娘，軋軋鳴窗紙。',48,'全唐诗/poet.song.227000.json','["蟲有織絹娘，軋軋鳴窗紙。", "山翁卧中聞，謂是機上婢。", "瓠花日蕭疎，豆葉行披靡。", "青燈照夜闌，胡爲苦如此。"]'),
('e5cda81a-bc77-44e1-b8c0-d9e203f6097d','十蟲吟  其三','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有絡緯婆，如繅復如紡。',48,'全唐诗/poet.song.227000.json','["蟲有絡緯婆，如繅復如紡。", "豆籬秋雨餘，秉燭不須網。", "置之銀絲籠，因而入羅幌。", "偏資兒女玩，終夜奏繁響。"]'),
('9b6da738-8f08-410b-9ad0-5bc294590783','十蟲吟  其四','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有搗米叔，善跳如舂穀。',60,'全唐诗/poet.song.227000.json','["蟲有搗米叔，善跳如舂穀。", "偶與屋上塵，墮地豈好觸。", "兒童仰置之，反弓奮腰腹。", "欲行復遭抑，屢作不能伏。", "非汝懶於舂，其力有不足。"]'),
('ab7f7f49-3d80-483e-b9d2-d84a468fb8cf','十蟲吟  其五','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有賣油公，什伍處陰濕。',60,'全唐诗/poet.song.227000.json','["蟲有賣油公，什伍處陰濕。", "長脚如蠨蛸，脛細走不及。", "兒童反接之，邀其吐微汁。", "所挾雖不多，坐此遭攟拾。", "傾資僅有此，微生何以給。"]'),
('9bdedf94-e6f6-4b40-876c-e3438d902b21','十蟲吟  其六','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有避債夫，緝繭枝間綴。',72,'全唐诗/poet.song.227000.json','["蟲有避債夫，緝繭枝間綴。", "竊食檉松毛，負之以爲蓋。", "首鼠開兩端，見人深拒閉。", "想汝作債初，已作逃匿計。", "小兒不汝赦，推尋見根柢。", "計窮挺身走，終日失其竁。"]'),
('7a111390-8d77-48e7-9fec-edee21bbf346','十蟲吟  其七','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有轉丸蜣，雙角牛怒張。',72,'全唐诗/poet.song.227000.json','["蟲有轉丸蜣，雙角牛怒張。", "生子牛矢中，轉圜技所長。", "兩兩如推車，千百滿路旁。", "彈丸有不若，纍纍圓且光。", "汙穢不自羞，敢比蘇合香。", "惜哉爾之智，不善擇其良。"]'),
('8060c4cb-e782-4f61-a0af-66415886cb95','十蟲吟  其八','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有蛀地牛，曲吻利如鈎。',84,'全唐诗/poet.song.227000.json','["蟲有蛀地牛，曲吻利如鈎。", "趯取尾作首，倒行腹爲頭。", "燥土作陷沙，露喙伺其幽。", "小蟲誤過之，一入出無由。", "小兒嫉其然，取彼衆中酋。", "縛置它穴口，其類亦相仇。", "一引兩得之，盡置清溪流。"]'),
('ecbc3a16-878e-4af8-9b56-190d7f5fc597','十蟲吟  其九','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有攛梭子，頭腹俱銳長。',96,'全唐诗/poet.song.227000.json','["蟲有攛梭子，頭腹俱銳長。", "綠衣而絳裏，飛躍低踉蹡。", "名我固甚善，所愧無筐箱。", "維天有南箕，不可以簸揚。", "微蟲人强名，此豈彼竊攘。", "秋田蚱蜢橫，暗野如飛蝗。", "索索淺草中，不倚兩股强。", "類中最善類，霜露死其常。"]'),
('9c0997e4-42b4-4eb9-9b89-745d8ea87c6f','十蟲吟  其一○','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有蠹書魚，白膩鉛粉如。',72,'全唐诗/poet.song.227000.json','["蟲有蠹書魚，白膩鉛粉如。", "岐尾細而長，所嗜惟食書。", "我老書久廢，兒曹復相疎。", "經年不啟櫝，宜爾穴以居。", "蝕紙兼齧字，古篆成紆餘。", "腹中有經傳，顧我何空虛。"]'),
('5194c319-1697-47b0-9621-6c73cb9e88ca','續十蟲吟  其一','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有搏蠅虎，似蟢無網罟。',72,'全唐诗/poet.song.227000.json','["蟲有搏蠅虎，似蟢無網罟。", "羣蠅爭嘬時，潜身入其聚。", "蠅初玩其小，突然能攫取。", "生擒加面縛，不辨頭翅股。", "蠅爲人所憎，同欲畀茲虎。", "其奈彼實繁，日食能幾許。"]'),
('e0617456-2343-4a55-8b63-06e9423b0fad','續十蟲吟  其二','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有白蟻虎，食蟻功有取。',108,'全唐诗/poet.song.227000.json','["蟲有白蟻虎，食蟻功有取。", "大厦初落成，白蟻郛其礎。", "日繁實有徒，歲久仆梁梠。", "聞爾能食之，往求數十許。", "縱之穴竅中，種育成生聚。", "食蟻既無餘，虎自緣庭戶。", "亦復生几案，徃徃入筐筥。", "主人反厭憎，擁篲務屏去。", "客謂主勿然，前勞宜論敘。"]'),
('d105159a-fb50-4887-abbd-20f8bc420143','續十蟲吟  其三','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有齧桑羊，兩鉗如角怒。',84,'全唐诗/poet.song.227000.json','["蟲有齧桑羊，兩鉗如角怒。", "玄甲類蛣蜣，亦如龜背負。", "我有十畝桑，苦爲渠所蠹。", "食必食其心，樹死又飛去。", "不知從何來，鑽鑿不到處。", "上下開兩窗，隠匿巧多路。", "嗟哉啄木鳥，剛吐柔不茹。"]'),
('da4642b6-1140-43dd-b246-1148a8f2bce0','續十蟲吟  其四','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有齧菊羊，齧腦腦則死。',108,'全唐诗/poet.song.227000.json','["蟲有齧菊羊，齧腦腦則死。", "人謂食且盡，細察理不爾。", "微軀細於蠅，玄甲而利嘴。", "頂上一粟紅，鮮明大如蟣。", "方當四五月，苗盛新怒起。", "上下截其莖，於中寄生子。", "腦瘁子乃成，分枝從此始。", "種菊須摘腦，不摘分披靡。", "理有損而益，未用分慍喜。"]'),
('0034d43e-cdf7-4625-b84e-25c393da32fa','續十蟲吟  其五','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有土中狗，翼短身則長。',84,'全唐诗/poet.song.227000.json','["蟲有土中狗，翼短身則長。", "行地如狗子，兩臂健擘張。", "縱橫成穴道，堀堁身蔽藏。", "握之人手中，排抉力甚强。", "夜飛能打人，有物憑爲殃。", "收之入藥錄，虻蛭同其良。", "君看醫師術，可謂宰相方。"]'),
('701948cb-c145-4a16-a334-d0867d86f59a','續十蟲吟  其六','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有水走馬，八脚成四蹄。',60,'全唐诗/poet.song.227000.json','["蟲有水走馬，八脚成四蹄。", "映日如薸葉，點點水中開。", "得食時爭嘬，忽然各東西。", "天牛非觳觫，水馬非駃騠。", "形容貴其似，甕舞爲醯鷄。"]'),
('b7f04d3a-d317-4ecd-bfa7-e1c4270dc15e','續十蟲吟  其七','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有天水牛，兩臂徒甚修。',72,'全唐诗/poet.song.227000.json','["蟲有天水牛，兩臂徒甚修。", "長尾龜其類，玄背鱉與儔。", "細評無甚似，大槩勿深求。", "終身混沮洳，亦與蝦蛭游。", "或云能羽化，爲蟬槐樹頭。", "清高乃如許，亦足掩前羞。"]'),
('b667940d-11cc-41d6-8ef1-9b376385ad33','續十蟲吟  其八','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有蝌蚪子，初化厠羣魚。',72,'全唐诗/poet.song.227000.json','["蟲有蝌蚪子，初化厠羣魚。", "鱍鱍穿綠藻，洋洋泳深蒲。", "俄然生臂股，去尾登泥塗。", "回首謂羣魚，幸來相就居。", "神鯉爲魚長，不肯受辱汙。", "答云我龍種，豈與爾爲徒。"]'),
('1ff73e14-c730-4e0f-89a2-e984810da9dc','續十蟲吟  其九','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有報雨蛙，竹樹能攀援。',96,'全唐诗/poet.song.227000.json','["蟲有報雨蛙，竹樹能攀援。", "青褐隨所處，膚如凝脂鮮。", "長頸而方頷，顧盼升高顛。", "久晴初得雨，清聲滿林園。", "紅蕉映白日，碧葦覆清泉。", "幽居樂清浄，飲露如風蟬。", "俯視蝦蟆輩，迥然異凡仙。", "能鳴復善晦，所貴身名全。"]'),
('308dc8b0-e705-41b8-b3fb-b396fae5638b','續十蟲吟  其一○','舒岳祥','宋','宋诗','song-poetry','','[]','蟲有摇櫓郎，楚楚綠衣裳。',96,'全唐诗/poet.song.227000.json','["蟲有摇櫓郎，楚楚綠衣裳。", "怒目祇自躁，奮臂倚枝長。", "附桑寄螵蛸，亦入秘術方。", "折之插屋壁，經時子穰穰。", "竹籬疎復密，牽牛花低昂。", "迎風新意氣，顧盼何昂藏。", "如逢大車轍，毅然亦敢當。", "不如捕鳴蟬，脆美不爾傷。"]'),
('42107a59-b28b-4d5b-b3ad-1a6546c55a5c','十二月二十七日病起行花下聞春禽有感','舒岳祥','宋','宋诗','song-poetry','','[]','昨日立春節，今晨春鳥鳴。',96,'全唐诗/poet.song.227000.json','["昨日立春節，今晨春鳥鳴。", "前峯宿蒼靄，風聲和且平。", "南翁病來久，起繞花枝行。", "花枝向人笑，婉孌感幽情。", "摩挲朂小男，何時看汝成。", "童稚引我前，老至不覺驚。", "艱難亦已極，須汝見休明。", "望望替官役，不顧日月征。"]'),
('77338a57-0a55-4313-9ace-d95355a51bab','放言','舒岳祥','宋','宋诗','song-poetry','','[]','寒暑一大瘧，天地一病軀。',96,'全唐诗/poet.song.227000.json','["寒暑一大瘧，天地一病軀。", "古來幾寒暑，元氣朘削餘。", "人物生其中，短小一侏儒。", "神農乏藥草，黄帝無醫書。", "坐令豺虎橫，咬嚼爲膏腴。", "頑疾久不治，臟腑生蟲蛆。", "願借大雷斧，磔此害物徒。", "八荒既清廓，萬古無憂虞。"]'),
('3fcbbccf-935a-484f-8185-67d1f638236a','題王德淵水西藁','舒岳祥','宋','宋诗','song-poetry','','[]','子有婉微句，藏之平淡間。',108,'全唐诗/poet.song.227000.json','["子有婉微句，藏之平淡間。", "想子無慍色，熙熙好容顔。", "吉人罕暴戾，詳緩心自閒。", "吾知子用意，欲挽陶韋還。", "欲以靜息競，欲以柔鎸頑。", "坐使聽者心，悠然和且安。", "子來索我語，我與子無言。", "評茶及品水，此事在舌端。", "還有分別否，歸鴻沒遠天。"]'),
('775a9b74-c25c-4f46-9760-83df412e7780','稻花桑花','舒岳祥','宋','宋诗','song-poetry','','[]','稻花花中王，桑花花中后。',156,'全唐诗/poet.song.227000.json','["稻花花中王，桑花花中后。", "餘花皆嬪妃，以色媚左右。", "稻花吹早香，風露千萬畝。", "上以奉玉食，粢盛及醴酒。", "下以飽蒼生，億兆餔其口。", "桑花雖無華，紅葚映纖手。", "皇后首親蠶，六宮承傅姆。", "天生衆裸蟲，無羽毛飛走。", "匪此皆凍死，性命安得有。", "予謂二花者，斯民之父母。", "昔予賦麥花，適當來牟候。", "未及歌二花，三花誰可後。", "請續時夏詩，以爲風化首。"]'),
('ce16a8f3-7f82-4789-b97d-bd7101ff3ca3','春日新浴','舒岳祥','宋','宋诗','song-poetry','','[]','白髮美青陽，新年試新浴。',120,'全唐诗/poet.song.227000.json','["白髮美青陽，新年試新浴。", "小窗潔而明，板閣密以燠。", "簾垂風絕蹊，湯煖雲升屋。", "探手酌溫凉，微微澆背腹。", "上盆頮吾面，下盆濯吾足。", "初如馬釋鞿，漸覺蟬蛻殻。", "周浹更融怡，味如書熟讀。", "澡身當去塵，洗心當脫俗。", "湛然清浄源，不遣生惡濁。", "振衣聊出門，篝煙度修竹。"]'),
('1bc1464c-d48c-4e69-8d71-0fd5ddcf1877','七月十七日夜翫月','舒岳祥','宋','宋诗','song-poetry','','[]','遲月呼不出，海氣紅碧噓。',84,'全唐诗/poet.song.227000.json','["遲月呼不出，海氣紅碧噓。", "何人捧隋璧，上處青松疎。", "松間著不得，飛徹萬里衢。", "散作千山雪，蘆花摇江湖。", "冰輪雖漸側，老桂斫不枯。", "清光已非昨，來日更可吁。", "徘徊情所結，有酒且歌呼。"]'),
('378d5750-60fc-4067-bab0-4e501761084b','借居喜杉棚成','舒岳祥','宋','宋诗','song-poetry','','[]','夏炎已云極，秋暑方自茲。',156,'全唐诗/poet.song.227000.json','["夏炎已云極，秋暑方自茲。", "借居面西日，午後如烹炊。", "主人愛敬客，架杉覆青枝。", "赫日辟三舍，鮮飈汎淪漪。", "高蟬亦好吟，振響流笙箎。", "夜靜明月出，疎影復陸離。", "欹枕寢桃竹，露坐冠筍皮。", "凡此暑中事，施之無不宜。", "念我逃世難，過用恐禍隨。", "昔時半山老，畏熱架條枚。", "不知公相貴，清儉諒可思。", "我本無家客，祿盡壽有遺。", "得此已厚忝，銜感以成詩。"]'),
('b30539ee-a713-45c3-a63b-febbec412b26','贈醫博士范心齋','舒岳祥','宋','宋诗','song-poetry','','[]','疾病之所生，風寒燥濕毒。',192,'全唐诗/poet.song.227000.json','["疾病之所生，風寒燥濕毒。", "浸淫侵臟腑，脈絡起絲粟。", "有藥所不攻，鍼砭功始錄。", "有如龍潜見，巖穴通隠伏。", "又如善用兵，洞窟皆驅逐。", "毛皮與腠理，一二數可燭。", "刺俞已及髓，投穴不中肉。", "春回九地底，冰崖芽衆綠。", "范子故書生，於此見也獨。", "十年從良師，神祕卷篋櫝。", "我疑秦盧扁，垣牆能外矚。", "又疑華佗子，披臟先剖腹。", "范生何大奇，方書可無讀。", "我老目已昏，煩君爲濯滌。", "更閲十年書，細字蠅頭黑。", "與子作佳傳，當與太史續。"]'),
('c3b92446-7c4d-49fb-8e1e-9abcbbf34d64','幽疥','舒岳祥','宋','宋诗','song-poetry','','[]','性不耐喧聒，况遭疥癢牽。',120,'全唐诗/poet.song.227000.json','["性不耐喧聒，况遭疥癢牽。", "此物有朋黨，一搔千竅連。", "幽陰及肘股，爛漫羅脅肩。", "城狐及社鼠，不如汝穴堅。", "蟻蝨猶外患，爾獨腠理穿。", "百藥既不醒，取說聊自完。", "閑邪自檢束，斂容如見賢。", "彼亦畏天理，亦有負其頑。", "既不廢談笑，亦不妨食眠。", "萬事貴隠忍，此方老子傳。"]'),
('0ae5a3cf-8387-4f17-8267-00754056581c','將別棠谿遺仲素季厚昆仲','舒岳祥','宋','宋诗','song-poetry','','[]','新交勝舊交，生別猶死別。',168,'全唐诗/poet.song.227000.json','["新交勝舊交，生別猶死別。", "饑魂散欲飛，愁腸鬰以結。", "去住誠兩難，主客新握別。", "家山杳何許，千丈高嶻嶭。", "試登黄甘望，百里見積雪。", "我甔無儲粟，我篋無重褐。", "妻孥幸團欒，忘此饑與渴。", "倚君爲大厦，顧我顔色悅。", "無家未易歸，無産難久歇。", "鄉校著我名，免在編氓列。", "麥田望有秋，桑葉行可掇。", "貰貲延餘年，空囊誰負竊。", "不敢久累君，去去春二月。", "爲我謝王戴，徽音無斷絕。"]'),
('6f4f759c-90ce-4bc8-99e6-c5458184ba96','食蓮有感戲爲古興新體','舒岳祥','宋','宋诗','song-poetry','','[]','青蘋先知秋，調遣入窗几。',108,'全唐诗/poet.song.227000.json','["青蘋先知秋，調遣入窗几。", "荷花如六郎，一笑忽墮水。", "美人坐生愁，攬衣中夜起。", "繁華難久持，零落自茲始。", "所思在遠道，千里復萬里。", "何處無芙蕖，秋江總相似。", "折取蓮蓬看，蜜房綴蜂子。", "青繭初脫衣，瑶軫中含髓。", "食蓮須食心，心中苦如此。"]'),
('0977ffc2-5167-4bf6-8b5e-93deb0e36bbd','寇攘之餘穀五斗才易一鷄衰老多病資血味以爲養求之弗可得畜二母鷄自春抱育至夏百翼不減子美生理喜而有作','舒岳祥','宋','宋诗','song-poetry','','[]','昔有尸鄉翁，養鷄蓋阡陌。',192,'全唐诗/poet.song.227000.json','["昔有尸鄉翁，養鷄蓋阡陌。", "累財千餘萬，積微利自博。", "子美居瀼西，此物尚百翮。", "作詩戒宗文，牆東樹籠柵。", "我今山居中，生理苦迫窄。", "衰年資食治，時有不速客。", "海魚不常儲，溪蟹碎難擘。", "頗欲效兩翁，字鷄供口食。", "買得雙伏雌，領以一赤幘。", "戶外聽約束，安能汙案席。", "剖坼五十卵，引哺漸開拆。", "從茲日生生，向秋益繁息。", "麥雲行刈黄，可得二十石。", "已知餠臛具，不假天邊翼。", "竊笑茅季偉，割烹惟一隻。", "奉親不及賓，資生拙無策。"]'),
('5cc55098-5722-4a10-a3cc-280c9a1b8cbc','古思二首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','耿耿不可忍，相思在東北。',60,'全唐诗/poet.song.227000.json','["耿耿不可忍，相思在東北。", "花月以爲姿，風露以爲食。", "取我虞氏琴，一彈三歎息。", "泠然不可尋，變爲湘江瑟。", "湘江深復深，哀哀淚千尺。"]'),
('5328cc3f-1d41-43b9-a244-9816bd3c5d24','古思二首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','饑餓未必死，甘腴能殺人。',72,'全唐诗/poet.song.227000.json','["饑餓未必死，甘腴能殺人。", "憔悴未必殞，逸樂能喪身。", "所以巖谷槁，以儉全其真。", "秉耒自耕野，腰斧躬採薪。", "亦復誦書史，自負亨經綸。", "兵寇幸無恙，委蛇保天民。"]'),
('931069d1-923c-4397-96db-131b50a65200','矚物','舒岳祥','宋','宋诗','song-poetry','','[]','灼灼日及華，朝榮夕已墜。',84,'全唐诗/poet.song.227000.json','["灼灼日及華，朝榮夕已墜。", "牽牛泫碧露，見晛歘憔悴。", "拒霜舒曉紅，惟愁夕陰至。", "蜻蛚庇其根，亦復多愁思。", "容色豈不佳，浮脆何足貴。", "念此令人嗟，百年何流駛。", "所以靖節翁，把菊有深意。"]'),
('fd6af998-eb54-48bf-a8f6-3bcd82aaaaf9','過字韻詩辱諸友聯和方營度枯鄙以酬厚意偶報北兵自甌閩回驅男女牛羊萬計入蛟湖深畯出獨山屯尚義由童公嶺以北三日夜不休聞之驚心遂成閣筆是月十四夜對月感涕遂即前韻以紀時事奉呈諸友','舒岳祥','宋','宋诗','song-poetry','','[]','麥倒桑折枝，山外花門過。',72,'全唐诗/poet.song.227000.json','["麥倒桑折枝，山外花門過。", "牛亡主不歸，婦去蠶未卧。", "在者哭空村，吞聲誰敢大。", "盲暉隠空崖，驚塵飛暗堁。", "川逝痛陵遷，春深悲國破。", "可惜此良宵，月輪升紫磨。"]'),
('a2e7f6de-37ae-493f-830f-517d66f5e46f','十六夜月色佳甚對酒效樂天體招酒伴賞月','舒岳祥','宋','宋诗','song-poetry','','[]','八月十六夜，清凉明月天。',72,'全唐诗/poet.song.227000.json','["八月十六夜，清凉明月天。", "新酒雖未熟，陳酒喜未乾。", "早稻有餘飯，輕衫未爲寒。", "傍人見我醉，胸中故朗然。", "有詩不自作，但詠古人篇。", "喚取故山甫，醉即對牀眠。"]'),
('29fa3931-8212-4c29-9dc7-dc46d77d847d','九月十四日夜枕不寐起視明月清寒著人泠然有欲仙之意','舒岳祥','宋','宋诗','song-poetry','','[]','筍冠枕清泠，胡床坐空闊。',72,'全唐诗/poet.song.227000.json','["筍冠枕清泠，胡床坐空闊。", "鮮飈飛早霜，活水漾明月。", "神遊十丈蓮，仰卧恣天閲。", "挽取河東流，黑我頭上雪。", "泥丸吐神光，陟降在金闕。", "湛然大圓鏡，一悟萬想滅。"]'),
('d78d4b07-7f93-4b31-9f9f-8604a413c199','十一日夜雲月點綴山氣如海羈雌暗嗥倏忽東西因誦王摩詰云夜登華子岡輞水淪漣與月上下寒山遠火明滅林外深巷寒犬吠聲如豹村墟夜舂復與疏鐘相間往往摩詰詩多描模此境界余更掇拾遺餘耳','舒岳祥','宋','宋诗','song-poetry','','[]','孤舂出苫蓋，遠火翳層磯。',36,'全唐诗/poet.song.227000.json','["孤舂出苫蓋，遠火翳層磯。", "雲月光涎涎，露葉浄輝輝。", "此時正寂默，沙禽鳴且飛。"]'),
('e6290042-91ac-4ac7-bff5-ca1edbc3cc17','琴旨','舒岳祥','宋','宋诗','song-poetry','','[]','重露洗叢菊，長宇流哀鴻。',144,'全唐诗/poet.song.227000.json','["重露洗叢菊，長宇流哀鴻。", "瞽月入九地，啞木號太空。", "老翁中夜起，清坐尋絲桐。", "兩片乾死木，和合藏深衷。", "七絃說妙義，十指揚春風。", "自古知音者，舜文周孔公。", "四聖洗憂患，琴與易道通。", "舜處嚚傲厄，文居君臣窮。", "二叔流讒言，陳蔡靡所容。", "物外有變逆，聖道當正中。", "感此悟琴旨，瞭然古人胸。", "置琴且勿彈，待我讀易終。"]'),
('0c5cdec2-bae2-4cf8-b472-08fa7dcae7ce','送達善歸玉塘','舒岳祥','宋','宋诗','song-poetry','','[]','霜降水泉涸，風緊草木枯。',96,'全唐诗/poet.song.227000.json','["霜降水泉涸，風緊草木枯。", "柴扃常自閉，淡泊守園廬。", "晨有客來訪，裹飯如桑輿。", "世事不欲論，幽懷詠唐虞。", "蚩尤作五兵，軒轅力誅除。", "戰伐從此始，禍患引八區。", "茲事傷我心，何由返古初。", "我輩惜榆景，來往莫相疎。"]'),
('2513bed2-81f4-482b-8b31-a1761163c9e1','古意','舒岳祥','宋','宋诗','song-poetry','','[]','客從南方來，遺我薰風琴。',108,'全唐诗/poet.song.227000.json','["客從南方來，遺我薰風琴。", "薰風未易致，且奏易水吟。", "高浪忽起立，四顧變愁陰。", "征馬立踟躇，旁人淚沾襟。", "壯士不畏死，怒髮豎森森。", "長揖辭四坐，秦關無阻深。", "燕客視秦王，已若罝中禽。", "一朝事不成，易水有悲音。", "請君且勿彈，此曲傷人心。"]'),
('b4aa5ffd-4b89-4a84-b228-bef4d08b37e8','十二月初六日龜藏夜坐有感','舒岳祥','宋','宋诗','song-poetry','','[]','厲厲歲于邁，栗栗風向遒。',120,'全唐诗/poet.song.227000.json','["厲厲歲于邁，栗栗風向遒。", "老驥倦長坡，卧樵如罷牛。", "時時一長吁，慚與螻蟻儔。", "高鴻志萬里，矰繳非所憂。", "胡爲苦哀鳴，失類中道休。", "壯士今則已，偃仰搔白頭。", "讀書有分限，眼暗志未酬。", "轉蓬從風起，直上晴空遊。", "流星下至地，化石空山幽。", "升沉亦何常，念此涕淚流。"]'),
('de2e07e5-fdfe-4b38-964b-4f90bd2056bd','子瞻在惠州以十月初吉作重九和淵明己酉九月九日韻余去年以此日奔避萬山今日則有間矣有野人饋菊兩叢對之歎息因繼韻陶蘇之後','舒岳祥','宋','宋诗','song-poetry','','[]','去年十月吉，四山戎馬交。',96,'全唐诗/poet.song.227000.json','["去年十月吉，四山戎馬交。", "携家走萬壑，惟恐草莽凋。", "今日復此日，回睇龍舒高。", "青黄雜遠樹，丹碧曖微霄。", "黄華一斗酒，慰此兩足勞。", "念茲一釜內，觸之成爛焦。", "我窮天所憐，杯水解鬰陶。", "冥心聽回斡，聊以永今朝。"]'),
('e588f7c2-9614-4262-8635-dc8452750a89','十月三十日晴暖而梅意殊冷也','舒岳祥','宋','宋诗','song-poetry','','[]','良月今日盡，始見小春天。',96,'全唐诗/poet.song.227000.json','["良月今日盡，始見小春天。", "明日爲子正，陽復於此焉。", "牆陰委宿莽，已覺青娟娟。", "壞壁出凍蠅，亦解飛翾翾。", "向來可憎物，今者更堪憐。", "梅梢太瘦生，此意正渺綿。", "窺園頻挾策，粒吐紅豆鮮。", "正須待一雪，我豈資暄妍。"]'),
('b71b2760-8e80-446f-a91a-54052af8958e','次韻袁伯長寄贈之作','舒岳祥','宋','宋诗','song-poetry','','[]','維時十月閏，收穫已登場。',288,'全唐诗/poet.song.227000.json','["維時十月閏，收穫已登場。", "朋舊喜我至，殷勤置壺觴。", "問我何方來，憂墨見清揚。", "答言辱君問，欲報不成章。", "憶昔盜起初，堅冰由履霜。", "妖民縱愚妄，敢凌太陽光。", "賤子久客鄞，移家入新昌。", "完璞保貞吉，訓猷謀善臧。", "嶔嶇遠荆棘，瘏痡辟鋒鋩。", "五男不挾冊，四婦廢條桑。", "長孫病風攣，二孫鶴未昂。", "三孫始周晬，瘍垢浴蘭湯。", "曾孫客中産，敢擬門戶當。", "復有四女孫，包裹針線裝。", "步涉青店谿，伏莽突長槍。", "性命幸完免，翁媼扶筍將。", "回首煙焰漲，搜山發窖藏。", "家林付瓦礫，書籍罹咎殃。", "賫糧中道絕，萬事慨以慷。", "墳塋失灑掃，祖禰廢蒸嘗。", "瀼西非吾里，浣花無草堂。", "猛獸難與羣，我亦思還鄉。", "又聞來屠剡，玉石恐俱傷。", "冒暑去雪村，故里隔一岡。"]'),
('79ab7902-6b96-4374-9b3c-d858e7cc7000','次達善送趙君理韻因寄畬齋陳貴白','舒岳祥','宋','宋诗','song-poetry','','[]','杉棚已絕筆，復得雲錦書。',156,'全唐诗/poet.song.227000.json','["杉棚已絕筆，復得雲錦書。", "况當既望後，一鏡懸空虛。", "恍然玉堂上，乘鶴來須臾。", "君健勝我健，我臞甚君臞。", "人事有離合，尺牘莫相疎。", "老驥不忘騁，老耕不忘畬。", "筆硯易乾澀，時時要喣濡。", "井汲去泥鮒，清冽用有餘。", "自君之往矣，我懷久不舒。", "久聞畬齋君，插架富名都。", "欲往鵁鶄市，讀書借其居。", "我曾見其文，鼎臠出帥初。", "何年澂齋老，道我問其途。"]'),
('33581c96-d249-4994-9e55-35e8ca2559c9','客好','舒岳祥','宋','宋诗','song-poetry','','[]','薄田歲罕收，柴門客多好。',60,'全唐诗/poet.song.227000.json','["薄田歲罕收，柴門客多好。", "車轍自成趣，蒿萊不須掃。", "鄰家知客到，亦復饋梨棗。", "酒盡當復沽，言論自顛倒。", "萬事皆可談，慎忽談世道。"]'),
('3ed0ed66-68f0-4b77-9b42-6ff7b981016b','巖間宴坐','舒岳祥','宋','宋诗','song-poetry','','[]','蛩泣草根露，鶴鳴松頂風。',180,'全唐诗/poet.song.227000.json','["蛩泣草根露，鶴鳴松頂風。", "標格既有異，音韻那能同。", "我家水石村，圓月出中峯。", "樵子時往還，野客多仙蹤。", "杳杳林表磬，冥冥巖下鐘。", "霧重時作雨，衣翠濕重重。", "孔竅明似藕，肌骨通玲瓏。", "巖花時嗅馥，掩冉紛青紅。", "萬葉互戛擊，琴瑟間笙鏞。", "我當大悶時，一嘯來清風。", "鳳鳴相應和，龍吟諧律筒。", "竅竹去其節，清響合商宮。", "累黍以爲律，旋變爲無窮。", "仙人授刀尺，度數合纖洪。", "此訣留巖石，千古蒼苔封。"]'),
('a1042154-0b02-4cb4-bd5d-46ea19522b12','村莊麥飯虀筍有懷達善正仲帥初因寄袁仲素季厚陳用之','舒岳祥','宋','宋诗','song-poetry','','[]','麥風生曉寒，梅潦藴炎溽。',288,'全唐诗/poet.song.227000.json','["麥風生曉寒，梅潦藴炎溽。", "三日不出門，新筍已成竹。", "獨酌固自佳，對婦亦不俗。", "黄魚出海門，饜飫及僮僕。", "因思去年時，煎牟作糜粥。", "饑餓走荒山，羣奴深兩目。", "今春幸完生，一飽萬事足。", "薄蠶微有收，條桑柔更綠。", "百里無鷄豚，雖老不食肉。", "本是在家僧，殺生豈吾欲。", "頗恨在棠谿，芻豢事屠戮。", "歸來賣筍翁，燒煮擬果腹。", "無奈軍馬囂，十百遭縛束。", "此君何不幸，乃值汝輩辱。", "今辰斑衣郎，扣門求采錄。", "開奩粲纖指，解苞剝寒玉。", "釋縛李左車，拭面何平叔。", "有此席上珍，舉筯誠不惡。", "風味近瑶柱，標格薦醽醁。", "似憐老翁饞，洗我塵一斛。", "蛻脫成癯仙，凌空駕黄鵠。", "吐吭出新詩，落紙欹醉墨。", "王劉戴三君，秦楚齊敵國。", "樂縣森筍簴，箭鋒值正鵠。"]'),
('fb156b98-4751-4c7c-acdf-346d3c3a9bd1','雨餘草樹間羽蟲亂鳴山齋晚酌朋輩已散聽之不減孔稚圭兩部鼓吹也既醉而卧卧而覺家人尚明燈事績說向來鼻鼾雷鳴兩山皆撼也戲作示之','舒岳祥','宋','宋诗','song-poetry','','[]','秋蟲不用喙，動羽哀更清。',60,'全唐诗/poet.song.227000.json','["秋蟲不用喙，動羽哀更清。", "夜長不肯默，我眠渠自鳴。", "我則異於是，鼻息爲雷聲。", "止作不以力，大音自天成。", "鼻吼耳不知，此樂尤難名。"]'),
('6cc28847-27a0-44ea-9198-4502ac4b292b','七月二日戲爲紈扇新體','舒岳祥','宋','宋诗','song-poetry','','[]','美人弄紈扇，常恨無秋風。',108,'全唐诗/poet.song.227000.json','["美人弄紈扇，常恨無秋風。", "待得秋風至，棄置在篋中。", "棄置不自惜，物理有終窮。", "反恐美人寵，隨手亦成空。", "十五邯鄲女，玉指弄絲桐。", "秀慧解歌舞，艷彩敵芙蓉。", "一朝登上國，飛聲凌後宮。", "此日邢夫人，正自難爲容。", "紈扇手所題，主惠余其終。"]'),
('47ce643c-b0fd-4f13-b10b-33923814c3f2','日食','舒岳祥','宋','宋诗','song-poetry','','[]','十月初吉日，四野聞驚呼。',180,'全唐诗/poet.song.227000.json','["十月初吉日，四野聞驚呼。", "停杯出門看，日食將無餘。", "有如黑漆盤，來掩白玉盂。", "自午而及申，磨盪未還初。", "父老涕泗語，便恐天眼枯。", "前年六月吉，晝日如煤塗。", "衆星爭光怪，淡月懸天衢。", "已謂畢生世，不復覩赤烏。", "須臾還舊觀，田野頓昭蘇。", "今胡久淪厄，翳昧不可祛。", "前時縉紳謂，占度不屬吳。", "分野受其咎，天道安可誣。", "以日諉敵國，不君良可吁。", "茲辰爲誰食，無路攄臣愚。", "太陽萬萬古，少待收桑榆。"]'),
('08f31576-4d9c-4ed7-b677-fe377f7abf2c','丙子兵禍自有宇宙寧海所未見也予家二百指甔石將罄避地入剡貸粟而食解衣償之不敢以淵明之主人望於人也因讀淵明乞食詩和韻書懷呈達善亦見達善燒痕藁中有陶公乞食顔公乞米二帖跋尾也','舒岳祥','宋','宋诗','song-poetry','','[]','淵明不可及，適意惟所之。',84,'全唐诗/poet.song.227000.json','["淵明不可及，適意惟所之。", "無食不免乞，折腰乃竟辭。", "主人必義士，知心如子期。", "厚饋既賙急，復酌我以巵。", "談諧有真味，斯人定能詩。", "柳惠未失正，魯男豈可非。", "學陶何必乞，書此以自貽。"]'),
('97458f76-3e68-470c-894f-e0458dec14f3','次韻酬達善','舒岳祥','宋','宋诗','song-poetry','','[]','昔有好名者，舉國讓子之。',84,'全唐诗/poet.song.227000.json','["昔有好名者，舉國讓子之。", "若或非其人，簞食見色辭。", "草木固同臭，磁鐵非有期。", "主人解談諧，寓言蒙莊巵。", "陶公豈真乞，善謔淇澳詩。", "仲尼不假蓋，將護子夏非。", "賢哉此賓主，不乞彼自貽。"]'),
('545ff872-8e15-4db0-8bc5-8cae9171885e','促纖歎','舒岳祥','宋','宋诗','song-poetry','','[]','刺刺重剌剌，唧唧復唧唧。',132,'全唐诗/poet.song.227000.json','["刺刺重剌剌，唧唧復唧唧。", "只解促鬢絲，豈能催婦織。", "織亦何用催，有絲願成匹。", "今夏蠶薄收，巧手閑刀尺。", "昨下急急符，三日立稅籍。", "篋中無餘絲，紅女淚雙滴。", "汝更催不休，使我不得息。", "汝因貪與嗔，形化生股翼。", "不特登我門，又入牀下壁。", "號我夜不眠，墐戶無計塞。", "何時清霜來，堀堁同一寂。"]'),
('ef331071-c7f3-4797-939e-52d906b03858','十月五日風','舒岳祥','宋','宋诗','song-poetry','','[]','十月五日風，俗占端可驗。',288,'全唐诗/poet.song.227000.json','["十月五日風，俗占端可驗。", "常年誰能記，兩歲入程槧。", "去年當此月，初三月未艷。", "暮下陳村莊，夜投象原店。", "道邊人未眠，山曲燈微閃。", "時經兵火餘，驚問暗窺覘。", "往扣瓜葛門，炊糜聊屬厭。", "仲叔爲豬肝，不辭口腹玷。", "回思萬馬驚，心掉舌爲舚。", "恐恐如有追，昧爽踏霜霰。", "橫山過西田，惡風吹欲阽。", "蕭蕭三兩家，逋流已先占。", "憐我是官人，枯薪許分㮇。", "時艱無沽戶，粗糲得充歉。", "我行僕忙追，趙坑石排劍。", "荒蹊陟崇岡，奔湍嚙深塹。", "有塢當中心，紙鄉家自贍。", "主人褐寬博，黄泥補茨苫。", "邀我勸我留，鋪床展伸欠。", "少婦亦解事，爐中添燄燄。", "我意自多危，岌岌急風纜。", "蓐食入雪樓，山深路猶闇。", "冰柱照層崖，霜花滑斷磡。", "山家喜客來，開門容弛擔。"]'),
('2773f8e0-7d4d-4894-8a55-13666316aa29','陰雨幾月餘三月初一日聞鳩鳴有作','舒岳祥','宋','宋诗','song-poetry','','[]','春雨濛濛來，花時昏昏過。',72,'全唐诗/poet.song.227000.json','["春雨濛濛來，花時昏昏過。", "山深多悲風，閉戶祇欲卧。", "此村無杜鵑，不知桑葉大。", "灘聲自不惡，頼此洗塵堁。", "曉聞晴鳩呼，雲陰似將破。", "故園何時歸，麥飯出舂磨。"]'),
('ab452dc9-b8be-4f6f-b30c-83add4433de9','聞鳩有作喜爲晴兆也是日開霽又喜其占之有驗再賦之以貽達善季辨天色難保惟快作詩爲應耳','舒岳祥','宋','宋诗','song-poetry','','[]','雨久成淫昏，新晴如改過。',72,'全唐诗/poet.song.227000.json','["雨久成淫昏，新晴如改過。", "漸向東皋耕，還思北窗卧。", "昏眼喜天晴，觀書驚字大。", "流泉無淈泥，輕風不揚堁。", "歸途未須忙，差穀聊避破。", "小園遲能來，早茶看落磨。"]'),
('74d0ec71-86af-4295-9fba-d7e861e9581f','十月初五日重賦菊','舒岳祥','宋','宋诗','song-poetry','','[]','昔人十月菊，已恨光景衰。',84,'全唐诗/poet.song.227000.json','["昔人十月菊，已恨光景衰。", "今茲十月菊，瘦蘂未覺遲。", "兩年無官歷，弦望占盈虧。", "人言閏在子，節候固應違。", "此物秉堅正，未怕風霜欺。", "寧同此身槁，不與清香離。", "香性自流傳，更過梅花枝。"]'),
('6921b131-96f1-47e0-822d-c52ef6a20126','贈馮法師','舒岳祥','宋','宋诗','song-poetry','','[]','我昔登巾山，曾題翠微閣。',96,'全唐诗/poet.song.227000.json','["我昔登巾山，曾題翠微閣。", "清詩照江月，月落詩不落。", "踏露沐長松，遼東一隻鶴。", "千載還歸來，塔杪棲寥廓。", "過我滄海東，復作羽衣客。", "問客何處來，乃是巾山郭。", "舊題雷卷去，恐我有新作。", "贈之錦繡段，歸哦耿林壑。"]'),
('dca99dfb-2973-4ac1-b361-81d31e5a88b5','初蟬','舒岳祥','宋','宋诗','song-poetry','','[]','雨餘山氣凉，高林發清樾。',72,'全唐诗/poet.song.227000.json','["雨餘山氣凉，高林發清樾。", "黄鸝百囀罷，初蟬始幽咽。", "獨繭曳長繰，既續還又絕。", "衰年感時節，坐久心寸折。", "夢歸伊川上，樹深泉亂發。", "倚杖聽多時，殘陽滿雙闕。"]'),
('a27e633a-ccfc-4f1a-9e16-3747efa478e6','送陳用之遠遊','舒岳祥','宋','宋诗','song-poetry','','[]','流水寫清音，青山發令姿。',144,'全唐诗/poet.song.227000.json','["流水寫清音，青山發令姿。", "左右惟所取，囊篋恒相隨。", "君遊且有日，欲訪燕趙奇。", "此行猶在眼，已作久別思。", "君如生馬駒，騰踏不可羈。", "王良施轡勒，往獻白玉墀。", "胸中二三策，和扁爲國醫。", "南士方世用，砭鍼貴適宜。", "腰間黄金印，季子何必歸。", "丈夫輕四海，吾老不可期。", "何以爲君贈，梅花千里枝。", "何以爲我報，千首紀行詩。"]'),
('fac155c0-911b-4498-9084-87b295e020f3','失題','舒岳祥','宋','宋诗','song-poetry','','[]','山雲如練靜，水雲如鶴飛。',84,'全唐诗/poet.song.227000.json','["山雲如練靜，水雲如鶴飛。", "細觀聚散間，動靜皆天機。", "是物本無心，出處不可期。", "我亦嘗出岫，不雨竟空歸。", "師今恐雲去，密密關窗扉。", "收卷成坐卧，補綴爲衲衣。", "此中有深意，宴坐添爐霏。"]'),
('fb306853-0cdb-4ba1-aa67-6991806011d4','交阮嗣宗一首','舒岳祥','宋','宋诗','song-poetry','','[]','貧莫客千里，富莫不出門。',108,'全唐诗/poet.song.227000.json','["貧莫客千里，富莫不出門。", "迫隘多陵辱，飄颻困風塵。", "所以丈夫志，奮翼凌清氛。", "一舉蹴四海，載舉登崑崙。", "玉皇顧我笑，衆嫭粲以繁。", "引酒酌北斗，銀河爲飛翻。", "天姿固如是，齷齪何足云。", "鄙哉貧賤者，矯首望餘芬。", "鵬鷃各有分，榆枋保終年。"]'),
('92afdd77-c76a-45fe-8120-a011ea1cf4f8','初九日夜月下聞蛙此物得水悅樂故鳴心事與農人相關也','舒岳祥','宋','宋诗','song-poetry','','[]','平田展明湖，密林含宿霧。',108,'全唐诗/poet.song.227000.json','["平田展明湖，密林含宿霧。", "整冠對明月，天眼實汝顧。", "那敢醉謼號，袒跣縱箕踞。", "清心聽鳴蛙，勝與俗子語。", "青秧插已齊，決決溝底度。", "憂樂在晴雨，將非爲私故。", "斯言乃知音，旁人自不喻。", "余茲適無事，泯然離好惡。", "坐久天西傾，汝鳴余睡去。"]'),
('973e103b-77a9-4c4e-b08d-438de7bf1454','五月初四日浴閣成','舒岳祥','宋','宋诗','song-poetry','','[]','罷農亦易足，麥黄秧已綠。',48,'全唐诗/poet.song.227000.json','["罷農亦易足，麥黄秧已綠。", "早蟬發高林，晚鶑隔修竹。", "壺觴休倦劬，草閣一開浴。", "翛然非吾故，佳眠恣清熟。"]'),
('2080e2c2-f379-4320-b331-6a95f2cf445e','題蕭照畫卷','舒岳祥','宋','宋诗','song-poetry','','[]','遠峰沒空蒼，近樹森立壁。',48,'全唐诗/poet.song.227000.json','["遠峰沒空蒼，近樹森立壁。", "叢篁鬰長汀，茅茨露半脊。", "歸舟何處家，中流弄長笛。", "或恐畫師身，留此黯淡跡。"]'),
('04beeeed-bf2f-46a2-9657-f0302872bb34','往時予有湖湘之游同年黄東發提舉以清江楮衾贈別藏之四年矣山房夜寒覆之甚佳亂後不知東發避地何處作此擬寄','舒岳祥','宋','宋诗','song-poetry','','[]','我昔向湘潭，故人貽我別。',156,'全唐诗/poet.song.227000.json','["我昔向湘潭，故人貽我別。", "珍於錦鯨贈，未數綈袍脫。", "溫如陽春曦，白似臘天雪。", "香收禪榻雲，光映書齋月。", "政爾獨眠佳，毋使惡卧裂。", "陰寒不內侵，和氣無外泄。", "自從離亂來，袍褞罄攘奪。", "惟此寄僧房，與書俱不滅。", "我本生蠹魚，自愛紙中穴。", "宛如蠶作繭，蛾吐眉眼出。", "夜來初肅霜，子美衾如鐵。", "忽憶此青氈，覆我儉且潔。", "中有布衾銘，此銘無冷熱。"]'),
('72843e58-a3f2-4842-af46-832043b34ff4','謝達善見惠碧桃古體','舒岳祥','宋','宋诗','song-poetry','','[]','碧桃有佳實，方春開白花。',156,'全唐诗/poet.song.227000.json','["碧桃有佳實，方春開白花。", "花悅悅花者，實惠能詩家。", "詠花不詠實，未解寫嘆嗟。", "水蒼充朝佩，天碧瀉露華。", "空青珍莫采，帝珠浄無瑕。", "水波遠涵竹，霄影浮副瓜。", "春山浄梳掠，秋烟澹籠遮。", "卵色未有別，膽形圖更加。", "清酸笑金橘，寒脆壓銀茄。", "瑶池漱靈液，萼綠蒙翠紗。", "一食潤燥吻，再食思無邪。", "三食換仙骨，四食凌飛霞。", "回首謝玉塘，吾詩不妄誇。"]'),
('0ec30678-2ddf-48f2-ae9a-ed799860fd68','周梅所還譚山','舒岳祥','宋','宋诗','song-poetry','','[]','柴門萬物靜，秋色栖四山。',72,'全唐诗/poet.song.227000.json','["柴門萬物靜，秋色栖四山。", "風篁自灑掃，雲鳥相往還。", "而有玄寂士，泠然鳴轡環。", "此客不喜飲，舉瓢酌潺湲。", "來既無所期，去亦不可攀。", "抱月入綠蘿，枕石秋菲間。"]'),
('5e1a3ab9-c62b-4363-8b15-58b32689c49b','石臺紀遊','舒岳祥','宋','宋诗','song-poetry','','[]','蒼山面長溪，勢若飲奔馬。',96,'全唐诗/poet.song.227000.json','["蒼山面長溪，勢若飲奔馬。", "層臺跨其脊，萬古絕蕭灑。", "登臨惟茲時，朋從未云寡。", "迢迢歷榛莽，靡靡眺原野。", "白雲與翠霞，夐在履舄下。", "窮秋向摇落，霜菊摘盈把。", "賞心孰與同，幽抱欣已寫。", "邈矣千載期，名山俟來者。"]'),
('e702b642-97eb-4aef-8276-afcca0e2b55c','梅花石吟','舒岳祥','宋','宋诗','song-poetry','','[]','梅花樹下梅花石，花作玉痕石鐵色。',192,'全唐诗/poet.song.227000.json','["梅花樹下梅花石，花作玉痕石鐵色。", "黄筌粉本花光枝，風吹數片尤奇特。", "何年處士橫斜句，影落寒溪印苔磧。", "又疑飛自羅浮來，花僊謫墮投蒼璧。", "或是天星下隕時，打著梅梢滅不得。", "若非曾支織女機，機上花紋相照射。", "定是荆和泣玉時，淚入璞間餘點滴。", "不然越女昔浣紗，指痕印粉難揩拭。", "荒唐詭幻不可窮，我自稽經探根極。", "傅巖人去實和羹，花落空巖餘此迹。", "花開花落幾春風，棄捐牆角真堪惜。", "携向簷前洗濯看，相對無言三太息。"]'),
('351f2851-37e4-495e-ba70-b36c16ec5154','蠟梅詠','舒岳祥','宋','宋诗','song-poetry','','[]','蜜蜂數日不出衙，將謂凍蟄無生涯。',128,'全唐诗/poet.song.227000.json','["蜜蜂數日不出衙，將謂凍蟄無生涯。", "今朝起看後園樹，總將蜜蠟銜爲花。", "香作蜜香色蠟色，花瓣分明是蜂翼。", "不是案頭乾死螢，不是營營蠅止棘。", "朝陽熠熠泛崇光，黄露溶溶蜜滿房。", "柔梢不入嬋娟鬢，道韻偏宜冷淡裝。", "與梅同時喚作梅，風味甚似枝葩非。", "若將形色定品格，何得江珧比荔枝。"]'),
('d2b2e968-34f7-44b2-9ccd-b557234ac086','自壽','舒岳祥','宋','宋诗','song-poetry','','[]','閬風老人五十九，白頭饑凍荒山走。',128,'全唐诗/poet.song.227000.json','["閬風老人五十九，白頭饑凍荒山走。", "偶然脫命得生還，閭里相看驚老醜。", "今朝初度最可憐，五子三孫在眼前。", "老妻欲作無麵餠，問訊雞孃渠未肯。", "海水潮小未登魚，霜後黄柑亦自疎。", "窮人作事天不與，只有紅梅相媚嫵。", "爲渠一笑買村酤，老夫自歌稚子舞。", "明年六十更可歌，大亂不死奈我何。"]'),
('df6f60b7-e861-4028-97a2-3c49b5aae705','十二月十七日歸故園酌紅梅花下','舒岳祥','宋','宋诗','song-poetry','','[]','今年剩有冬一月，今冬先得半月春。',192,'全唐诗/poet.song.227000.json','["今年剩有冬一月，今冬先得半月春。", "留春借冬皆樂事，但苦世上無閒人。", "平臯梅花如雪浪，夜色晨光迷滉漾。", "就中紅香清且妍，風流故在海棠上。", "昨夜月明天不寒，夢中走馬來花前。", "舊時都下千金買，翻棄草莽不值錢。", "性情貴遠初厭近，久不見之端可憐。", "今朝起揀白髭鬚，未能免俗爲花娛。", "小車駊騀溪石滑，一竿掛酒懸長魚。", "無人對飲花爲伴，小奴亦解吹長管。", "花應憐我老而狂，起舞踏影月凌亂。", "老人更醉三十年，不爲酒僊即花僊。"]'),
('5dd0bf50-bd45-48ac-b113-55350311caed','平皋木芙蓉千株爛然雲錦醉行其中如遊芙蓉城也作歌紀之','舒岳祥','宋','宋诗','song-poetry','','[]','牡丹一名木芍藥，拒霜也號木芙蓉。',192,'全唐诗/poet.song.227000.json','["牡丹一名木芍藥，拒霜也號木芙蓉。", "好花名盡多重疊，不取枝同取貌同。", "悲鴻一聲天雨血，落霞萬頃江飲虹。", "水花已盡岸花出，千朵萬朵能白紅。", "曾共鴛鴦登繡縟，也隨鸂鶒上屏風。", "金釵欲插嫌花重，玉手高攀與面重。", "弄色合歡無限思，九心千葉爲誰容。", "朝看花開紅偏淡，暮見花斂紅轉濃。", "朝開夕斂如趨市，明日風光移別蘤。", "平生愛花入骨髓，白頭出沒與花似。", "老我逢花六十秋，花開花落水悠悠。", "未喫太平一杯酒，歲歲花開伴白頭。"]'),
('e2d0f3a4-9094-466b-8b4c-7f62bca31df8','老融墨戲詞','舒岳祥','宋','宋诗','song-poetry','','[]','寒木蕭蕭，寒汀渺渺。',50,'全唐诗/poet.song.227000.json','["寒木蕭蕭，寒汀渺渺。", "船尾插竿童子閒，船頭推篷天欲曉，鴈鴈斜飛起衰草。", "頗記江湖獨宿時，一夢十年看未了。"]'),
('aef1c9a3-8278-4fd5-bafe-888c398fce5f','贈楊佳孫','舒岳祥','宋','宋诗','song-poetry','','[]','作詩意得在句先，下筆直寫意所到。',96,'全唐诗/poet.song.227000.json','["作詩意得在句先，下筆直寫意所到。", "世間惟俗最難醫，剖石得玉加精巧。", "初如面壁無所睹，一點圓明通萬竅。", "楊生楊生聽我言，老語諄諄毋乃耄。", "生平十九未可量，淘洗晶熒方入妙。", "一再三見志愈堅，嘉子至意爲傾倒。"]'),
('ebe03922-9d0d-4132-9195-6c03792327ef','七月十一日曉聞鶑有感','舒岳祥','宋','宋诗','song-poetry','','[]','秋曉秋鶑鳴綠樹，我自徘徊不能去。',64,'全唐诗/poet.song.227000.json','["秋曉秋鶑鳴綠樹，我自徘徊不能去。", "年年鳴值晚春時，曉窗共聽人何處。", "鶑鶑少駐聽我吟，我吟未成淚雙注。", "來年啼上繭頭山，爲說老人題此句。"]'),
('91caf108-6ec1-4b25-b253-777fe20f8d49','題潘少白詩','舒岳祥','宋','宋诗','song-poetry','','[]','海颶既過天泬寥，瓦檠弄焰靜自摇。',104,'全唐诗/poet.song.227000.json','["海颶既過天泬寥，瓦檠弄焰靜自摇。", "特山吟稿適在案，讀罷不知山月高。", "早從唐體入圓妥，更向派家事掀簸。", "盡囊六卷要我刪，子自得之何必我。", "燕騎紛紛塵暗天，少陵詩史在眼前，我才衰退空茫然。", "君能於此更著力，唐體派家俱可捐。"]'),
('c3ed940d-2d71-4882-b06a-66fe29a1e269','牡丹','舒岳祥','宋','宋诗','song-poetry','','[]','東風常带三分冷，春日自有一種香。',96,'全唐诗/poet.song.227000.json','["東風常带三分冷，春日自有一種香。", "百花合和不可揀，中人如酒令人狂。", "馬塍賣花只貪早，野翁自愛開遲好。", "看花不可見花心，爛熳開時春已老。", "梢頭繭栗幻柈杅，有許包藏費天巧。", "自携尊酒醉花陰，偃仰鹿皮聽語少。"]'),
('c78939a4-0b46-4e09-930f-cbe6f7bae983','近作對江牡丹吟七章呈正仲正仲於拙吟無不亟和者獨此七章未和携而歸茭湖半月矣遞筒未至歌以趣之','舒岳祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','邵子花開二十四，吟詩驚動洛諸公。',192,'全唐诗/poet.song.227000.json','["邵子花開二十四，吟詩驚動洛諸公。", "我家兩株三十枝，歡喜亦與邵子同。", "作詩七絕惱正仲，過旬不見回郵筒。", "正仲材高氣浩博，鄙我瑣細無豪雄。", "文叔今見小敵怯，八駿豈肯盤蟻封。", "再三思索得其意，笑我不知時節異。", "洛陽城中天地中，春色花光好天氣。", "此時高韻一兩篇，流出胸中真樂事。", "我生初見錢塘春，歌舞西湖早已顰。", "如今不見湖山面，鳥歌似哭花爲塵。", "作詩告人誰爲聽，當哀而樂非天真。", "我謝正仲此意厚，請不吟詩但飲酒。"]'),
('9a7a3db5-6b9f-4c9b-aca5-d09662331678','次韻和正仲碧蓮花','舒岳祥','宋','宋诗','song-poetry','','[]','好翁和了碧桃詠，并欲盡賦園中花。',144,'全唐诗/poet.song.227000.json','["好翁和了碧桃詠，并欲盡賦園中花。", "思遲才退句未吐，高篇已捷老柏塗。", "此花蔓生枝自勁，天水碧染雪藕紗。", "振鷺蟬聯蒼玉佩，不比掘閲紛衣麻。", "山阿幽人貞且吉，城隅靜女澹以華。", "偶然種之近蒼柏，君比兔絲疑未嘉。", "兔絲無根空托附，結子濫充方藥家。", "小兒欲以凌霄擬，一種麤俗堪歎嗟。", "碧蓮比擬最清切，好向天苑凌青霞。"]'),
('7ec6394f-ce0e-42f6-8358-951dc5699085','分龍吟','舒岳祥','宋','宋诗','song-poetry','','[]','五月二十分龍雨，今日霏微如下土。',252,'全唐诗/poet.song.227000.json','["五月二十分龍雨，今日霏微如下土。", "前日何日何霖霪，正是分龍乃如許。", "有餘不足相乘除，天道人事元非疎。", "何龍分得此鄉雨，問龍先日何處居。", "我昔遊三江五湖，江湖處處皆龍潴。", "我老歸農卧海曲，與龍爲隣無猜虞。", "一盂飽飯龍所與，一片閒雲龍所噓。", "百年地主屬老夫，龍來龍去識我無。", "神龍飲食與人異，布席欲薦寒泉蔬。", "我知雨從龍身落，有時雨過墮蝦魚。", "昔年海上親眼見，龍出滄溟騰碧虛。", "蜿蜒百丈露爪尾，黑水精靈光徹軀。", "龍兮只在人頭上，人不語龍誰語乎。", "我有一寸愚，願龍聽區區。", "一村南北異時雨，天公用意何偏枯。", "願龍溥澤均八極，東海蒼生誠可吁。"]'),
('74911ef8-688d-4aff-9910-9b352c2ae0e5','歸至相見嶺喜見紫海','舒岳祥','宋','宋诗','song-poetry','','[]','相見嶺頭相見少，北風吹却南翁倒。',64,'全唐诗/poet.song.227000.json','["相見嶺頭相見少，北風吹却南翁倒。", "短日荒荒白草枯，顛狂亂葉如飛鳥。", "前峯低處紫海出，知是吾歸里中道。", "父兄問訊今何如，只是相公言語好。"]'),
('506aecff-0f33-4d18-85ea-7ac407a109e9','潘少白前歲惠予零陵石一片方不及尺而文理巧秀有山水煙雲之狀予以作硯屏始成因賦長吟以遺之','舒岳祥','宋','宋诗','song-poetry','','[]','白雲際天隅，峯峯爭秀出。',218,'全唐诗/poet.song.227000.json','["白雲際天隅，峯峯爭秀出。", "浩浩水石灘，歸鳥時滅沒。", "我欲茅三間，巢此重疊峰。", "我欲舟一葉，釣此蒼茫中。", "君從何處得此石，千巖萬壑在方尺。", "李成范寬格深秀，關仝荆浩骨峭特。", "殆非一人之所能，欲窮其源不可得。", "君言此物出零陵，遠近來去皆天成。", "是中能著元次山，刻詩勒頌留孱顔。", "後來柳子曾作守，銘記摹寫無遺閑。", "二子去後精魄在，文章散落水石間。", "鬼神往往竊餘巧，戲弄筆墨留斑斑。", "贈我以作書硯屏，林風石月秋泠泠，蕭齋靜對如有聆。", "元子柳子突出也大奇，今日之事我爲之。"]'),
('d1741e20-fa69-4468-b706-e76bccbb07b6','樂神曲','舒岳祥','宋','宋诗','song-poetry','','[]','汙田稻子輸官糧，高田豆角初上場。',176,'全唐诗/poet.song.227000.json','["汙田稻子輸官糧，高田豆角初上場。", "楓林沉沉誰打鼓，農家報本兼祈禳。", "打鼓打鼓急打鼓，大巫邀神小巫舞。", "絳衫繡帔朱冠裳，手持鈴劍道神語。", "前年軍過雞柵空，今年一母生十雄。", "甽東種秫穫頗厚，大甑炊糍甕成酒。", "家機白布闊且長，翁媼製作新衣裳。", "再拜奠神重酌酒，男耕女桑十倍强。", "大婦小婦別有祝，生養好男房計足。", "巫公巫公告爾神，産穀不如多産銀。", "馿載馬馱車碌碌，免斫柘條行箠扑。"]'),
('e8f75a08-53ba-4ac9-9b33-eb8003557949','退之謂以鳥鳴春往往鳥以夏鳴耳古人麥黄韻鸝庚之句乃真知時山齋靜聽嘲哳羣萃有麥熟之鳴戲集鳥名而賦之','舒岳祥','宋','宋诗','song-poetry','','[]','麥熟即快活，汝不食麥空饒舌。',368,'全唐诗/poet.song.227000.json','["麥熟即快活，汝不食麥空饒舌。", "前時斗粟銀百星，老農無銀色菜青。", "此鳥年年啄草子，今年草根救人死。", "鳥無所食饑奈何，見人食麥喜且歌。", "催人鍛磨尤慇懃，前身恐是老農身。", "大麥炊糍先祭祖，小麥作餠賽田神。", "姊捉麥，姊捉麥，姊娣相隨筐有獲。", "田間滯穟縱復橫，傴僂東阡與西陌。", "婆餠焦，斷消息。", "而今麥熟婆當還，莫憂餠焦兒不食。", "脫布袴，村村雨滿田無路。", "平生不慣著新衣，兩腿泥深逐牛步。", "脫破袍，與郎裁衫兩髀高。", "田頭赫日曬額焦，脫衣掛樹踏桔槔。", "畫眉叫，畫眉叫，抹截梳裝趁炊早。", "夫婦如賓有古風，烏頭白頰宜相好。", "上堂問訊白頭翁，蚤晚寒溫候不同。", "善事阿姑姑不惡，麤茶淡飯是家風。", "提葫蘆，沽美酒，布帘書字隣家有。", "沽來行饁望田頭，先酌甆甌奉姑舅。", "不學前村百舌兒，說非說是摇花柳。", "不學桑間鳩婦相勃磎，天陰逐去晴歸來。", "大婦偷，我弗偷，辨說曲直令儂羞。", "淺鋪薄遍煮莧汁，二升麥餠鶻突流。"]'),
('e86834e4-3126-46be-9f45-c67d92c23b4c','梅下洗盞酌台紅感舊','舒岳祥','宋','宋诗','song-poetry','','[]','天台紅酒須銀杯，清光妙色相發揮。',64,'全唐诗/poet.song.227000.json','["天台紅酒須銀杯，清光妙色相發揮。", "甆髹玉石豈不雅，君第酌之應自知。", "我有銀杯何所宜，恕齋惠我前朝得。", "今朝把酒竟茫然，梅花萬里人南北。"]'),
('7a83b850-cd69-45eb-b9b0-0d3487729868','賦山菴梅花','舒岳祥','宋','宋诗','song-poetry','','[]','庭前梅花八九樹，長爲春風導先路。',80,'全唐诗/poet.song.227000.json','["庭前梅花八九樹，長爲春風導先路。", "他山消息未曾真，特與詩人映門戶。", "無情有性悟色空，將影和香作言語。", "吳酥入酒鬭輕明，是雪是花并月咀。", "折來燭下看橫斜，素屏淡墨無聲句。"]'),
('da6387bd-3d66-475f-9680-03238ed292b6','生日仲素惠羊酒作此奉謝','舒岳祥','宋','宋诗','song-poetry','','[]','去年蝶軒饋羊酒，主人憐我空無有。',208,'全唐诗/poet.song.227000.json','["去年蝶軒饋羊酒，主人憐我空無有。", "座上六客皆解吟，一翁不吟開笑口。", "今年病叟蚤還山，烹雞炰鱉翁對媼。", "五男四婦六稚孫，更有曾孫依乳姆。", "往來兩載總遭荒，瓦瓶聊以挹酒漿。", "山蔬滿盤白雪白，野橘堆飣黄金黄。", "荒村得此已自足，羣奴饑啄撐空腸。", "忽聞棠谿有書至，袁詩陳賦兩輝煌。", "一松正可枯蘗比，五雛真與羣雞爭。", "舉家病瘧涉三月，一日計減一斗糧。", "留儲到此作素供，問君何爲特殺生。", "臟神見夢羊踏菜，便呼茗椀來祓禳。", "君當戒屠我辟穀，輕身與蝶同飛揚。"]'),
('64f487e2-53c3-42bf-9c5c-338cae3d3c09','田公姥詞','舒岳祥','宋','宋诗','song-poetry','','[]','田公布衣五尺長，田姥角冠八寸强。',164,'全唐诗/poet.song.227000.json','["田公布衣五尺長，田姥角冠八寸强。", "平生布施不造殃，教養兒孫耕與桑。", "田公姥，生爲農家夫與婦。", "壽考百年作田祖，歲歲田頭管風雨。", "春三秋九享雞豚，环珓神靈如對語。", "田公姥，聽儂歌，看儂舞。", "使我倉有秔，使我庾有稌，使我囷有黍。", "使我富牛羊，千斯牸兮百斯牯。", "田公姥，儂肴芬芬兮儂酒湑湑，官稅既輸兮公役不煩。", "男不爲人驅，女不爲傖婦，讀書識字應門戶。"]'),
('dc5dbeb7-0b68-4665-8b86-a6af45edc7ed','次韻和李寔父焰火行','舒岳祥','宋','宋诗','song-poetry','','[]','山樵夏斬樗櫟枝，受盡日炙兼風吹。',130,'全唐诗/poet.song.227000.json','["山樵夏斬樗櫟枝，受盡日炙兼風吹。", "天寒歲晚見功用，春透肝鬲連腰肢。", "一室暖香勝樺燭，破衲紉縫針線續。", "牀頭甕子新篘成，翁媼分虀小筵席。", "山家此樂無厭時，何須玉筍扶金巵。", "我亦平生知此味，今年此味奇更奇。", "山中低厂編錯薪，不知山外飛氛塵。", "一塵一窩榾柮老稚均，此時痛快出苦辛。"]'),
('538e6cb0-dca7-4d12-9fd5-4765f1ccad7d','虞美人草','舒岳祥','宋','宋诗','song-poetry','','[]','咸陽一火燒天紅，重瞳將軍帝業空。',320,'全唐诗/poet.song.227000.json','["咸陽一火燒天紅，重瞳將軍帝業空。", "欲據彭城作盟主，漢王隨手定關中。", "垓下楚歌聞太晚，帳前驚起途已窮。", "當時楚士盡漢歸，只有虞兮心不離。", "悲歌泣下計何短，項王去後知屬誰。", "世傳姬死橫中道，怨魄悲魂化青草。", "年年摇曳舞春風，枝似柳條花似蓼。", "羅衣猶自作吳粧，也似美人顔色好。", "有人傳曲入絲桐，宛轉吳音泣帳中。", "試將此曲花前奏，花能起舞腰肢弓。", "但疑此事史無書，項王潰去姬何如。", "只應歌罷王自走，不爲虞兮一回首。", "死耶禽耶兩不知，流傳想像寄花枝。", "人生變化那可料，蜀王曾化爲子規。", "楚王剽悍骨肉叛，項伯私漢無親臣。", "范增怒去黥布反，生死相隨一婦人。", "呂雉前曾入楚軍，項羽還之亦有恩。", "虞死不憐王土葬，帝王豈爲兒女仁。", "道人能識此花名，老人爲造花枝曲。", "我歌此曲花當舞，更使今人淚相續。"]'),
('87ad4a48-1f62-4e56-8aa8-218f1abf2895','庵中有紅山茶一株自臘月開至二月半爲蕊尚無數也蓋十霜十雪矣','舒岳祥','宋','宋诗','song-poetry','','[]','山茶一株紅勝燭，旋落旋開相陸續。',144,'全唐诗/poet.song.227000.json','["山茶一株紅勝燭，旋落旋開相陸續。", "朱霞散射曉霏晴，熠熠林光映幽谷。", "雪中見此朱砂杯，道人無情還悅目。", "端正濃粧不逞妖，處女頩然在幽獨。", "有時脫蒂響蒼苔，不作他花飛片逐。", "劍南樵叟設色時，就掌調丹貴勻熟。", "花容肉色兩相宜，肌理細膩端不俗。", "畫猶如此况天生，謂花無韻評未足。", "白茶雖白太清癯，何惜深紅著深綠。"]'),
('f2bdeb9e-c0d4-41f8-b9bb-dad3e699bcf3','憶筇竹杖詞','舒岳祥','宋','宋诗','song-poetry','','[]','筇竹杖，筇竹杖，敬齋惠我侔璆盪。',156,'全唐诗/poet.song.227000.json','["筇竹杖，筇竹杖，敬齋惠我侔璆盪。", "萬里岷江下峽船，大竹一筒中貯兩。", "四明直在海東頭，我得一條長在掌。", "蛟龍已蛻脊骨全，色如黄玉中心堅。", "節圍五寸莖似筆，重如鐵石聲鏗然。", "杖兮杖兮吾與爾，曾入千巖萬壑裏。", "虎豹遠遁兮魑魅不逢，走及狙公兮追及鹿子。", "忽不見兮誰從，寧入水兮爲龍。", "或以撾馬兮其毀，不逢日暮兮山空，篁竹鬼嘯兮霧雨其濛。"]'),
('cd0ddd76-17e1-407b-863c-11e6a053ca0d','餞歲行','舒岳祥','宋','宋诗','song-poetry','','[]','歲來沙上草頭迎，歲去梅邊雪中送。',160,'全唐诗/poet.song.227000.json','["歲來沙上草頭迎，歲去梅邊雪中送。", "歲去年來不自由，我亦送迎何所用。", "人情厭舊只歡新，不道新來老却人。", "喜爲兒孫添一歲，可憐光景轉成塵。", "送君此去信悠哉，不知明日肯重來。", "宇宙無窮迷道路，追隨不見上層臺。", "蕭蕭便恐逐風散，茫茫尚想隨潮回。", "歲去怱怱不復顧，我猶留此君何處。", "非緣故歲去無情，自是新年促君去。", "送故迎新一百年，不迎不送無新故。"]'),
('bc82de16-53f1-4627-aab9-804d15694850','守歲行','舒岳祥','宋','宋诗','song-poetry','','[]','一年辛苦歲終成，夜杵相聞曉甑香。',208,'全唐诗/poet.song.227000.json','["一年辛苦歲終成，夜杵相聞曉甑香。", "缸面浮蛆初滃滃，小槽壓作春簷鳴。", "東隣麥磨連日響，餠料已具蔞牙長。", "磨刀霍霍割紅鮮，銀鬣翻光趁湖上。", "歲闌無事且招邀，隣曲披榛共來往。", "爲言今歲勝去年，來歲應須更勝前。", "去年除夜各走險，荒村千里無人煙。", "今年山舍一爐火，妻子甥孫相對坐。", "巷翁里媼在眼前，共酌瓦盆行果蓏。", "只憐舊歲去無還，惜此須臾未去間。", "多情一宿尚難別，况是相同一歲闌。", "固知無計得留駐，只怕眠中不知去。", "添燈續火甚慇懃，起寫桃符覓詩句。"]'),
('a0d6a4e7-8886-4f0d-ab08-a13f5e9b4932','浣紗婦','舒岳祥','宋','宋诗','song-poetry','','[]','修竹柴門向山路，晴日滿溪春欲莫。',40,'全唐诗/poet.song.227000.json','["修竹柴門向山路，晴日滿溪春欲莫。", "浣紗少婦不知寒，兩脚如霜下灘去，少年閑倚青梅樹。"]'),
('7f8160ef-4812-422d-bbe1-37e44cefc7a1','一蓑','舒岳祥','宋','宋诗','song-poetry','','[]','蓬窗漏晚風，蓑衣蓋秋雨。',40,'全唐诗/poet.song.227000.json','["蓬窗漏晚風，蓑衣蓋秋雨。", "蒲白早潮來，小兒事扶櫓。", "三尺鯉魚飛上天，漁翁醉卧不能舉。"]'),
('7aae1eed-64d0-4bfc-b280-8fcffa396ead','六月十四夜久雨新霽見月極佳坐觀萬堂中收拾塵霓湛然不作久不見此趣因書之以寄正仲','舒岳祥','宋','宋诗','song-poetry','','[]','久雨新霽如發蒙，嫩月出海來屋東。',160,'全唐诗/poet.song.227000.json','["久雨新霽如發蒙，嫩月出海來屋東。", "開軒靜聽百蟲語，清光入沼翻簾櫳。", "白日勞勞生萬事，不如淡月含冥濛。", "收心展體且高枕，合眼不管東方紅。", "我緣居貧得清省，晏起一粥黄昏鐘。", "更深一頓白湯餠，坐送落月沉西峰。", "眼昏燈下不看字，與書相忘如不逢。", "漸收少年辟穀效，養取眼力成方瞳。", "自行此法頗簡易，有能修之神氣充。", "臨役多憂劉正仲，少忍一月毋怱怱。"]'),
('0d5a8fd3-6986-47d5-9bd1-02907f7f2df9','正仲次韻謝證明亦翁之作此意佳甚不次韻爲報','舒岳祥','宋','宋诗','song-poetry','','[]','人言乍見易得好，以我觀君久更佳。',144,'全唐诗/poet.song.227000.json','["人言乍見易得好，以我觀君久更佳。", "古來善友晏平仲，顧沮孔子胡爲哉。", "不如寒拾兩相遇，撫掌吃吃笑口開。", "雖然是中有機事，笑人惡念自墮邪。", "不如見惡亦弗笑，惻然憫悟自嘆嗟。", "醉翁四十早自號，君年五十銜始題。", "好翁地位君須到，除拜甚稱何歉懷。", "他銜敘爵此敘齒，稱位不以官高低。", "他年同入隠逸傳，何須羊馬卧青苔。"]'),
('2b716edb-15e1-4e2b-9b00-584da65f4883','題余文叔山間四時之樓','舒岳祥','宋','宋诗','song-poetry','','[]','輕財好事余文叔，磊落襟期端不俗。',128,'全唐诗/poet.song.227000.json','["輕財好事余文叔，磊落襟期端不俗。", "外方避地客來多，我亦從君借書屋。", "屋前曲徑繞淪漪，池上高樓新結束。", "一條碧澗貫虹飛，幾片青霞排闥宿。", "四時自換景自留，是中雲月無春秋。", "家家見山長在眼，處處有山堪起樓。", "不如此樓能著我，磨墨題詩樓上頭。", "主人之賢樂復樂，青山曾見此客不。"]'),
('64017bc0-a7c7-4611-9e8a-74a6fda14d02','楊白花','舒岳祥','宋','宋诗','song-poetry','','[]','楊白花，懊惱隨風渡江水。',76,'全唐诗/poet.song.227000.json','["楊白花，懊惱隨風渡江水。", "將心莫託少年郎，少年一去輕萬里。", "楊條插地便生根，花性飄揚似夢塵。", "恨不築城高萬丈，花飛莫放出重門。", "珠簾繡柱香雲護，祇有黄鶑知去路。"]'),
('e9ec802a-dccf-498b-adb4-faebc9d6be09','騎牛歌題厲歸真騎牛圖','舒岳祥','宋','宋诗','song-poetry','','[]','人騎馬，我騎牛。',112,'全唐诗/poet.song.227000.json','["人騎馬，我騎牛。", "騎馬行大道，青絲爲轡金絡頭。", "胡衣北笠見者走，揚鞭指顧矜朋儔。", "騎牛入山谷，不覊不勒無拘束。", "我只騎牛犢自隨，母子相呼煙草綠。", "騎馬不若騎牛安，牛自肥芻馬傷穀。", "我見騎馬郎，白金入手遭鞭朴。", "何如騎牛兒，樹下高眠無寵辱。"]'),
('0a67d885-5437-4d30-ae6f-c5dcca949084','烏鹽角行','舒岳祥','宋','宋诗','song-poetry','','[]','山中一種烏鹽樹，剝皮爲角開春路。',84,'全唐诗/poet.song.227000.json','["山中一種烏鹽樹，剝皮爲角開春路。", "牧童把去上牛吹，煙草茫茫沒遠陂。", "一聲兩聲兮桑青柘綠，三聲四聲兮麥綻秧肥。", "山花如火遮眉目，吹此田家太平曲。", "三年不聽此曲聲，捲却地皮人痛哭。"]'),
('a05d45aa-5cbd-4719-8504-e448d25f7d7c','碧桃','舒岳祥','宋','宋诗','song-poetry','','[]','碧桃本是僊人花，僊人花裏飯胡麻。',128,'全唐诗/poet.song.227000.json','["碧桃本是僊人花，僊人花裏飯胡麻。", "初來此樹向誰得，翠眉嬋娟萼綠華。", "世間俗桃千百數，溪谷往往蒸成霞。", "紛紛見此欲羞死，亂紅吹落污窗紗。", "陳宮露唾天水碧，粉黛欲學爭咨嗟。", "豈知僊妃作狡獪，挼花染汁便爾嘉。", "瑶池蟠桃即此種，花飛不肯污泥沙。", "實成唯許方朔喫，時時還戲王母家。"]'),
('2935ce79-fb1b-4d0a-835d-1671ec47df2d','山甫畫松','舒岳祥','宋','宋诗','song-poetry','','[]','山甫作古松，意造無定本。',130,'全唐诗/poet.song.227000.json','["山甫作古松，意造無定本。", "枝枝藏太陰，筆筆涵混沌。", "氣吞千尺崖，猶作飛瀑滾。", "肺肝生洞壑，槎枒出隠嶙。", "奮臂盤礴餘，墨漬筆不吮。", "若人蓋天機，豈爲尋丈窘。", "胸中有磥砢，欲出不可忍。", "恐是城南樹，寫形難自隠。", "嗚呼夾山自有真松圖，朝夕左右陳座隅。", "伐薪架屋聽笙竽，好翁之計誠非疎。"]'),
('7920745f-c741-4967-a4b8-722324a871b9','曉霜成花日色凄淡炙背南簷記所聞見','舒岳祥','宋','宋诗','song-poetry','','[]','十月二十有二日，霜凇成花泥淈淈。',96,'全唐诗/poet.song.227000.json','["十月二十有二日，霜凇成花泥淈淈。", "黑旗一點飛過村，居民縮頭那敢出。", "又聞鄞騎入連山，搜捕鄉兵火廬室。", "台明隔嶺易張皇，紛紛徙家藏穀實。", "須臾又報兵首擒，向來安民今未畢。", "老夫開戶望前山，且炙南簷半窗日。"]'),
('a7666862-f66c-4005-bd51-340f491ecb12','出入二嶺行','舒岳祥','宋','宋诗','song-poetry','','[]','出童公，入童公，一嶺二水分西東。',260,'全唐诗/poet.song.227000.json','["出童公，入童公，一嶺二水分西東。", "前山萬竹入新路，新路蒼海通方蓬。", "入黄甘，出黄甘，一山二水分北南。", "北南百谷會江海，鎮亭下注南山潭。", "問君何事經二嶺，辟寇辟兵探絕境。", "青山兩路雙闕開，桑柘人煙在深井。", "迢迢橫過澄溪頭，水風激激流人影。", "籃輿落日黄泥坂，短策東風日將晚。", "深竹人家少隣並，麥苗翠被鋪平田。", "忍饑猶自念民饑，餠餌風來一飽寬。", "况今聖算窮幽遐，檢括丁口究阡陌。", "或說更戍起南氓，或議關防驅北客。", "中原隴土少人耕，何惜就寬因去窄。", "自古先王訂版圖，兵農合一如常式。", "嗚呼先王爲民定軍例，後王爲軍定民籍。", "嗚呼老儒臨風三歎息，爲國何如惜民力。"]'),
('62fb537e-4a11-4731-9d5f-e72a8502f7c0','春雪','舒岳祥','宋','宋诗','song-poetry','','[]','去年臘雪已四白，五白六白農夫愁。',130,'全唐诗/poet.song.227000.json','["去年臘雪已四白，五白六白農夫愁。", "麥苗凍熟鋤不得，菜心僵死何時抽。", "常年梅花已爛漫，今者乾沒如拘囚。", "枯枝尚黏紅豆綠，細蘂初作蒼蠅頭。", "紛紛黄雀狡於鼠，窮閻有粟爭呼取。", "老鳶自作攫肉謀，空屋狐貍夜相聚。", "嗚呼狐貍有屋爾得居，室中居人今在無。", "或言白骨如白雪，雪亦有仁遮白骨。"]'),
('1ee55b8e-8ffd-440e-9154-a27722298af1','綠萼香梅十樹咸淳間自內前買歸亂後尚存對之感歎','舒岳祥','宋','宋诗','song-poetry','','[]','縞衣黄裏綠雲跗，僊家結束來天隅。',128,'全唐诗/poet.song.227000.json','["縞衣黄裏綠雲跗，僊家結束來天隅。", "承平故態今尚爾，流落空山成歎吁。", "莫對此花被渠惱，惜花情重人先老。", "多少當時似玉人，埋沒沙場隨塞草。", "杳杳宮車去不回，上林雁過無書到。", "內園今更不堪看，蝶廢蜂休日易昏。", "玉砌無人寒兔入，觚稜棲草野鴟蹲。", "黍離麥秀今如此，豈爲梅花故斷魂。"]'),
('47dc71ae-ec7d-4540-b635-bfc7a1bfb007','詵十二弟以冬菊盆爲余壽此花品金色而中心作葱管突起正如金荔子乃作雪中英一首謝之','舒岳祥','宋','宋诗','song-poetry','','[]','弟以冬菊爲兄壽，臨風多情爲三嗅。',154,'全唐诗/poet.song.227000.json','["弟以冬菊爲兄壽，臨風多情爲三嗅。", "煌煌金椀覆金柈，葱管玲瓏明艷透。", "重陽曾見金佛頭，頂似旋螺踴泡漚。", "別有一種金荔子，心中簇簇高堆起。", "此時衆菊爭紛敷，二品於中亦自殊。", "况此千林骨立後，何從得此金覆盂。", "從來菊號霜下傑，今當喚作雪中英。", "雪中松柏不若汝剛貞，孔云後凋特晚耳，冬嶺落毛釵亂橫。", "水仙山礬何足道，此花便是梅花兄。"]'),
('9509dc58-f5ab-4f57-95d6-b738666797a5','桂臺','舒岳祥','宋','宋诗','song-poetry','','[]','神龍不知身變化，猶認潜鱗爲故我。',288,'全唐诗/poet.song.227000.json','["神龍不知身變化，猶認潜鱗爲故我。", "先生曾出雨八紘，浪靜波恬歸海卧。", "先生兩處領桂臺，夢寐一生遊學舍。", "阿宜移扁就山窗，鐵畫銀鈎金鈕鏁。", "綠陰閉戶不知春，長日觀書誰覺夏。", "天上吹香遍遠山，月中散影流清夜。", "先生見扁如坐齋，隨行不用木上座。", "攀枝踏影弄猿鶴，萬事不到桂叢下。", "天下清芬是此花，世間最俗惟檀麝。", "後車還許樂天陪，吟筆更須侯喜把。", "幾人名遂不知幾，一日倉皇方淚墮。", "人知德祐不出高，豈識咸淳歸計果。", "平生一瓣桂臺香，口誦翁詩幾百過。", "舊臺何在桂凋零，日暮哀禽自相和。", "今臺喜見桂婆娑，往來不礙江鷗社。", "舊臺不見見今臺，依舊風流壓江左。", "他年人訪桂臺游，舊名更復因今播。", "月中桂樹最久長，此樹還如月輪大。"]'),
('502f5770-c87a-43bc-af1c-eba3bb34f8bf','十二月初一日醉歌','舒岳祥','宋','宋诗','song-poetry','','[]','常年此日正月吉，今年經閏臘月一。',162,'全唐诗/poet.song.227000.json','["常年此日正月吉，今年經閏臘月一。", "歲闌喜展一月期，勝似戈揮魯陽日。", "搔頭偶見鶩陳橫，曝背閑看蜂衙出。", "一冬妍暖三月晴，薄雪微雨麥壠青。", "平臯十畝耡溉畢，明年擬取甔石贏。", "歸耕還有新權柄，向時樵長今里正。", "弟姪推尊不敢辭，斗酒隻雞先自慶。", "牧豬釀秫待誅求，賣田買鈔博性命。", "北人自好南人惡，人事紛紛天未定。", "君不見唐任濤宋魏閑，因詩放後逢寬令。"]'),
('85f55678-2219-4d86-a1b5-c4c8aaf1428f','九日敏求與姪璋九萬載酒蓀墅邀予與胡山甫潘少白及華頂周服之道士周若晦作客欲摘蕊浮杯叢委草間未有消息憫然賦之','舒岳祥','宋','宋诗','song-poetry','','[]','五柳先生貧欠酒，不說無花過重九。',176,'全唐诗/poet.song.227000.json','["五柳先生貧欠酒，不說無花過重九。", "杜陵野客酒可賒，只恨青蕊成蹉跎。", "如今風物尤悽惻，繞叢覓蕊無消息。", "寒螿相弔野水流，病蝶來偎寒日夕。", "不見金錢將翠羽，惟有悲風吹蔓棘。", "古人愛汝非無意，志士仁人例憔悴。", "楚國無人屈子傷，陶杜凄凉唐晉季。", "此日何日悲更悲，聊嗅青枝記一時。", "往時好事環轍迹，建業錢塘華盡識。", "就中內本碧玉杯，欲買黄金惜不得。", "兩都風景今何如，淚墮叢邊和露滴。"]'),
('47038343-c262-43ac-a7c1-6bd75ee81c9e','孤雁','舒岳祥','宋','宋诗','song-poetry','','[]','憂心悄悄睡未能，開門看月一片冰。',208,'全唐诗/poet.song.227000.json','["憂心悄悄睡未能，開門看月一片冰。", "竅木相磨作鬼語，凍星入牖如螢青。", "孤雁哀號向何處，老夫掩耳不欲聽。", "爾從沙場經萬里，昔時繫書達天子。", "如今若向上林過，縱有書來誰取視。", "陰山豁處狹如門，結陣來時各有羣。", "辛苦避鷹兼避弋，前行半度後行分。", "秋水江南無所畏，老菰沉米蘆摇穗。", "鷗鳬善熟少驚猜，飲啄不爭遊且戲。", "不知何事背羣飛，欲宿無依去無疑。", "天長路杳翅流血，夜向霜凄聲轉微。", "自倚能飛無與敵，豈知天勢有違機。", "作書好報前征侶，看取悲鳴落羽時。"]'),
('265bb2d1-1f5f-4a45-ac4e-ada0448f7ea0','罪言','舒岳祥','宋','宋诗','song-poetry','','[]','匪兕匪虎吾道非，鸜之鵒之侯不歸。',200,'全唐诗/poet.song.227000.json','["匪兕匪虎吾道非，鸜之鵒之侯不歸。", "山南山北靡有定，瀼東瀼西生計微。", "頹牆宿莽露泥泥，荒田野菊秋菲菲。", "我止安息，我行安之。", "噫吁嘻！過殷墟兮麥漸漸，覽周原兮黍離離。", "黍麥之秀，黍麥之有。", "無麥無禾，不耕胡取。", "白骨兮成豀，膏肉兮成泥。", "已焉哉！想自古之如彼，匪斯今之可哀。", "死莫懲於既往，生胡保其將來。", "東溟之濱，相奪相攘。", "殺人填海，浩浩不盈。", "輪迴報復，此死彼生。", "天假手於王師，使盡殪於秦坑。", "痛臨淵而一弔，悲萬古之茫茫。"]'),
('d7951180-c334-4b37-88fc-f766d437a418','雜言','舒岳祥','宋','宋诗','song-poetry','','[]','瑣兮尾兮胡中露，鸜之鵒之在乾侯。',82,'全唐诗/poet.song.227000.json','["瑣兮尾兮胡中露，鸜之鵒之在乾侯。", "朝吟九歎復五噫，暮賡七歌并四愁。", "白日曀曀，中林幽幽。", "墐塞兩版，蒙茸一裘。", "屋漏煤墮，糜攪粕浮。", "美人不來兮歲暮誰謂。", "霰雪滮滮，落葉如雨。"]'),
('6a9f30c7-3a18-4e69-bede-6c1a3cb6a155','杜鵑花','舒岳祥','宋','宋诗','song-poetry','','[]','杜陵野老拜杜鵑，念渠蜀王身所變。',192,'全唐诗/poet.song.227000.json','["杜陵野老拜杜鵑，念渠蜀王身所變。", "我今流涕杜鵑花，爲是此禽流血濺。", "嗟哉杜宇何其愚，萬事成敗皆斯須。", "一枰黑白翻覆手，揖讓放弒皆丘墟。", "汝初一身今百億，凝滯結戀胡爲乎。", "爾生不能存社稷，死怨謝豹何區區。", "至今有子不自保，寄巢生育非良圖。", "百億禽分百億花，數若恒河沙復沙。", "此花開時此鳥至，青楓苦竹爲其家。", "錦官玉壘不可念，翠華黄屋天之涯。", "不聞十月杜鵑鳥，只見十月杜鵑花。", "何必看花與聽鳥，老夫日日自思家。"]'),
('d74ab1b5-631f-4021-a53e-317eae06e9bd','解梅嘲','舒岳祥','宋','宋诗','song-poetry','','[]','昨夜鵂鶹聲婉孌，斗覺春隨呼喚轉。',176,'全唐诗/poet.song.227000.json','["昨夜鵂鶹聲婉孌，斗覺春隨呼喚轉。", "今朝檢歷知立春，屋角梅花笑初囅。", "向人带笑復含嗔，嗔我今爲異代民。", "我語梅花勿嗔笑，四海已非唐日照。", "爾花也是易姓花，憔悴荒園守空嶠。", "閬風自是可憐人，六十年來逢立春。", "安危治亂幾番見，到此三年哭斷魂。", "我是先朝前進士，賤無職守不得死。", "難學夷齊餓首陽，聊效陶潛書甲子。", "星回世換市朝新，頭白空山與鬼鄰。", "更有橫金拖紫客，臨危不死穩藏身。"]'),
('b1271472-9e98-4a17-a0d1-c9cac77ecb65','年根雨雪行','舒岳祥','宋','宋诗','song-poetry','','[]','霧雨弊弊生窮歲，雞寒入屋犬竇吠。',80,'全唐诗/poet.song.227000.json','["霧雨弊弊生窮歲，雞寒入屋犬竇吠。", "老衾破絮少溫存，濕薪吐汁無氣勢。", "一冬已近四月晴，殘歲垂垂點滴聲。", "人心無底難爲德，一日不作將不食。", "年頭未有五日糧，井花水滿人閉倉。"]'),
('5917c258-52c1-454b-9a63-0a7c4857e357','槐花','舒岳祥','宋','宋诗','song-poetry','','[]','尊貴三公府，匆忙舉子裝。',48,'全唐诗/poet.song.227000.json','["尊貴三公府，匆忙舉子裝。", "周官那可見，唐制自難忘。", "夕照深宮裏，西風大道旁。", "蟬鳴猶未悟，但報早秋凉。"]'),
('fc59d6d6-43ab-4d94-9de4-e9e46a7cdf6b','有田婦獻水麥甚美不知滹沱玉食曾有此否感悵作詩','舒岳祥','宋','宋诗','song-poetry','','[]','牟麥未全黄，和灰熟煮香。',48,'全唐诗/poet.song.227000.json','["牟麥未全黄，和灰熟煮香。", "嚼來冰響齒，嚥下露生吭。", "肉似雞頭韌，形疑鱟子長。", "食芹應配美，吾欲獻君王。"]'),
('cc3327a8-384c-4a03-a424-131b2ce93e9a','喜食新麥','舒岳祥','宋','宋诗','song-poetry','','[]','亂後歸田好，殘生似可延。',48,'全唐诗/poet.song.227000.json','["亂後歸田好，殘生似可延。", "餘花戀餘景，新麥起新烟。", "𤱶澮藏科斗，園林带杜鵑。", "妻孥共甘苦，一醉慰饑年。"]'),
('feccd66f-3fce-4770-a952-ae5642566f91','春日懷帥初','舒岳祥','宋','宋诗','song-poetry','','[]','夜雨流如澗，春風響似雷。',48,'全唐诗/poet.song.227000.json','["夜雨流如澗，春風響似雷。", "千愁芳草遠，一笑百花開。", "白髮癡貪酒，昏眸懶上臺。", "懷人不可見，應棹剡船回。"]'),
('eec5d57a-7281-4ba1-989e-d7c946128d9f','八月十九日得董正翁寺丞書兵疫後城中故舊十喪八九愴懷久之顧我已多幸矣','舒岳祥','宋','宋诗','song-poetry','','[]','黄菊一瓶酒，青山四壁書。',48,'全唐诗/poet.song.227000.json','["黄菊一瓶酒，青山四壁書。", "吾年餘幾許，天意復何如。", "寒日沙禽並，風霜野果疎。", "山城詢故舊，十九是丘墟。"]'),
('746e26de-9982-49cc-afc5-93ba10311f57','溪上小憩','舒岳祥','宋','宋诗','song-poetry','','[]','鵲立碧峯遠，雞啼清晝寬。',48,'全唐诗/poet.song.227000.json','["鵲立碧峯遠，雞啼清晝寬。", "青苔留客醉，白髮借書看。", "方枕藤花軟，一瓶丹井寒。", "此時無二事，藜杖共盤桓。"]'),
('32905715-95c7-4b91-a00f-f765cc0d7446','種麥後栽補桑柘至田家憩息','舒岳祥','宋','宋诗','song-poetry','','[]','桑柘疎時補，篁茅密處刪。',48,'全唐诗/poet.song.227000.json','["桑柘疎時補，篁茅密處刪。", "水邊黄葉路，雨外夕陽山。", "一鳥自啼足，兩牛相對閑。", "山翁留壁記，子丑話時艱。"]'),
('5b4fb6fb-c048-42ca-bf57-b565f180eae7','有懷寄二林','舒岳祥','宋','宋诗','song-poetry','','[]','去矣兩黄鵠，歸與一老翁。',48,'全唐诗/poet.song.227000.json','["去矣兩黄鵠，歸與一老翁。", "秋蟲陰雨裏，夕鳥水雲中。", "今古唯愁在，乾坤總幻空。", "詩成無寄處，沙上竚來鴻。"]'),
('401d2c2c-2c56-438f-a43a-c8679be867b3','有懷寄正仲','舒岳祥','宋','宋诗','song-poetry','','[]','往事沄沄逝，新愁衮衮生。',48,'全唐诗/poet.song.227000.json','["往事沄沄逝，新愁衮衮生。", "風來看木末，月上候潮聲。", "偶鳥分枝泊，鄰蛩護穴鳴。", "洗憂思學易，聞爾著書成。"]'),
('94f100f0-d658-4540-8f6c-d30968e74b1e','百年','舒岳祥','宋','宋诗','song-poetry','','[]','流水故人盡，荒村落葉多。',48,'全唐诗/poet.song.227000.json','["流水故人盡，荒村落葉多。", "空餘老矍鑠，全是病維摩。", "齒落不知味，眼花應有魔。", "百年聊爾爾，千載欲如何。"]'),
('8873c9eb-9d11-4fa4-bc87-95bd4816161d','與正仲同遊故園','舒岳祥','宋','宋诗','song-poetry','','[]','向老工詩句，殘春盡樹花。',48,'全唐诗/poet.song.227000.json','["向老工詩句，殘春盡樹花。", "君來相映發，吾得減咨嗟。", "著帽風前側，揮毫醉後斜。", "避塵如避虎，籬外便雲遮。"]'),
('0bd73e8e-5e3d-44ce-abcb-b5613a10a91d','題正仲真遊園','舒岳祥','宋','宋诗','song-poetry','','[]','借問真遊趣，華胥路不賒。',48,'全唐诗/poet.song.227000.json','["借問真遊趣，華胥路不賒。", "青黄隨澗柳，紅白任巖花。", "適意絃歌鳥，無私鼓吹蛙。", "秋風榛子熟，撒雹散林鴉。"]'),
('5ff2c065-3801-41e8-b38c-84a9068e7bcf','曉寒獨立紅茶花下','舒岳祥','宋','宋诗','song-poetry','','[]','長物烏皮几，宜人白氎裘。',48,'全唐诗/poet.song.227000.json','["長物烏皮几，宜人白氎裘。", "曉霜花口噤，午雨柳綿收。", "毛髮匆匆變，光陰冉冉休。", "直須瓜芡熟，長枕卧清秋。"]'),
('6f212394-bff3-4358-9214-12c2c555a0aa','田家即事','舒岳祥','宋','宋诗','song-poetry','','[]','飽暖無他事，天心亦易迴。',48,'全唐诗/poet.song.227000.json','["飽暖無他事，天心亦易迴。", "繅車翻急瀑，麥磨響輕雷。", "履辟行泥笋，衣蒸過雨梅。", "荒村斷魚肉，隨興酌山杯。"]'),
('f1a4db9e-552c-48ac-a78b-e39f5102d41e','燈花','舒岳祥','宋','宋诗','song-poetry','','[]','衆花皆可喜，最好是燈花。',48,'全唐诗/poet.song.227000.json','["衆花皆可喜，最好是燈花。", "好結無風屋，偏生有慶家。", "案頭生瑞菌，火裏養丹砂。", "清夜開樽看，山人被詔加。"]'),
('7cc5045d-b98c-4cb1-9cd9-e1282d02ce90','前所詠諸花皆托物以賦者爾未若眼花乃吾身之花豈得遺乎','舒岳祥','宋','宋诗','song-poetry','','[]','春去花亦去，何如見此花。',48,'全唐诗/poet.song.227000.json','["春去花亦去，何如見此花。", "青山飛靄合，白日亂烟遮。", "望月惟昏鏡，看書似隔紗。", "瀟湘聞夜雨，此景屬誰家。"]'),
('4f0e3e14-0f1b-4f77-8f52-9ad76aa549fe','己丑正月二十四日避地鹽楹入省坑存思庵和舊韻  其一','舒岳祥','宋','宋诗','song-poetry','','[]','到此于今四，情深即故鄉。',48,'全唐诗/poet.song.227000.json','["到此于今四，情深即故鄉。", "新松知改徑，舊竹不依行。", "平施天猶病，周回日載陽。", "鄰人餽雞黍，厚意未能償。"]'),
('b4e37390-4ab2-4dc4-a6b5-eb0e4fdfebcd','己丑正月二十四日避地鹽楹入省坑存思庵和舊韻  其二','舒岳祥','宋','宋诗','song-poetry','','[]','雪蕻羊羔白，菘芽栗肉黄。',48,'全唐诗/poet.song.227000.json','["雪蕻羊羔白，菘芽栗肉黄。", "爲誰端有此，正爾未能忘。", "覺後心無慍，修來面有光。", "道人參妙趣，一炷石鑪香。"]'),
('3508a650-742d-4dae-896e-a23574462614','七月望日避地省坑存思庵留題時章林出白石可爲水晶有旨差路縣官同金玉提舉差夫取鑿又宿兵守之吏卒旁午指予爲上戶求雞羊酒米油鐵無以應其求且不堪其屢也來避于此予念自丁丑之亂至此凡三避矣僧舊屋更新悵然有感因賦之','舒岳祥','宋','宋诗','song-poetry','','[]','去家無十里，過嶺即他鄉。',48,'全唐诗/poet.song.227000.json','["去家無十里，過嶺即他鄉。", "避地身三到，傷時淚數行。", "高簷齊古樹，新屋背斜陽。", "我欲相鄰住，青山志未償。"]'),
('57cccc46-8891-4756-a5c5-aa07954b7a27','會計家釀得十石日飲三升可周一歲是日一飲成醉','舒岳祥','宋','宋诗','song-poetry','','[]','朱朱石榴樹，白白水栀花。',48,'全唐诗/poet.song.227000.json','["朱朱石榴樹，白白水栀花。", "振鷺青溪客，遷鶯碧柳家。", "衰年新旅食，小雨夢京華。", "貧有杯中物，賓來未用賒。"]'),
('a9f391d1-c671-4ed7-883c-81d2bc5ff9c3','收心','舒岳祥','宋','宋诗','song-poetry','','[]','山寒猨夢斷，地遠雁魂歸。',48,'全唐诗/poet.song.227000.json','["山寒猨夢斷，地遠雁魂歸。", "獵火雲中樹，漁榔月下磯。", "官梅撩技癢，池草見天機。", "百歲風前燭，收心坐翠微。"]'),
('0ed5be66-3e6a-46e6-85d2-350bbbfe5650','謝周拙翁惠萬歲藤杖','舒岳祥','宋','宋诗','song-poetry','','[]','周老手中杖，天封頂上藤。',48,'全唐诗/poet.song.227000.json','["周老手中杖，天封頂上藤。", "戰龍紛可解，鬭虎斃堪乘。", "險路扶勝僕，深林肯伴僧。", "山中行住坐，頼此好交朋。"]'),
('e72bbd39-b9c1-44eb-a2c1-e756d11e81c2','歲晚寄帥初','舒岳祥','宋','宋诗','song-poetry','','[]','車魚鄮城館，書畫剡溪船。',48,'全唐诗/poet.song.227000.json','["車魚鄮城館，書畫剡溪船。", "飯顆詩應瘦，燈花人未眠。", "空林带冰月，老屋架霜烟。", "寂寞凰棲叟，思君又一年。"]'),
('1609bfc3-f16c-46d2-99f6-db89f5e352f1','睡魔','舒岳祥','宋','宋诗','song-poetry','','[]','睡魔如瘧鬼，日日應期來。',48,'全唐诗/poet.song.227000.json','["睡魔如瘧鬼，日日應期來。", "符篆燒難却，茶槍戰不開。", "中宵翻醒去，當晝又潛回。", "應是五窮數，留君共酌杯。"]'),
('034d2377-54c0-44b0-9ab8-18a80a1f1ddd','白髮','舒岳祥','宋','宋诗','song-poetry','','[]','新髮從渠白，舊顔疑我非。',48,'全唐诗/poet.song.227000.json','["新髮從渠白，舊顔疑我非。", "莫嫌冠易墮，且喜蝨無依。", "鏡裏星星出，梳來日日稀。", "長慚老松樹，翠鬣沐烟霏。"]'),
('ead53d4a-60b2-4dc8-8e07-9d66e3dc4695','石蓮花','舒岳祥','宋','宋诗','song-poetry','','[]','石上原無藕，林間自有蓮。',48,'全唐诗/poet.song.227000.json','["石上原無藕，林間自有蓮。", "開花高似雪，垂實軟如綿。", "不入江妃笑，祇令山鬼憐。", "芙蓉生木末，可證楚人篇。"]'),
('a6bd1b66-7c94-4da2-9e9d-4ae999ce7037','旱蓮','舒岳祥','宋','宋诗','song-poetry','','[]','紫玉炎天菊，紅芽陸地荷。',48,'全唐诗/poet.song.227000.json','["紫玉炎天菊，紅芽陸地荷。", "孤芳羣訕集，一笑百憂多。", "美味河豚虐，妍姿鴆毒苛。", "借渠存警戒，何必辯真訛。"]'),
('a81fae48-69a6-46e9-82db-c72df147d53a','去年大兵入台仙居幸免今冬屠掠無噍類衣冠婦女相隨俱北聞而傷之作俘婦詞','舒岳祥','宋','宋诗','song-poetry','','[]','初謂無兵禍，那知酷至斯。',48,'全唐诗/poet.song.227000.json','["初謂無兵禍，那知酷至斯。", "相看不敢哭，有死未知期。", "兒向草間沒，夫隨劍口離。", "琵琶猶带怨，况是作俘纍。"]'),
('91ae8e74-0244-4ad2-8adf-35dcadd0051a','次和杉棚','舒岳祥','宋','宋诗','song-poetry','','[]','上伏清凉散，家僮手自成。',48,'全唐诗/poet.song.227000.json','["上伏清凉散，家僮手自成。", "日斜蛟弄影，風過鼠行聲。", "解助藤床冷，何妨棐几明。", "風車捲冰雪，得似此般清。"]'),
('55b42682-e51c-4aac-ae3a-eafb7c20538d','自歸耕篆畦見村婦有摘茶車水賣魚汲水行饁寄衣舂米種麥泣布賣菜者作十婦詞  其一','舒岳祥','宋','宋诗','song-poetry','','[]','前壠摘茶婦，頃筐带露收。',48,'全唐诗/poet.song.227000.json','["前壠摘茶婦，頃筐带露收。", "艱辛知有課，歌笑似無愁。", "照水眉誰畫，簪花面不羞。", "人生重容貌，那得不梳頭。"]'),
('144bed4a-c99d-4b10-80f1-36394a1be19f','自歸耕篆畦見村婦有摘茶車水賣魚汲水行饁寄衣舂米種麥泣布賣菜者作十婦詞  其二','舒岳祥','宋','宋诗','song-poetry','','[]','田頭車水婦，挽水要流通。',48,'全唐诗/poet.song.227000.json','["田頭車水婦，挽水要流通。", "烏帽掀炎日，青裙鼓晚風。", "翻翻循故步，踏踏似虛空。", "聽取勞歌意，生身莫嫁農。"]'),
('4013f96a-fc4c-4442-8230-36dfd8f9d9db','自歸耕篆畦見村婦有摘茶車水賣魚汲水行饁寄衣舂米種麥泣布賣菜者作十婦詞  其三','舒岳祥','宋','宋诗','song-poetry','','[]','江上提魚婦，朝朝入市闉。',48,'全唐诗/poet.song.227000.json','["江上提魚婦，朝朝入市闉。", "守船留稚子，換酒醉良人。", "不著凌波襪，長垂濺水裙。", "渾家同泛客，笑殺別離津。"]'),
('1487c6f1-e696-453b-8df3-dfd005f4015e','自歸耕篆畦見村婦有摘茶車水賣魚汲水行饁寄衣舂米種麥泣布賣菜者作十婦詞  其四','舒岳祥','宋','宋诗','song-poetry','','[]','溪頭汲水婦，力小憇中途。',48,'全唐诗/poet.song.227000.json','["溪頭汲水婦，力小憇中途。", "奉佛澄齋鉢，供姑潔飯盂。", "煮蔬甘勝肉，洗布白于酥。", "釀黍修時祀，家篘不用沽。"]'),
('c895e4a6-d75f-490b-be0c-65d66f545c2e','自歸耕篆畦見村婦有摘茶車水賣魚汲水行饁寄衣舂米種麥泣布賣菜者作十婦詞  其五','舒岳祥','宋','宋诗','song-poetry','','[]','欲識農家樂，聽予行饁詞。',48,'全唐诗/poet.song.227000.json','["欲識農家樂，聽予行饁詞。", "兩家從結髮，一飯亦齊眉。", "世上恩多薄，田間禮莫違。", "不須言富貴，頭白鎮相隨。"]'),
('b2bf1807-4095-4dae-8064-e1b3ac7341de','自歸耕篆畦見村婦有摘茶車水賣魚汲水行饁寄衣舂米種麥泣布賣菜者作十婦詞  其六','舒岳祥','宋','宋诗','song-poetry','','[]','閨中寄衣婦，夫婿在遼陽。',48,'全唐诗/poet.song.227000.json','["閨中寄衣婦，夫婿在遼陽。", "夜靜翦刀響，天寒鍼線長。", "自傷乖匹偶，不肯繡鴛鴦。", "早願王師息，我歡還故鄉。"]'),
('7694fa9b-95bd-4c93-a50c-f722a065d04b','自歸耕篆畦見村婦有摘茶車水賣魚汲水行饁寄衣舂米種麥泣布賣菜者作十婦詞  其七','舒岳祥','宋','宋诗','song-poetry','','[]','田家舂米婦，隔宿辦朝糧。',48,'全唐诗/poet.song.227000.json','["田家舂米婦，隔宿辦朝糧。", "舉臼紅顔汗，投舂玉腕揚。", "雞窺篩下米，犬舐簸前糠。", "未奉翁姑食，炊塵不敢嘗。"]'),
('37e12ffa-6ad4-40e3-85e9-c92f1f47f212','自歸耕篆畦見村婦有摘茶車水賣魚汲水行饁寄衣舂米種麥泣布賣菜者作十婦詞  其八','舒岳祥','宋','宋诗','song-poetry','','[]','種麥誰家婦，青裙皂角冠。',48,'全唐诗/poet.song.227000.json','["種麥誰家婦，青裙皂角冠。", "從夫無燥濕，自小習艱難。", "窠淺愁鴉竊，株成畏馬殘。", "夜來新得雪，濁盎慰初寒。"]'),
('6cdab3c4-e28c-4c59-8db8-54c78210c5a6','自歸耕篆畦見村婦有摘茶車水賣魚汲水行饁寄衣舂米種麥泣布賣菜者作十婦詞  其九','舒岳祥','宋','宋诗','song-poetry','','[]','婦啼如此苦，吏奪一何豪。',48,'全唐诗/poet.song.227000.json','["婦啼如此苦，吏奪一何豪。", "尺布不得著，長年空自勞。", "剝衣聊贖命，覆體不生毛。", "念欲全家去，乾坤何處逃。"]'),
('bcf9540e-9782-41a2-a68d-e3aea6fd657e','自歸耕篆畦見村婦有摘茶車水賣魚汲水行饁寄衣舂米種麥泣布賣菜者作十婦詞  其一○','舒岳祥','宋','宋诗','song-poetry','','[]','賣菜深村婦，休嗟所獲微。',48,'全唐诗/poet.song.227000.json','["賣菜深村婦，休嗟所獲微。", "蕪菁勝乳滑，萊菔似羔肥。", "橐裏腰錢去，街頭買肉歸。", "種蔬勝種稻，得米不憂饑。"]'),
('ef71525d-77c9-4331-898a-bfab19efb717','蝶軒讀易幾','舒岳祥','宋','宋诗','song-poetry','','[]','負薪收芋栗，捫蝨曝荆扉。',48,'全唐诗/poet.song.227000.json','["負薪收芋栗，捫蝨曝荆扉。", "落日烏行亂，清霜杏葉飛。", "歲窮終有復，人老自知非。", "兀兀窗西夜，吾方理易幾。"]'),
('49d7587c-a9ab-4a2b-97fb-ca5fe274dd90','和正仲君子泉','舒岳祥','宋','宋诗','song-poetry','','[]','脈來層嶂遠，影到片天清。',48,'全唐诗/poet.song.227000.json','["脈來層嶂遠，影到片天清。", "洗硯雲根起，歸瓢乳味盈。", "岩花蒙潤澤，水草見分明。", "已遂投簪志，何須起濯纓。"]'),
('7e3e5614-c3cf-46f2-b1f9-0311a0bc93d0','二老亭','舒岳祥','宋','宋诗','song-poetry','','[]','人與松俱老，因名二老亭。',48,'全唐诗/poet.song.227000.json','["人與松俱老，因名二老亭。", "只慚吾髮白，不及爾髯青。", "佚史應同傳，幽圖總寫形。", "把杯長與對，我醉任渠醒。"]'),
('da7a78d9-6aac-4aa3-bf4a-7a83e7430d02','喜山甫相過  其一','舒岳祥','宋','宋诗','song-poetry','','[]','閬風有詩派，一派落山房。',48,'全唐诗/poet.song.227000.json','["閬風有詩派，一派落山房。", "新思如春柳，別來應更長。", "相逢無可說，不見自難忘。", "此是空圓意，雨餘荷葉香。"]'),
('e977aeb8-5950-4f31-a538-71c4cb73a640','喜山甫相過  其二','舒岳祥','宋','宋诗','song-poetry','','[]','夢回春草遠，病起故人來。',48,'全唐诗/poet.song.227000.json','["夢回春草遠，病起故人來。", "耿耿孤燈話，沈沈細雨杯。", "千愁雙鳥過，一笑百花開。", "世事渺烟水，相携卧綠苔。"]'),
('dc65ea18-4cfd-4f03-9a4d-abb07fda22b3','食鹿肉謝正仲見餽','舒岳祥','宋','宋诗','song-poetry','','[]','山寺曾聞叫，悲哉失侶音。',48,'全唐诗/poet.song.227000.json','["山寺曾聞叫，悲哉失侶音。", "能鳴終召禍，善走竟成禽。", "設罟須新雨，尋蹤戀舊林。", "衰年資血味，生殺亦何心。"]'),
('895d0680-e261-47ed-8b31-e6b9e354e1ef','踏莎偶成三首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','坐避窗邊瀑，行便石上莎。',48,'全唐诗/poet.song.227000.json','["坐避窗邊瀑，行便石上莎。", "清池寫癯貌，空谷應悲歌。", "暮色東西合，蟲聲寤寐多。", "離愁誰與洗，舉斗酌明河。"]'),
('9fad0895-d77d-4ccb-b61e-52b106a35ef7','踏莎偶成三首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','兩山天一路，孤石水分流。',48,'全唐诗/poet.song.227000.json','["兩山天一路，孤石水分流。", "多難身衰日，新凉病有瘳。", "侯封竹萬箇，奴課橘千頭。", "生理能如此，真堪隠去休。"]'),
('332d04b4-5884-4154-9029-b0b64753e3a7','踏莎偶成三首  其三','舒岳祥','宋','宋诗','song-poetry','','[]','玉宇浮叢雁，黄槐带化蟬。',48,'全唐诗/poet.song.227000.json','["玉宇浮叢雁，黄槐带化蟬。", "青山一長嘯，白日半欹眠。", "機斷蟲虛織，囊空蘚疊錢。", "去年真可怕，戎馬暗山川。"]'),
('1fe025e9-1fbb-4419-966a-c814494ef564','七夕','舒岳祥','宋','宋诗','song-poetry','','[]','河似琉璃底，水行空影中。',48,'全唐诗/poet.song.227000.json','["河似琉璃底，水行空影中。", "槎浮應恍惚，星會恐朦朧。", "七月初七夜，一年須一逢。", "經躔那有此，吾欲問天公。"]'),
('d80ffa4a-f8b6-4af0-b755-68e6607e6d71','聞雞早起','舒岳祥','宋','宋诗','song-poetry','','[]','鐘扣星辰動，鷄號天地開。',48,'全唐诗/poet.song.227000.json','["鐘扣星辰動，鷄號天地開。", "夜來新過雨，行處旋生苔。", "白日一窗轉，飛霜兩鬢摧。", "勞生何所戀，只憶兩三杯。"]'),
('0c14aa31-3e00-422b-8495-44fe5acab817','十月初五日夜聞雞','舒岳祥','宋','宋诗','song-poetry','','[]','荒郊寒雁起，深夜早雞鳴。',48,'全唐诗/poet.song.227000.json','["荒郊寒雁起，深夜早雞鳴。", "木枕違安寢，繩床遣不平。", "風霜雙鬢晚，歲月寸心驚。", "牛具孤忠在，鷗波萬事輕。"]'),
('ab156494-6d42-4675-9bbf-d87ada80a75b','登小山谷','舒岳祥','宋','宋诗','song-poetry','','[]','亭榭隨人事，江山換劫灰。',48,'全唐诗/poet.song.227000.json','["亭榭隨人事，江山換劫灰。", "鄒裾前日盛，謝屐幾時來。", "紅樹欹城坂，黄花上石臺。", "欲尋觀聚賦，誰與剗蒿萊。"]'),
('62c96293-36f7-45f5-9ce9-f0e95bebe4ed','茅屋','舒岳祥','宋','宋诗','song-poetry','','[]','茅屋不稱意，清泠照此心。',48,'全唐诗/poet.song.227000.json','["茅屋不稱意，清泠照此心。", "白鷗波萬頃，黄鳥樹千岑。", "薝蔔炎天雪，蒲萄午日陰。", "舊來須此物，隘巷若爲尋。"]'),
('717d13fb-bfca-4372-abf0-bce7675b0eb8','紀事','舒岳祥','宋','宋诗','song-poetry','','[]','盜賊自反覆，干戈無是非。',48,'全唐诗/poet.song.227000.json','["盜賊自反覆，干戈無是非。", "上謀先劫掠，善勝昧攻圍。", "禮樂成烏有，詩書入翠微。", "無銀堪易米，甘采首陽薇。"]'),
('cc1f4ebe-8af4-4638-afca-2614ce0e8cdf','詠海棠','舒岳祥','宋','宋诗','song-poetry','','[]','一年春瀲灧，二月錦闌干。',48,'全唐诗/poet.song.227000.json','["一年春瀲灧，二月錦闌干。", "綠嫩難扶醉，紅輕最覺寒。", "欲知花有恨，來向雨中看。", "泥飲須通曉，千枝放燭殘。"]'),
('aa55c25a-ea97-4166-bbd2-705c9add1c24','自用韻再賦海棠','舒岳祥','宋','宋诗','song-poetry','','[]','含羞滄海畔，移種蜀江干。',48,'全唐诗/poet.song.227000.json','["含羞滄海畔，移種蜀江干。", "對此花枝重，不應詩語寒。", "半開須與醉，足睡更來看。", "說與花神道，當筵莫放殘。"]'),
('b366b94e-b4e3-452b-a3a1-dc9054c288ca','樵童自故園來獻海棠因賦二章  其一','舒岳祥','宋','宋诗','song-poetry','','[]','深蔓迷歸路，荒蹊未有家。',48,'全唐诗/poet.song.227000.json','["深蔓迷歸路，荒蹊未有家。", "誰知寒雨裏，也作小春花。", "菌紫松間茁，菘黄澗底芽。", "道人新破戒，窗外種紅茶。"]'),
('2fc53c23-abb7-4b68-87a5-444187c751ea','樵童自故園來獻海棠因賦二章  其二','舒岳祥','宋','宋诗','song-poetry','','[]','只道嬌春日，誰知戰朔風。',48,'全唐诗/poet.song.227000.json','["只道嬌春日，誰知戰朔風。", "輕霜去人遠，愛景入枝紅。", "依舊風情在，難將艷冶同。", "年年摇落後，來惱白頭翁。"]'),
('6a0b870c-9c50-41c1-9123-abab8d229078','山齋排悶','舒岳祥','宋','宋诗','song-poetry','','[]','耳聾便穩睡，眼暗總迷雲。',48,'全唐诗/poet.song.227000.json','["耳聾便穩睡，眼暗總迷雲。", "樹濕直如沃，花香不待焚。", "燕歸知舊主，蜂坌有新君。", "莫怪今非昔，從他聚必分。"]'),
('2a4dbee1-aae7-4bba-b73f-5096a71fcdbf','三月六日黄霧四塞涉三日不散木葉屋瓦積塵皆泥粉因記所見','舒岳祥','宋','宋诗','song-poetry','','[]','故國烏頭白，太空雞子黄。',48,'全唐诗/poet.song.227000.json','["故國烏頭白，太空雞子黄。", "蒲茸千頃麥，筠粉萬株桑。", "錯莫昏花眼，朦朧塵土腸。", "天河如可挽，洗出太陽光。"]'),
('455fca3d-8984-4733-b487-24e56569ac49','書事','舒岳祥','宋','宋诗','song-poetry','','[]','倚徙白頭杖，哀傷赤子兵。',48,'全唐诗/poet.song.227000.json','["倚徙白頭杖，哀傷赤子兵。", "斜封今不用，直指近方行。", "商鞅何妨徇，桑羊儘可烹。", "擊蒙須用此，尺箠惜刑輕。"]'),
('a8b64489-4946-41ae-be8f-534545f324bb','即事','舒岳祥','宋','宋诗','song-poetry','','[]','冬旱井泉竭，霜清天宇空。',48,'全唐诗/poet.song.227000.json','["冬旱井泉竭，霜清天宇空。", "驚心嚴戍馬，極目覽征鴻。", "弓手徵中產，船官及老農。", "可憐時節在，吾道自終窮。"]'),
('98d27931-d992-4db4-ae55-103550c5f6cc','物化','舒岳祥','宋','宋诗','song-poetry','','[]','擾擾孰分形，紛紛誰與明。',48,'全唐诗/poet.song.227000.json','["擾擾孰分形，紛紛誰與明。", "螻蛄擘地走，蚯蚓上階鳴。", "隨事皆天道，因人見物情。", "蟬吟兼蝶舞，風韻喜輕清。"]'),
('5d0b282e-e934-4f36-9e5f-04969c33eb4f','初食栗','舒岳祥','宋','宋诗','song-poetry','','[]','新凉喜見栗，物色近重陽。',48,'全唐诗/poet.song.227000.json','["新凉喜見栗，物色近重陽。", "兔子成毫紫，鵝兒脫殻黄。", "寒宵蒸食暖，饑曉嚼來香。", "風味山家好，蹲鴟得共嘗。"]'),
('1c430314-4b7b-4b6c-84ca-5ea2915fd8cb','秋晚隨意行澗上值老農問勞去年避亂時事  其一','舒岳祥','宋','宋诗','song-poetry','','[]','書在心猶在，時艱變易衰。',48,'全唐诗/poet.song.227000.json','["書在心猶在，時艱變易衰。", "白雲山半寺，紅葉水西祠。", "農老言多善，烏馴噪總慈。", "誰于千載後，見我苦吟時。"]'),
('9118da7e-89ef-4a04-80ca-15b31283d38f','秋晚隨意行澗上值老農問勞去年避亂時事  其二','舒岳祥','宋','宋诗','song-poetry','','[]','輞川疎舊業，復望草堂歸。',48,'全唐诗/poet.song.227000.json','["輞川疎舊業，復望草堂歸。", "落葉無人徑，殘陽向水扉。", "井螢吹不滅，塹烏暗還飛。", "豺虎方當道，何時賦式微。"]'),
('beb2ba86-7347-4cdc-ba34-8bbbb6d9bfc7','初八夜遭綠林之禍因紀其事','舒岳祥','宋','宋诗','song-poetry','','[]','夫子賦歸與，田園欲把鉏。',48,'全唐诗/poet.song.227000.json','["夫子賦歸與，田園欲把鉏。", "春風吹故國，流水遶通衢。", "螮蝀吞滄海，蟾蜍食太虛。", "一燈深夜酒，呼子了殘書。"]'),
('7753c0c7-10c4-472a-be6c-4a3d97c68555','遊天王寺','舒岳祥','宋','宋诗','song-poetry','','[]','客子倦行役，閒尋古剎林。',48,'全唐诗/poet.song.227000.json','["客子倦行役，閒尋古剎林。", "雙巖來勢盡，匯水去聲沈。", "經社千人會，然燈七佛深。", "松行喧萬籟，僧定不知音。"]'),
('cab99b1c-5f6a-446c-a3f2-8328dbccb75d','寄子堂','舒岳祥','宋','宋诗','song-poetry','','[]','知君不寂寞，禪悅只空房。',48,'全唐诗/poet.song.227000.json','["知君不寂寞，禪悅只空房。", "書卷依經藏，吟聲繞寺廊。", "早霜貍面白，新酒菊花黄。", "共此山家景，西峯隔夕陽。"]'),
('e9b9fd66-4c68-4bc7-a99c-928888ab8ed4','正仲思歸作篆畦今夜月十詩非篆畦月乃雁蒼月蓋杜子美鄜州月之意也予作十章乃篆畦月也  其一','舒岳祥','宋','宋诗','song-poetry','','[]','篆畦今夜月，先暝啟黄昏。',48,'全唐诗/poet.song.227000.json','["篆畦今夜月，先暝啟黄昏。", "狐叫青峯逕，僧歸白石源。", "分燈三戶市，打鼓七郎村。", "莫管啼烏繞，吾今已斷魂。"]'),
('1446e159-13ea-46ea-95e5-aee82b139640','正仲思歸作篆畦今夜月十詩非篆畦月乃雁蒼月蓋杜子美鄜州月之意也予作十章乃篆畦月也  其二','舒岳祥','宋','宋诗','song-poetry','','[]','篆畦今夜月，湧海出初更。',48,'全唐诗/poet.song.227000.json','["篆畦今夜月，湧海出初更。", "溪寺鳴鐘罷，山城禁火明。", "梅光初點滴，鶴睡自凄清。", "還念故人遠，燈花結未成。"]'),
('5d3fe9bd-0f40-4de4-bde3-e214dec9be80','正仲思歸作篆畦今夜月十詩非篆畦月乃雁蒼月蓋杜子美鄜州月之意也予作十章乃篆畦月也  其三','舒岳祥','宋','宋诗','song-poetry','','[]','篆畦今夜月，出嶠二更初。',48,'全唐诗/poet.song.227000.json','["篆畦今夜月，出嶠二更初。", "蓐食催鳴碓，蒙頭靜著書。", "清霜聞吠犬，細火有歸漁。", "一盞解寒酒，風爐煮雪蔬。"]'),
('b7a41865-0079-4e23-b4c8-32289b956436','正仲思歸作篆畦今夜月十詩非篆畦月乃雁蒼月蓋杜子美鄜州月之意也予作十章乃篆畦月也  其四','舒岳祥','宋','宋诗','song-poetry','','[]','篆畦今夜月，有待到三更。',48,'全唐诗/poet.song.227000.json','["篆畦今夜月，有待到三更。", "水鳥隔烟叫，山樵踏雪行。", "詩成嫌燭短，酒渴愛菹清。", "此際誰爲伴，梅邊送影橫。"]'),
('04166826-0ef5-4dff-a4b9-ac8ada193530','正仲思歸作篆畦今夜月十詩非篆畦月乃雁蒼月蓋杜子美鄜州月之意也予作十章乃篆畦月也  其五','舒岳祥','宋','宋诗','song-poetry','','[]','篆畦今夜月，絕妙四更殘。',48,'全唐诗/poet.song.227000.json','["篆畦今夜月，絕妙四更殘。", "欹枕清無寐，推窗獨起看。", "流鴻曳稀宿，躍鯉散微瀾。", "頗記倦遊日，孤舟宿雪灘。"]'),
('88037222-e851-40b3-ae29-b8e9ed7c4631','正仲思歸作篆畦今夜月十詩非篆畦月乃雁蒼月蓋杜子美鄜州月之意也予作十章乃篆畦月也  其六','舒岳祥','宋','宋诗','song-poetry','','[]','篆畦今夜月，初出五更頭。',48,'全唐诗/poet.song.227000.json','["篆畦今夜月，初出五更頭。", "清旭輝相映，餘光淡未收。", "烟消江樹出，霞弄市嵐浮。", "憶昔趨丹陛，雞人唱曉籌。"]'),
('3b38d57b-6afb-4307-8dfa-5ef5db406bd2','正仲思歸作篆畦今夜月十詩非篆畦月乃雁蒼月蓋杜子美鄜州月之意也予作十章乃篆畦月也  其七','舒岳祥','宋','宋诗','song-poetry','','[]','篆畦今夜月，尊酒共論文。',48,'全唐诗/poet.song.227000.json','["篆畦今夜月，尊酒共論文。", "凍茁沙中笋，冰芽澗底芹。", "人生半歌哭，世事異傳聞。", "風憲分流品，儒生免出軍。"]'),
('c92c78e6-2db7-4e8f-b053-9e25c383166a','正仲思歸作篆畦今夜月十詩非篆畦月乃雁蒼月蓋杜子美鄜州月之意也予作十章乃篆畦月也  其八','舒岳祥','宋','宋诗','song-poetry','','[]','篆畦今夜月，政自使人憐。',48,'全唐诗/poet.song.227000.json','["篆畦今夜月，政自使人憐。", "久廢登山屐，愁催下瀨船。", "衰年免黄帽，舊習守青氈。", "東浙承平地，如今是近邊。"]'),
('4c9c3408-7882-46f5-a92b-6d2bfbb84c69','正仲思歸作篆畦今夜月十詩非篆畦月乃雁蒼月蓋杜子美鄜州月之意也予作十章乃篆畦月也  其九','舒岳祥','宋','宋诗','song-poetry','','[]','篆畦今夜月，特地向人明。',48,'全唐诗/poet.song.227000.json','["篆畦今夜月，特地向人明。", "海驛催傳箭，荒雞誤報更。", "平生大敵勇，末暮小詩行。", "老矣今安用，深盃送此生。"]'),
('7c250d66-7eb1-4eae-867e-cc2a1f1b4362','正仲思歸作篆畦今夜月十詩非篆畦月乃雁蒼月蓋杜子美鄜州月之意也予作十章乃篆畦月也  其一○','舒岳祥','宋','宋诗','song-poetry','','[]','篆畦今夜月，故意照人衰。',48,'全唐诗/poet.song.227000.json','["篆畦今夜月，故意照人衰。", "一夢十年過，千愁萬里來。", "只今安粵徼，何日悔輪臺。", "吟罷四百字，更傾三五杯。"]'),
('ae7f67c0-3be1-4617-ab92-b08e30a77ceb','寄石泉策禪師','舒岳祥','宋','宋诗','song-poetry','','[]','不來三十載，僧與寺俱非。',48,'全唐诗/poet.song.227000.json','["不來三十載，僧與寺俱非。", "棕屨延蒼蘚，蒲團坐翠微。", "溪傳松頂相，風助竹談機。", "侍者能栽菊，秋深重扣扉。"]'),
('2bb58c5b-598a-46ac-acef-c4392b08fb7b','少師丞相國公西磵先生挽歌二首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','宰輔平生望，儒酸貴日同。',48,'全唐诗/poet.song.227000.json','["宰輔平生望，儒酸貴日同。", "諸賢親盛德，末俗仰高風。", "道喪悲歌鳳，時乖歎卧龍。", "經綸茲日泯，憂愛與身終。"]'),
('09373a3f-0333-4f36-8820-d2cd83ed5004','少師丞相國公西磵先生挽歌二首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','咸淳無正史，德祐少完人。',48,'全唐诗/poet.song.227000.json','["咸淳無正史，德祐少完人。", "他日修公傳，終身作宋臣。", "淵明還死晉，商皓本逃秦。", "壯士元無淚，西風自濕巾。"]'),
('b80b9061-0801-4c70-a8a2-eb98a823adff','兼靜黄壇楊君書室也取錢起柴門兼竹靜之句名之邑里吟人題詠殆遍矣予爲友作反騷不知者便謂子雲與屈子異意非也','舒岳祥','宋','宋诗','song-poetry','','[]','本自柴門靜，誰令種竹喧。',48,'全唐诗/poet.song.227000.json','["本自柴門靜，誰令種竹喧。", "月來將畫寫，風過引書翻。", "默坐雨偏響，閑眠雪易繁。", "動中還有靜，此意互爲根。"]'),
('2458cf1f-f4dd-4b70-b751-00c13958554a','余名宴居之室曰一枝巢賦詩以自遣','舒岳祥','宋','宋诗','song-poetry','','[]','世事隨流水，年華逐北風。',48,'全唐诗/poet.song.227000.json','["世事隨流水，年華逐北風。", "雁橫殘笛外，人老夕陽中。", "聽雪三間永，催梅百榼空。", "沿溪漉明月，只在最高峯。"]'),
('7e5e3d0d-2054-4586-8785-38ca187a4be3','喜帥初歸剡','舒岳祥','宋','宋诗','song-poetry','','[]','吳客多流越，君尋古剡歸。',48,'全唐诗/poet.song.227000.json','["吳客多流越，君尋古剡歸。", "民貧官箠急，歲歉米船稀。", "嶺鹿三丫入，溪鱸一尺肥。", "榆林知可隠，安得翅能飛。"]'),
('2ef61971-63f4-420f-b79c-738a9a23401c','和亦翁韻','舒岳祥','宋','宋诗','song-poetry','','[]','斜日照疲蹇，茅茨葺未成。',48,'全唐诗/poet.song.227000.json','["斜日照疲蹇，茅茨葺未成。", "覘梅天氣好，卧雪夢魂清。", "葉脫懸星大，谿長去火明。", "詩翁如退將，誰守五言城。"]'),
('c592e6f7-929c-4386-9a09-f78060a0ced1','小窗一首寄帥初','舒岳祥','宋','宋诗','song-poetry','','[]','愛酒不嗜飲，行藏一小窗。',48,'全唐诗/poet.song.227000.json','["愛酒不嗜飲，行藏一小窗。", "斜陽屐樵磴，細雨笠漁矼。", "紅樹橋邊獨，青禽石上雙。", "永懷草廬葛，來訪鹿門龐。"]'),
('53c97785-e7fa-415e-a6cf-87af23e9fa3e','爲胡後山提幹詠南麓古松','舒岳祥','宋','宋诗','song-poetry','','[]','志在千尋上，根蟠十里間。',48,'全唐诗/poet.song.227000.json','["志在千尋上，根蟠十里間。", "不除當路樹，爲作對門山。", "田近龍常見，枝低鶻可攀。", "向來戎馬入，世故涉艱難。"]'),
('915b53fc-6247-446d-88de-d428cf61618f','中夜對月有省','舒岳祥','宋','宋诗','song-poetry','','[]','風開半村雨，月吐四更潮。',48,'全唐诗/poet.song.227000.json','["風開半村雨，月吐四更潮。", "靜處常參省，從來本寂寥。", "天機雙鶴唳，霜信一鴻飄。", "短髮梳還癢，寒釭凝不摇。"]'),
('144b1fee-b028-4060-910e-37dca90df112','十月十三日嫩晴薄寒山房新構書閣去年此日北兵入是夜自中心墺徙獨山','舒岳祥','宋','宋诗','song-poetry','','[]','霧重月無色，夜來寒有情。',48,'全唐诗/poet.song.227000.json','["霧重月無色，夜來寒有情。", "牆根餘宿莽，木末弄初晴。", "去歲那知有，新冬得此生。", "擁爐談往事，鸜鵒報三更。"]'),
('06d55280-733f-43e7-89ea-0e8306b8e8f8','早凉出邑','舒岳祥','宋','宋诗','song-poetry','','[]','暑濁難爲酒，秋清易得詩。',48,'全唐诗/poet.song.227000.json','["暑濁難爲酒，秋清易得詩。", "出門殘月在，騎馬曉風吹。", "山厂藤蘿構，荒園枳棘籬。", "新條聞快活，歸路不妨遲。"]'),
('4c0e851f-f44a-4a03-8767-666e0aa940ae','海眺','舒岳祥','宋','宋诗','song-poetry','','[]','自嫌林谷暗，欲作海天遊。',48,'全唐诗/poet.song.227000.json','["自嫌林谷暗，欲作海天遊。", "蘆葦人家曉，蒹葭國士秋。", "樹根生石上，山影占江流。", "載酒船頭去，風波幾瓦甌。"]'),
('60c46094-26f1-4704-8dd1-cd6dd3604b4d','送山甫還峽中','舒岳祥','宋','宋诗','song-poetry','','[]','到處圖松樹，何曾忘却山。',48,'全唐诗/poet.song.227000.json','["到處圖松樹，何曾忘却山。", "相携溪路斷，愁踏夕陽還。", "田狖吟桑空，山雞飲石間。", "所憂無可醉，天上酒星閑。"]'),
('96cafaa7-7c1f-4313-a3fd-7aa184eb4135','自次前韻酬馬奧諸丈見和  其一','舒岳祥','宋','宋诗','song-poetry','','[]','得肉鳶歸樹，無魚鶴下田。',48,'全唐诗/poet.song.227000.json','["得肉鳶歸樹，無魚鶴下田。", "此中藏世界，他處少人烟。", "可怪衣偏裻，何妨屐下穿。", "亂離多少事，史筆若爲傳。"]'),
('0a6fac91-792d-4462-b3be-013246b887d2','自次前韻酬馬奧諸丈見和  其二','舒岳祥','宋','宋诗','song-poetry','','[]','久別形容改，相逢涕淚收。',48,'全唐诗/poet.song.227000.json','["久別形容改，相逢涕淚收。", "少陵歌裏哭，元亮飲中憂。", "巖瀑和冰下，溪楂避石流。", "故園春早動，歸計莫悠悠。"]'),
('027cd1b7-8bdc-4c8c-9abf-4e55d6efabd3','巖雲','舒岳祥','宋','宋诗','song-poetry','','[]','巖雲黏壁白，瀑雨點簾斑。',48,'全唐诗/poet.song.227000.json','["巖雲黏壁白，瀑雨點簾斑。", "詩句鴉初曉，鄉愁日半山。", "故人來沼上，好鳥韻窗間。", "樹近夜先到，村空春未還。"]'),
('4312ef05-4187-4ab5-b8a0-9e70c8177cc4','悵望雁山雲','舒岳祥','宋','宋诗','song-poetry','','[]','悵望雁山雲，柴門一欠伸。',48,'全唐诗/poet.song.227000.json','["悵望雁山雲，柴門一欠伸。", "笭箵潭底影，襏襫雨中身。", "紅煮溟波日，青回燒地春。", "青城新祼奠，餘景付詩人。"]'),
('1b1bd386-c161-4429-9595-f69cabf55c9c','庚辰元旦試筆','舒岳祥','宋','宋诗','song-poetry','','[]','數我初生歲，今爲第二年。',48,'全唐诗/poet.song.227000.json','["數我初生歲，今爲第二年。", "光陰六十過，行輩幾人全。", "試把新詩寫，閑將好夢圓。", "兒孫扶出拜，蘇酒讓渠先。"]'),
('42a29bb1-e9fa-4af9-8668-d254228071d1','夜坐','舒岳祥','宋','宋诗','song-poetry','','[]','黄昏風雨後，清夜聖賢心。',48,'全唐诗/poet.song.227000.json','["黄昏風雨後，清夜聖賢心。", "松月生池底，窗燈間竹林。", "嚥津芝朮味，洗耳石泉音。", "早秫傳消息，清香慰暑襟。"]'),
('5e21f7b5-8cdb-46ee-95a1-e704a45fdb9c','矮樹','舒岳祥','宋','宋诗','song-poetry','','[]','千年矮桃樹，從昔不教長。',48,'全唐诗/poet.song.227000.json','["千年矮桃樹，從昔不教長。", "靜入仙人室，低親處女粧。", "苔枝深漬雨，秋實冷含霜。", "蜂蝶誰知顧，春風四畔香。"]'),
('3bf0e5de-f0cf-450c-bdb3-161baca26c1c','楊柳清明近二首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','楊柳清明近，棠梨烟雨愁。',48,'全唐诗/poet.song.227000.json','["楊柳清明近，棠梨烟雨愁。", "紅來千樹色，白盡幾人頭。", "歌哭同途去，繁華轉眼收。", "銅駝千古恨，只爲一尊休。"]'),
('c8ed76b4-1987-4926-8b5b-62030f522414','楊柳清明近二首  其二','舒岳祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','楊柳清明近，梨花氣候寒。',48,'全唐诗/poet.song.227000.json','["楊柳清明近，梨花氣候寒。", "誰家爭蹴踘，客子淚闌干。", "茇舍鳳棲小，芹泥燕子寬。", "西湖吾舊夢，見說不堪看。"]'),
('75b3171a-cbd7-4fc1-9dff-dd6bc944ae80','酬張常吉','舒岳祥','宋','宋诗','song-poetry','','[]','憑誰詩寄我，溪水接流瓢。',48,'全唐诗/poet.song.227000.json','["憑誰詩寄我，溪水接流瓢。", "島瘦神空泣，韓豪骨未銷。", "閑眠重落葉，久坐到歸樵。", "予亦逃名者，何當共寂寥。"]'),
('33894171-419b-483d-99bc-552e5ab63bc8','次韻酬正仲見和并貽用之','舒岳祥','宋','宋诗','song-poetry','','[]','世事多眉皺，綀衣覺鼻酸。',48,'全唐诗/poet.song.227000.json','["世事多眉皺，綀衣覺鼻酸。", "老懷呼子寫，瘦影引孫看。", "爾健心無事，吾貧骨带寒。", "一樽江上別，露氣夜來漙。"]'),
('d3cc8e86-990c-431c-bf0e-c88f753b1795','次韻酬用之見和','舒岳祥','宋','宋诗','song-poetry','','[]','秋晚如春早，晨昏海氣濛。',48,'全唐诗/poet.song.227000.json','["秋晚如春早，晨昏海氣濛。", "霜嗥呼偶鹿，雨啞破昏鐘。", "知命休行險，吟詩不怨窮。", "吾儕天所賜，出入戴青松。"]'),
('3ccb1240-ae21-4246-8523-8488fb044f23','十二月十三日曬藥有感','舒岳祥','宋','宋诗','song-poetry','','[]','賣藥不二價，買書甘一貧。',48,'全唐诗/poet.song.227000.json','["賣藥不二價，買書甘一貧。", "誰於无妄世，完此不貲身。", "酒熟狂連月，花香走四隣。", "因思少年事，默默自沾巾。"]'),
('8d42a577-a1f0-4594-b773-0ee82c2b855b','詠豆蔻花  其一','舒岳祥','宋','宋诗','song-poetry','','[]','春晚愁偏重，垂頭向下生。',48,'全唐诗/poet.song.227000.json','["春晚愁偏重，垂頭向下生。", "牡丹憐與葉，蕙草愛分莖。", "懸袋雙魚意，含胎少婦情。", "幽姿如冷淡，那敢擬傾城。"]'),
('1c06c687-6fa4-4d86-bea8-aa44b2ff22e1','詠豆蔻花  其二','舒岳祥','宋','宋诗','song-poetry','','[]','舌吐梅仁顆，心含豆角花。',48,'全唐诗/poet.song.227000.json','["舌吐梅仁顆，心含豆角花。", "折來無處著，留取愛名嘉。", "脆紫深愁雨，輕紅落軟沙。", "虞兮成恨草，姊娣共成家。"]'),
('11c80156-5fb7-4a5c-854a-9fac67adb67c','水閣新成與潘胡二子小飲','舒岳祥','宋','宋诗','song-poetry','','[]','小有龜藏意，橫陳燕息初。',48,'全唐诗/poet.song.227000.json','["小有龜藏意，橫陳燕息初。", "一間規畫舫，數板束方渠。", "隠几時聽雨，開窗即釣魚。", "天寒須共飲，吾已久捐書。"]'),
('0f411c94-a09b-4318-8de4-8e8bd481e670','次韻答潘宰見和送正仲多字韻詩','舒岳祥','宋','宋诗','song-poetry','','[]','彊健近八十，如君誠未多。',48,'全唐诗/poet.song.227000.json','["彊健近八十，如君誠未多。", "夢中思謁帝，醉後縱懸河。", "撫事遽如許，流年奈若何。", "相期成二老，舉斗酌纖阿。"]'),
('425d9b98-dfb4-4546-b48a-a9601f920e2c','次韻答達善季辯','舒岳祥','宋','宋诗','song-poetry','','[]','眼暗書多誤，牙摇飯著沙。',48,'全唐诗/poet.song.227000.json','["眼暗書多誤，牙摇飯著沙。", "山林消幾屐，天地總浮家。", "故國帛書鴈，荒園鼓吹蛙。", "經年無驛使，何處問京華。"]'),
('30279b99-b351-4fcd-b518-060dc8920297','次韻答陳用之王奕世袁明復三子和篇','舒岳祥','宋','宋诗','song-poetry','','[]','藥留殘焙火，枕避近溪風。',48,'全唐诗/poet.song.227000.json','["藥留殘焙火，枕避近溪風。", "意澹琴三疊，人和酒一中。", "自遭兵禍後，已覺世緣空。", "安得飄然去，茅廬海上峯。"]'),
('aed55cfc-f1f3-4c1f-822c-348fae29d37f','避地李山','舒岳祥','宋','宋诗','song-poetry','','[]','山居門早閉，雪後樹重青。',48,'全唐诗/poet.song.227000.json','["山居門早閉，雪後樹重青。", "不爲艱危迫，誰能險阻登。", "寒機與舂應，村誦隔溪聽。", "絕頂觀滄海，海平峯上層。"]'),
('8e5e8da2-f080-4d72-a50c-ddf047682706','蹔山','舒岳祥','宋','宋诗','song-poetry','','[]','薄暮悲歡意，無家去住間。',48,'全唐诗/poet.song.227000.json','["薄暮悲歡意，無家去住間。", "三間臨水屋，半樹夕陽山。", "石雨疎成密，沙潮去未還。", "數旬成卧病，轉老轉多艱。"]'),
('f882cd11-f581-4c01-9846-b3e85957abd6','將爲鄞江之遊先寄正仲三首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','相思不在遠，道地一來難。',48,'全唐诗/poet.song.227000.json','["相思不在遠，道地一來難。", "殘月中峯見，疎星半夜看。", "江湖青草遠，風雨小窗寒。", "鄞水饒魚米，何由得共餐。"]'),
('cd082da6-44e6-4baf-a866-f44c7c902adc','將爲鄞江之遊先寄正仲三首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','天地悲歌裏，江城戰血餘。',48,'全唐诗/poet.song.227000.json','["天地悲歌裏，江城戰血餘。", "哀湍瀉壞道，斜日照殘書。", "髮禿因慵櫛，園荒亦懶鋤。", "舊來雙紫燕，隨我到茅廬。"]'),
('de144edd-0217-4887-8bd3-e4f06c3565e0','將爲鄞江之遊先寄正仲三首  其三','舒岳祥','宋','宋诗','song-poetry','','[]','水漲苔梳髮，風晴麥漾鬚。',48,'全唐诗/poet.song.227000.json','["水漲苔梳髮，風晴麥漾鬚。", "茶香度深竹，燈影射平蕪。", "歲月江流駛，乾坤客枕孤。", "鄞鄉風物好，蓴菜出湘湖。"]'),
('f1ecc428-f00f-4bba-8551-8e0ae20c61ac','燈花','舒岳祥','宋','宋诗','song-poetry','','[]','火樹知誰種，燈花凝不銷。',48,'全唐诗/poet.song.227000.json','["火樹知誰種，燈花凝不銷。", "何人知此意，有喜在明朝。", "兒愛抄詩卷，童歡進酒瓢。", "紗籠添護惜，莫要隙風摇。"]'),
('ee203e1b-fb4d-441b-8e7b-a6b19f080ff8','留山甫','舒岳祥','宋','宋诗','song-poetry','','[]','新舂知麥味，舊債了鄰賒。',48,'全唐诗/poet.song.227000.json','["新舂知麥味，舊債了鄰賒。", "借榻無鵑處，敲門有竹家。", "韭苗香煮餠，菊腦和烹茶。", "少駐還山屐，烏紗細雨斜。"]'),
('c786814f-2324-4ec2-92f5-a6e8d8ad6397','春曉','舒岳祥','宋','宋诗','song-poetry','','[]','高枕還慵起，晴窗曉日明。',48,'全唐诗/poet.song.227000.json','["高枕還慵起，晴窗曉日明。", "家貧從省事，身老放徐行。", "溪樹藏村暗，山花照市明。", "園林有樂事，桑下見雛成。"]'),
('ce4337b7-9507-42ba-a2ea-af67490904af','靜息','舒岳祥','宋','宋诗','song-poetry','','[]','茅竹荒墟地，菰蒲野水天。',48,'全唐诗/poet.song.227000.json','["茅竹荒墟地，菰蒲野水天。", "故園長莽莽，歸興自翩翩。", "文字留身後，瓶罌滿眼前。", "海棠知我意，故作小春妍。"]'),
('871a6e86-3c18-44bb-8785-11b5fb12474a','冬日過良坑岡東望滄海隠隠見漁村有感時避地者多浮海云','舒岳祥','宋','宋诗','song-poetry','','[]','平陸人煙險，漁舟家口肥。',48,'全唐诗/poet.song.227000.json','["平陸人煙險，漁舟家口肥。", "青天圍篛笠，白雨澣蓑衣。", "靜釣鷗分石，寒歸雪滿扉。", "磻溪有恨事，嚴瀨本忘機。"]'),
('8b82ec4a-87bd-4e85-bffb-d9cdc999e91d','篆畦春日有懷正仲','舒岳祥','宋','宋诗','song-poetry','','[]','別來成隔歲，即是久相疎。',48,'全唐诗/poet.song.227000.json','["別來成隔歲，即是久相疎。", "詠物追唐律，名亭學史書。", "荑柔春霰後，花韻午晴初。", "閒日有閒課，人生無逸居。"]'),
('a015a40b-6756-4306-8044-2e82a899e166','曉起觀梅','舒岳祥','宋','宋诗','song-poetry','','[]','玉氣占虹貫，珠光照夜闌。',48,'全唐诗/poet.song.227000.json','["玉氣占虹貫，珠光照夜闌。", "凄凉兼水浄，的皪與星殘。", "欲折先呵手，誰來獨倚欄。", "白螺𣂏曉露，起向月中看。"]'),
('ae07ce93-8fd3-43b6-b211-7153f986f7c1','趨農','舒岳祥','宋','宋诗','song-poetry','','[]','種浸清明後，芽烹穀雨前。',48,'全唐诗/poet.song.227000.json','["種浸清明後，芽烹穀雨前。", "未能饑守死，何不力耕田。", "溪草鳬毛滑，山花雉頰鮮。", "倦行聊少憇，茅屋带晴煙。"]'),
('3e8a8786-1656-4617-a95c-52f756d71129','次和花字韻酬正仲實父少白三友','舒岳祥','宋','宋诗','song-poetry','','[]','不讀口生棘，多愁眼易花。',48,'全唐诗/poet.song.227000.json','["不讀口生棘，多愁眼易花。", "江湖四閒客，今古幾詩家。", "吟是蠲憂藥，功如解困茶。", "艱難俱已歷，好景夕陽斜。"]'),
('957af823-e53c-454c-9f13-e7d3620fab53','再次韻酬正仲','舒岳祥','宋','宋诗','song-poetry','','[]','好翁須好客，相映柳和花。',48,'全唐诗/poet.song.227000.json','["好翁須好客，相映柳和花。", "自是曹劉匹，非分唐宋家。", "書空因學草，品水爲知茶。", "愛酒欣逢伴，臨風醉墨斜。"]'),
('399a61ba-d06b-4a2e-910b-83af71ec0413','放螢寄正仲','舒岳祥','宋','宋诗','song-poetry','','[]','殘編百讀過，年去放螢飛。',48,'全唐诗/poet.song.227000.json','["殘編百讀過，年去放螢飛。", "好带隨身火，休爭秉燭輝。", "夜凉辭竹庋，風逆返書幃。", "未是明經日，何人拾汝歸。"]'),
('24ea24c2-ad41-45c5-a9ba-8a6a78d89d71','螢','舒岳祥','宋','宋诗','song-poetry','','[]','每向坳塘照，多從曲徑燒。',48,'全唐诗/poet.song.227000.json','["每向坳塘照，多從曲徑燒。", "無煙知有焰，著草不曾焦。", "雜燐因風亂，隨星沒夜遥。", "老來疏簡冊，四散任渠飄。"]'),
('d718e5e9-a06d-4064-9d4e-8835b4e8c213','漁童','舒岳祥','宋','宋诗','song-poetry','','[]','丫角長身者，依然髮懶梳。',48,'全唐诗/poet.song.227000.json','["丫角長身者，依然髮懶梳。", "只將星子餌，釣得尺來魚。", "險阻行來慣，風波舞自如。", "曾因潮岸塌，收得古人書。"]'),
('a7aca3e7-b371-46a2-b2e2-6ec194106942','春日山居好十首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','春日山居好，初春草色回。',48,'全唐诗/poet.song.227000.json','["春日山居好，初春草色回。", "小橋帘映柳，野店燭簪梅。", "箭茁穿沙出，蘭芽带雪開。", "從今排日去，連月覆樽罍。"]'),
('43d8b946-907f-42ac-a9c9-a081f8f8aa78','春日山居好十首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','春日山居好，尤佳是仲春。',48,'全唐诗/poet.song.227000.json','["春日山居好，尤佳是仲春。", "半開花有韻，微醉酒全真。", "堯帝衣裳日，周公禮樂辰。", "枝頭百舌子，播告太諄諄。"]'),
('a22fc5d8-5d01-4ced-bc66-d1f2113dffbc','春日山居好十首  其三','舒岳祥','宋','宋诗','song-poetry','','[]','春日山居好，春深自向歸。',48,'全唐诗/poet.song.227000.json','["春日山居好，春深自向歸。", "且看成茂實，何必戀芳菲。", "樹合明湖隔，蒿長遠徑微。", "風雩吾黨事，試浴振春衣。"]'),
('0fe42f5e-b3b5-422d-adc6-618e761f7eec','春日山居好十首  其四','舒岳祥','宋','宋诗','song-poetry','','[]','春日山居好，春來不問深。',48,'全唐诗/poet.song.227000.json','["春日山居好，春來不問深。", "柳能同燕舞，鶑解代花吟。", "有酒家閑去，無詩客莫尋。", "賣田强免役，何必苦勞心。"]'),
('87939f82-47b7-4dfa-a3e0-c84ebd0b3fbd','春日山居好十首  其五','舒岳祥','宋','宋诗','song-poetry','','[]','春日山居好，閑思二月頭。',48,'全唐诗/poet.song.227000.json','["春日山居好，閑思二月頭。", "麥青農作暇，荑秀女工休。", "布穀遲催種，提壺早勸遊。", "老夫同獵較，陌上暖風柔。"]'),
('6c3b3fec-073c-4c56-8ffe-7e8d57114dfe','春日山居好十首  其六','舒岳祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春日山居好，西湖樂事非。',48,'全唐诗/poet.song.227000.json','["春日山居好，西湖樂事非。", "青黄雖未接，紅紫自交輝。", "酒在何憂死，詩成可療饑。", "典書猶可醉，何必有金揮。"]'),
('6d6d1890-caa4-48f1-8e97-e19a00108094','春日山居好十首  其七','舒岳祥','宋','宋诗','song-poetry','','[]','春日山居好，柴門愛客過。',48,'全唐诗/poet.song.227000.json','["春日山居好，柴門愛客過。", "連朝恣泥飲，隨意有山歌。", "句小從人學，才衰覺氣和。", "情懷依分足，好景不須多。"]'),
('d7844593-13cb-4305-b061-432810df35c4','春日山居好十首  其八','舒岳祥','宋','宋诗','song-poetry','','[]','春日山居好，尋花急占先。',48,'全唐诗/poet.song.227000.json','["春日山居好，尋花急占先。", "騎馿投酒市，領鶴上漁船。", "薄暖還揮扇，輕寒未替綿。", "清和時候正，麗日牡丹天。"]'),
('94132f10-2bfe-40ef-bb3d-ff04bbe733b6','春日山居好十首  其九','舒岳祥','宋','宋诗','song-poetry','','[]','春日山居好，春園賞海棠。',48,'全唐诗/poet.song.227000.json','["春日山居好，春園賞海棠。", "風流思妙麗，老大尚清狂。", "暫拭傷時淚，還逢絕世粧。", "傾銀并注瓦，彼此一時芳。"]'),
('75b38ee2-4819-4531-b11e-000615949ad4','春日山居好十首  其一○','舒岳祥','宋','宋诗','song-poetry','','[]','春日山居好，光風草上浮。',48,'全唐诗/poet.song.227000.json','["春日山居好，光風草上浮。", "溟濛晨靄散，澹蕩夕陽收。", "發軔梅花報，攀轅芍藥留。", "春來亦何好，惟有白添頭。"]'),
('865a7295-7565-4810-9909-412b9a9e84aa','夏日山居好十首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','夏日山居好，清風報斷梅。',48,'全唐诗/poet.song.227000.json','["夏日山居好，清風報斷梅。", "林深蚊却退，山合鳥飛回。", "一霎過雲雨，數聲深水雷。", "遶園尋蠹笋，聊以薦山杯。"]'),
('89f79016-ae33-4f72-b52e-97446444b4d5','夏日山居好十首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','夏日山居好，吟來亦自豪。',48,'全唐诗/poet.song.227000.json','["夏日山居好，吟來亦自豪。", "焚香誦周易，痛飲讀離騷。", "莫諱無三甲，吾今已二毛。", "蕪編三百卷，空費一生勞。"]'),
('3e379ee3-05c1-4f3e-aaf5-f55b2714105c','夏日山居好十首  其三','舒岳祥','宋','宋诗','song-poetry','','[]','夏日山居好，還思童冠時。',48,'全唐诗/poet.song.227000.json','["夏日山居好，還思童冠時。", "汗流修舉業，浴罷間題詩。", "邊事廷紳奏，朝除邸報馳。", "槐花時節近，新說合新知。"]'),
('0c343972-d08c-4624-847d-aa706936c7b3','夏日山居好十首  其四','舒岳祥','宋','宋诗','song-poetry','','[]','夏日山居好，茅簷水餠香。',48,'全唐诗/poet.song.227000.json','["夏日山居好，茅簷水餠香。", "蕉衫身儉潔，紗帽頂清凉。", "潤葉桑藏井，新梢笋過牆。", "莫言炎熱苦，勝處苦寒鄉。"]'),
('33cda62d-50dc-41ff-9a2a-5da43b045918','夏日山居好十首  其五','舒岳祥','宋','宋诗','song-poetry','','[]','夏日山居好，凉風樹下生。',48,'全唐诗/poet.song.227000.json','["夏日山居好，凉風樹下生。", "三茶還可瀹，二韮尚堪烹。", "永日閑言語，平生實講明。", "半空飛赤電，燕坐不須驚。"]'),
('27d0b730-3627-4754-b7e9-9d7fdae40ef8','夏日山居好十首  其六','舒岳祥','宋','宋诗','song-poetry','','[]','夏日山居好，清溪一笛風。',48,'全唐诗/poet.song.227000.json','["夏日山居好，清溪一笛風。", "瘦軀便褐短，寡髮愛梳鬆。", "細雨明歸鷺，斜陽飲遠虹。", "有時吟未穩，飽步自書空。"]'),
('bc752db5-c8fa-44f5-9a8b-579de2d0cc6f','夏日山居好十首  其七','舒岳祥','宋','宋诗','song-poetry','','[]','夏日山居好，鷄鳴桑柘煙。',48,'全唐诗/poet.song.227000.json','["夏日山居好，鷄鳴桑柘煙。", "笋摇知狖過，草偃覺鵝眠。", "休問田園計，聊隨飲食緣。", "經營空自苦，煩惱更誰憐。"]'),
('3c5187e8-6094-4dbb-9dd7-73a40c59665e','夏日山居好十首  其八','舒岳祥','宋','宋诗','song-poetry','','[]','夏日山居好，蟲鳴山更幽。',48,'全唐诗/poet.song.227000.json','["夏日山居好，蟲鳴山更幽。", "青鞋紫藤杖，玉醴綠甆甌。", "飛露吹黄葛，凉風灑白頭。", "已知時雨順，更有虎狼憂。"]'),
('cffe591c-5d32-4642-9c74-42633fa2c5a0','夏日山居好十首  其九','舒岳祥','宋','宋诗','song-poetry','','[]','夏日山居好，日長宜學文。',48,'全唐诗/poet.song.227000.json','["夏日山居好，日長宜學文。", "金門堪避世，𤱶畝不忘君。", "林宿三冬雪，巖藏萬里雲。", "屈伸吾道在，何必雜人羣。"]'),
('cbbb8f6d-969b-40da-9112-232bbae3b89f','夏日山居好十首  其一○','舒岳祥','宋','宋诗','song-poetry','','[]','夏日山居好，藤床面北林。',48,'全唐诗/poet.song.227000.json','["夏日山居好，藤床面北林。", "荷心風百頃，秧底月千尋。", "幽鳥珍毛羽，流泉響磬琴。", "此中多樂事，客至亦能吟。"]'),
('2d6b145f-e478-466a-b933-d3017eedd327','秋日山居好十首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','秋日山居好，新凉讀舊書。',48,'全唐诗/poet.song.227000.json','["秋日山居好，新凉讀舊書。", "黍馨秋社祭，燈燦夜灘漁。", "茄摘收花後，瓜嘗脫蒂初。", "早田三得雨，一飽解憂虞。"]'),
('9c7a997b-4c44-44ca-8898-c1cb64b1e013','秋日山居好十首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','秋日山居好，園丁貢美蔬。',48,'全唐诗/poet.song.227000.json','["秋日山居好，園丁貢美蔬。", "燃萁酥煮豆，拗頸爛蒸壺。", "菰首甜供茹，薑芽嫩漉菹。", "秋來風物美，何必去吾廬。"]'),
('5c3774ee-22a4-4221-b6fb-a67a6c32f640','秋日山居好十首  其三','舒岳祥','宋','宋诗','song-poetry','','[]','秋日山居好，吾居山海間。',48,'全唐诗/poet.song.227000.json','["秋日山居好，吾居山海間。", "意行逢酒住，興盡放歌還。", "稻穫歸流水，林疎縮遠山。", "誰知僧快活，飯飽即身閒。"]'),
('6dc2972d-fc26-45e0-ac97-10c73e094484','秋日山居好十首  其四','舒岳祥','宋','宋诗','song-poetry','','[]','秋日山居好，星河頂上懸。',48,'全唐诗/poet.song.227000.json','["秋日山居好，星河頂上懸。", "聊隨兒女戲，也設果瓜筵。", "欹枕看星渡，開窗抱月眠。", "溪田六十日，接闕到紅鮮。"]'),
('a3f684e9-972c-4f90-aef1-74c9d6becbb5','秋日山居好十首  其五','舒岳祥','宋','宋诗','song-poetry','','[]','秋日山居好，新凉及早興。',48,'全唐诗/poet.song.227000.json','["秋日山居好，新凉及早興。", "玉餐陽塢米，冰嚼下洪菱。", "海錯來蒲港，溪鮮出石屏。", "欲從逋客逝，爲此未之能。"]'),
('02741500-37c0-4350-971d-3bd8b2026767','秋日山居好十首  其六','舒岳祥','宋','宋诗','song-poetry','','[]','秋日山居好，中秋興莫違。',48,'全唐诗/poet.song.227000.json','["秋日山居好，中秋興莫違。", "四腮鱸正脆，一尺蟹初肥。", "白露秔登饌，清霜絹下機。", "急舂輸井稅，無事早言歸。"]'),
('8fa4c555-5669-4629-9737-a8c1a5745842','秋日山居好十首  其七','舒岳祥','宋','宋诗','song-poetry','','[]','秋日山居好，重陽庶物穰。',48,'全唐诗/poet.song.227000.json','["秋日山居好，重陽庶物穰。", "剖菱紅綻白，剝栗紫含章。", "黄雀綿披脊，霜貍玉截肪。", "登高惟小圃，何必上重岡。"]'),
('dc4da118-c8bb-44bf-ba03-5633b1074681','秋日山居好十首  其八','舒岳祥','宋','宋诗','song-poetry','','[]','秋日山居好，清凉鴈過初。',48,'全唐诗/poet.song.227000.json','["秋日山居好，清凉鴈過初。", "雞頭消暑夕，鴨脚待霜餘。", "草浄蜃虻遠，瓜香蚤蟻除。", "小園新雨過，菜甲自刪鋤。"]'),
('fa072bc8-7a44-4bca-9e9e-df51a13a0df7','秋日山居好十首  其九','舒岳祥','宋','宋诗','song-poetry','','[]','秋日山居好，疎明入畫峯。',48,'全唐诗/poet.song.227000.json','["秋日山居好，疎明入畫峯。", "獵憐依寺鹿，樵護倚祠松。", "鴈起西風笛，人居夕照舂。", "東山久不到，勝具一枝筇。"]'),
('23616e94-d845-4774-96bf-fa741144fbe1','秋日山居好十首  其一○','舒岳祥','宋','宋诗','song-poetry','','[]','秋日山居好，秋濤木末橫。',48,'全唐诗/poet.song.227000.json','["秋日山居好，秋濤木末橫。", "龍藏寒水靜，鶻擊廣原平。", "紅葉茅茨露，黄花麯糵成。", "西風輕步履，隨意得閒行。"]'),
('74f866e9-3e00-4600-83ee-1e794d688763','冬日山居好十首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','冬日山居好，茅茨不漏風。',48,'全唐诗/poet.song.227000.json','["冬日山居好，茅茨不漏風。", "山厨蒸芋栗，野徑掃風蓬。", "嫩酒篘初白，寒灰撥暫紅。", "編氓吾未免，杜老屢囊空。"]'),
('e7605ed0-d47e-441b-93f4-d3a81eab7a70','冬日山居好十首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','冬日山居好，誰能倚市門。',48,'全唐诗/poet.song.227000.json','["冬日山居好，誰能倚市門。", "從橫鴉出郭，寂寞鸛歸村。", "爲念曲肱樂，因耽曝背溫。", "此時新放飲，招我苦吟魂。"]'),
('ba16482d-feb8-43e0-bad3-1e0b66afaf35','冬日山居好十首  其三','舒岳祥','宋','宋诗','song-poetry','','[]','冬日山居好，隨家豐儉宜。',48,'全唐诗/poet.song.227000.json','["冬日山居好，隨家豐儉宜。", "果成猿種核，薪落鶴巢枝。", "梅見天機早，菊知霜信遲。", "讀書年少事，任汝眼昏眵。"]'),
('6598a440-7c7c-41c3-80e8-580a7104f8fe','冬日山居好十首  其四','舒岳祥','宋','宋诗','song-poetry','','[]','冬日山居好，幽齋羃紙窗。',48,'全唐诗/poet.song.227000.json','["冬日山居好，幽齋羃紙窗。", "溫存簷鵲並，暖熱竹鳩雙。", "鹿下霜封塹，樵歸雪印矼。", "從茲謝城府，吾志鹿門龐。"]'),
('a56cd33a-434b-4922-8be9-c505c17df701','冬日山居好十首  其五','舒岳祥','宋','宋诗','song-poetry','','[]','冬日山居好，尤於老叟便。',48,'全唐诗/poet.song.227000.json','["冬日山居好，尤於老叟便。", "年衰催釀酒，骨冷早裝綿。", "著帽來梅下，扶輿到雪邊。", "興來聊復爾，微倦自高眠。"]'),
('f6305b17-03a0-452e-b18e-737897e2bf9b','冬日山居好十首  其六','舒岳祥','宋','宋诗','song-poetry','','[]','冬日山居好，農人告歲功。',48,'全唐诗/poet.song.227000.json','["冬日山居好，農人告歲功。", "明朝輸井稅，深夜動機舂。", "木脫見山市，霜清聞澗鐘。", "倘無饑凍迫，何必羨侯封。"]'),
('141d5f6e-9ad3-4487-bea0-efacc12c6dd8','冬日山居好十首  其七','舒岳祥','宋','宋诗','song-poetry','','[]','冬日山居好，先生獵較時。',48,'全唐诗/poet.song.227000.json','["冬日山居好，先生獵較時。", "海陂寒網鴈，嵐市夜分麋。", "酒熟隣相聚，家貧盜不窺。", "偷生前進士，幸矣過耆頤。"]'),
('7fab95c9-c90e-4496-a765-6b6ab7b00e0f','冬日山居好十首  其八','舒岳祥','宋','宋诗','song-poetry','','[]','冬日山居好，能閒樂自全。',48,'全唐诗/poet.song.227000.json','["冬日山居好，能閒樂自全。", "米豐平酒價，蔬賤減魚錢。", "偶爾思前事，依然是少年。", "下簾高枕卧，門外北風顛。"]'),
('bc9b99ab-9f4b-447b-9735-c1a6e1bd4eb2','冬日山居好十首  其九','舒岳祥','宋','宋诗','song-poetry','','[]','冬日山居好，不知年又窮。',48,'全唐诗/poet.song.227000.json','["冬日山居好，不知年又窮。", "老人六十七，破衲兩三重。", "未要迎新歲，聊須駐舊冬。", "明堂知未議，安用聘申公。"]'),
('3953efea-0d96-45b1-b021-4a6da1696ee5','冬日山居好十首  其一○','舒岳祥','宋','宋诗','song-poetry','','[]','冬日山居好，能安始識閒。',48,'全唐诗/poet.song.227000.json','["冬日山居好，能安始識閒。", "漁歸溪口港，樵下屋頭山。", "竹蠣含梅蘂，江鱸著玳斑。", "人生何所事，口腹最相關。"]'),
('01cf38a3-9ba9-414a-a27c-f85d455538b5','山甫遊鄞訪僧復歸山房','舒岳祥','宋','宋诗','song-poetry','','[]','麥熟歸小隠，詩名留遠方。',48,'全唐诗/poet.song.227000.json','["麥熟歸小隠，詩名留遠方。", "竹冠山靄重，棕屨石苔香。", "掃徑憐新筍，臨池玩舊芳。", "僧交非昔比，吾黨懼行藏。"]'),
('1cd8574b-46c8-4b8a-a78a-4d153c52f6b9','送胡山甫歸山房','舒岳祥','宋','宋诗','song-poetry','','[]','出峽復歸寺，身孤心更虛。',48,'全唐诗/poet.song.227000.json','["出峽復歸寺，身孤心更虛。", "半瓢岩下水，一豆雪中蔬。", "自制烏羅帽，閑將白髮梳。", "與君能幾別，此意重相於。"]'),
('073966fe-4202-4ad5-b0e2-cd40ab87fce0','八月十五夜月','舒岳祥','宋','宋诗','song-poetry','','[]','此夜十分月，年時中半秋。',48,'全唐诗/poet.song.227000.json','["此夜十分月，年時中半秋。", "華夷同一照，今古幾多愁。", "顥氣橫空白，天光際海浮。", "兒時讀書處，桂子落巖幽。"]'),
('5ea10d0d-b37d-4807-b3a9-014fedb20d4c','戲贈陳用之羨渠食筍也','舒岳祥','宋','宋诗','song-poetry','','[]','食筍肥勝肉，胸吞千畝寬。',48,'全唐诗/poet.song.227000.json','["食筍肥勝肉，胸吞千畝寬。", "汗青終日對，水墨一窗寒。", "吾子風流甚，此君冰雪完。", "每思參玉版，莫作北傖看。"]'),
('f6ac96d6-eca7-409a-b6c5-7376d05ec3c5','山行','舒岳祥','宋','宋诗','song-poetry','','[]','今日新晴好，東風散麥鬚。',48,'全唐诗/poet.song.227000.json','["今日新晴好，東風散麥鬚。", "山泉中琴瑟，巖鳥合笙竽。", "總是太平曲，何勞擊壤圖。", "誰知花濺淚，杜老獨嗟吁。"]'),
('45c52a35-1a27-410f-90dc-dac315212785','憶篆畦','舒岳祥','宋','宋诗','song-poetry','','[]','流水人千里，清風酒一尊。',48,'全唐诗/poet.song.227000.json','["流水人千里，清風酒一尊。", "烏頭何日白，鶴髮幾人存。", "石樹根基壯，秋蟲羽股繁。", "殷勤問來使，元亮欲歸園。"]'),
('cc5e2e51-3069-4a48-8cac-501bd007a2cc','送王奕世歸玉塘','舒岳祥','宋','宋诗','song-poetry','','[]','故人今有子，過我乞銘文。',48,'全唐诗/poet.song.227000.json','["故人今有子，過我乞銘文。", "紅樹催年老，青燈話夜分。", "詩箋傳父業，隸筆張吾軍。", "萬里青州路，沂公幾代墳。"]'),
('6fb54b23-9ea4-4340-b10c-292986569766','十二月初七日補綴舊詩寄正仲','舒岳祥','宋','宋诗','song-poetry','','[]','歲闌思飲酒，人老且捐書。',48,'全唐诗/poet.song.227000.json','["歲闌思飲酒，人老且捐書。", "春日將輝賁，陰風爲掃除。", "花前看燈蟹，雪後坐庵魚。", "有約君無負，牆根摘露蔬。"]'),
('dd9e9a87-7ffe-4f55-8549-893e9c6466cd','山居','舒岳祥','宋','宋诗','song-poetry','','[]','雀飲梅心雪，魚吞水面雲。',48,'全唐诗/poet.song.227000.json','["雀飲梅心雪，魚吞水面雲。", "山居差有味，世事不堪聞。", "野燒窮狸穴，晴霄轉鴈羣。", "溪寒春未著，閏月壓餘分。"]'),
('d9177c70-0e9c-4d2e-a36e-fa7fefbe673c','借正仲韻賦牡丹','舒岳祥','宋','宋诗','song-poetry','','[]','洛陽宮苑地，幻出幾花身。',48,'全唐诗/poet.song.227000.json','["洛陽宮苑地，幻出幾花身。", "艷色宜當午，開時惜殿春。", "管弦非舊國，風雨易愁人。", "同是多情客，相逢說夢因。"]'),
('965c2d89-6a7e-4b9c-8392-55e18efaa2d0','阪坑頭上籃輿煙雨中賦此醒困','舒岳祥','宋','宋诗','song-poetry','','[]','下眺黄泥阪，濛濛曉霧漫。',48,'全唐诗/poet.song.227000.json','["下眺黄泥阪，濛濛曉霧漫。", "巖泉時一滴，松雨幾曾乾。", "利倍鹽爲市，耕勞石作田。", "我來聊小憇，前去路千難。"]'),
('897dc0d2-db94-432f-8775-3df56ac81e2f','十三日即事','舒岳祥','宋','宋诗','song-poetry','','[]','蒿欺菊叢瘦，蔓壓橘枝低。',48,'全唐诗/poet.song.227000.json','["蒿欺菊叢瘦，蔓壓橘枝低。", "應俗精神減，傷時夢寐迷。", "欹眠中夜鴈，薄飯午時鷄。", "咄咄真堪怪，秋深杜宇啼。"]'),
('74053cc9-accd-49ef-9362-b528540dfa9b','春分偶飲成醉兀兀坐睡覺而殘月在窗矣','舒岳祥','宋','宋诗','song-poetry','','[]','酒熟還成飲，花香忽過牆。',48,'全唐诗/poet.song.227000.json','["酒熟還成飲，花香忽過牆。", "近燈人影大，斜月樹身長。", "陰洞龍藏雨，春苗麝養香。", "閒吟誰與語，醉倚一胡牀。"]'),
('3c915816-916d-4c21-a7a0-4a03cd49d8df','闕題','舒岳祥','宋','宋诗','song-poetry','','[]','潮分船出浦，雪破馬行沙。',48,'全唐诗/poet.song.227000.json','["潮分船出浦，雪破馬行沙。", "去去三千里，疎疎八九家。", "矮壺分乳酪，疏竹看梅花。", "虎豹方充斥，風林噪亂鴉。"]'),
('942e0b19-f221-49da-b7d5-32defd5ebb2f','田舍偶憶菖蒲','舒岳祥','宋','宋诗','song-poetry','','[]','山窗偶閑靜，無事憶菖蒲。',48,'全唐诗/poet.song.227000.json','["山窗偶閑靜，無事憶菖蒲。", "怪石磨劍脊，西風拂虎鬚。", "性貞偏愛潔，節勁固應癯。", "何日新書室，清泉手自𣂏。"]'),
('f88981ec-62b1-45fc-9368-879f55151cda','渚宮秋思','舒岳祥','宋','宋诗','song-poetry','','[]','石樹表獨立，瓦蛩相與言。',48,'全唐诗/poet.song.227000.json','["石樹表獨立，瓦蛩相與言。", "雙鷗定漁社，一犬護柴門。", "抱甕非吾土，浮家何處村。", "枕邊黄黍飯，用此了乾坤。"]'),
('b70e4aff-b5fc-48cd-bc90-63a81ddf8cb5','風','舒岳祥','宋','宋诗','song-poetry','','[]','太虛無朕兆，因物見形聲。',48,'全唐诗/poet.song.227000.json','["太虛無朕兆，因物見形聲。", "入竹須搶地，驅潮欲打城。", "八方隨氣轉，萬里掃塵清。", "誰道鵬摶壯，反從虎嘯生。"]'),
('6b30e53a-57e5-4e41-a53d-320ff16926ed','中秋與山甫登樓小酌','舒岳祥','宋','宋诗','song-poetry','','[]','莫笑斯樓小，因高勢自尊。',48,'全唐诗/poet.song.227000.json','["莫笑斯樓小，因高勢自尊。", "江山圖萬井，烟樹點千村。", "斫却月中桂，烹他海上鯤。", "乘槎八月半，與子探河源。"]'),
('c5297241-56f8-4892-99b3-0c304865ee3e','觀窗前月過有感','舒岳祥','宋','宋诗','song-poetry','','[]','簷影倒垂地，月高窗更陰。',48,'全唐诗/poet.song.227000.json','["簷影倒垂地，月高窗更陰。", "殘蛩沉積葉，悲鳥發遥岑。", "易下傷時淚，難平讀史心。", "胸中猶若此，酒盞可辭深。"]'),
('7bd886f0-7184-4e55-a0f5-1322811d51c9','聞有海船入鄞作詩附寄正仲','舒岳祥','宋','宋诗','song-poetry','','[]','華館多髯客，深山短髮翁。',48,'全唐诗/poet.song.227000.json','["華館多髯客，深山短髮翁。", "鐘聲更點外，螢焰燒痕中。", "春日同傾酒，寒溪數過鴻。", "天門通海路，詩寄鄮城東。"]'),
('62f60b44-9a88-46dd-b649-964084c37518','山甫還峽石有懷書寄','舒岳祥','宋','宋诗','song-poetry','','[]','靜者一爲別，誰將幽抱同。',48,'全唐诗/poet.song.227000.json','["靜者一爲別，誰將幽抱同。", "行詩求谷友，買紙囑溪翁。", "數點淡雲樹，一行遥海鴻。", "莫因尋薯蕷，深入萬山叢。"]'),
('c2ca8ab7-d882-4707-bcd8-9e4dcbea4d35','坐對蘭菊有樵人獻石輪囷如雲亦鐵中錚錚也喜而成咏','舒岳祥','宋','宋诗','song-poetry','','[]','老入遠公社，閑披貝葉文。',48,'全唐诗/poet.song.227000.json','["老入遠公社，閑披貝葉文。", "移梅兼得月，買石看生雲。", "潭浄知魚數，煙青別鷺羣。", "平生有香癖，蘭菊勝爐薰。"]'),
('4cdfaee8-52a6-4804-85b4-e54aba6d3b29','春深贈山甫','舒岳祥','宋','宋诗','song-poetry','','[]','石枕空蝴蝶，山窗足杜鵑。',48,'全唐诗/poet.song.227000.json','["石枕空蝴蝶，山窗足杜鵑。", "春深方沃若，人意自翛然。", "衰老難爲別，留連未肯眠。", "燈花知我意，今夜大如錢。"]'),
('8a8d7545-630e-4afd-ac2c-798e325ac0f1','贈周此山','舒岳祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','梅花台越路，來往此番新。',48,'全唐诗/poet.song.227000.json','["梅花台越路，來往此番新。", "風月三間屋，乾坤六尺身。", "枕中鉛汞術，筆下蕙蘭春。", "聽說西江事，廬山面目真。"]'),
('170ccc1f-3905-4eb1-bc14-7cc36b20e033','春晚聞霰客思凄然兩日不見達善季辯書懷奉寄','舒岳祥','宋','宋诗','song-poetry','','[]','夜闌風薄樹，雨急水坍沙。',48,'全唐诗/poet.song.227000.json','["夜闌風薄樹，雨急水坍沙。", "書在吾何恨，春深自憶家。", "高花猶著雪，淺草早鳴蛙。", "同是離居客，相逢弔歲華。"]'),
('90c236e5-5a18-4dbf-b508-a7e8a117dd96','趨俗','舒岳祥','宋','宋诗','song-poetry','','[]','殘雪高峯外，孤猿細雨中。',48,'全唐诗/poet.song.227000.json','["殘雪高峯外，孤猿細雨中。", "看花心未老，問事耳須聾。", "時俗同傖父，歸休學塞翁。", "相隨携酒去，獵較祭田公。"]'),
('08506822-e422-4873-9caf-d91544734e5d','葬沈氏墓','舒岳祥','宋','宋诗','song-poetry','','[]','連夜頻夢見，那知是與非。',48,'全唐诗/poet.song.227000.json','["連夜頻夢見，那知是與非。", "天高難告訴，佛近且皈依。", "修竹墳三尺，寒梅石四圍。", "有兒年十七，他日望傳衣。"]'),
('eee0a3ea-6b82-4bae-884e-8b41335a84d2','哭謝尚書','舒岳祥','宋','宋诗','song-poetry','','[]','翰林真學士，吏部老尚書。',48,'全唐诗/poet.song.227000.json','["翰林真學士，吏部老尚書。", "薊北非吾土，鄞江有舊廬。", "死生今已矣，出處竟何如。", "邛竹先龍化，人琴一慟餘。"]'),
('1b7f229b-b203-4243-8713-fc432e6f1abb','哭王達善','舒岳祥','宋','宋诗','song-poetry','','[]','一叟經年瘧，蕭然强飯蔬。',48,'全唐诗/poet.song.227000.json','["一叟經年瘧，蕭然强飯蔬。", "殘花清供後，瘦竹苦吟餘。", "女授伏生業，兒工阿買書。", "曾無一紙別，疑信問何如。"]'),
('5a495608-23e1-4a75-9d1b-7b0eec3f3018','哭李實甫','舒岳祥','宋','宋诗','song-poetry','','[]','帝閽嘗再叩，龍頷竟難攀。',48,'全唐诗/poet.song.227000.json','["帝閽嘗再叩，龍頷竟難攀。", "帙散螢千點，詩留豹一斑。", "人生會有極，吾道幾曾還。", "藏我擇軒記，名垂天地間。"]'),
('49658181-81d4-46ce-af22-9be4bf15cfb6','哭匊田詩老  其一','舒岳祥','宋','宋诗','song-poetry','','[]','尋源自永嘉，清響黜浮葩。',48,'全唐诗/poet.song.227000.json','["尋源自永嘉，清響黜浮葩。", "一字不犯古，五言真到家。", "思幽多掩抑，情至重咨嗟。", "欲擬徵君誄，天寒日又斜。"]'),
('92bbd780-2496-47f0-829d-c455b61ac814','哭匊田詩老  其二','舒岳祥','宋','宋诗','song-poetry','','[]','本是攻文者，其如癖在詩。',48,'全唐诗/poet.song.227000.json','["本是攻文者，其如癖在詩。", "人皆尊島佛，我欲效宗師。", "廢圃營新屋，寒花带短籬。", "風流無此老，遺藁訪佳兒。"]'),
('fce9bafb-919a-4b07-a30f-bd26c258f234','哭陳伯求','舒岳祥','宋','宋诗','song-poetry','','[]','早總淮西餉，晚爲刑部郎。',48,'全唐诗/poet.song.227000.json','["早總淮西餉，晚爲刑部郎。", "艱危身九隕，漂泊淚千行。", "天地孤忠在，山河遺恨長。", "寡妻隨季女，猶得在鄞鄉。"]'),
('4ab4efe6-4155-4a84-bb75-6cbb546837a2','燈下飲別','舒岳祥','宋','宋诗','song-poetry','','[]','歲晚客思去，天寒子肯來。',48,'全唐诗/poet.song.227000.json','["歲晚客思去，天寒子肯來。", "稽留須酒熟，歡喜見梅開。", "蠟屐匆匆駐，箯輿故故迴。", "嘉平猶未盡，且欲舉殘杯。"]'),
('4ffe66c2-b8e9-41e9-a6c7-1f2d07c7862b','贈別山甫','舒岳祥','宋','宋诗','song-poetry','','[]','勞君出南峽，從我上東山。',48,'全唐诗/poet.song.227000.json','["勞君出南峽，從我上東山。", "辟惡香萸紫，延年細菊斑。", "看雲獨無語，覆斗且徐還。", "說到忘機處，沙鷗也自閒。"]'),
('94e1b41e-9086-4c43-8aab-7a2a7efb57c4','贈別君英','舒岳祥','宋','宋诗','song-poetry','','[]','相去十五里，不來幾半年。',48,'全唐诗/poet.song.227000.json','["相去十五里，不來幾半年。", "知君有農事，疎我話詩篇。", "置石桐陰澗，開門海口天。", "老人愁此別，把酒菊叢邊。"]'),
('26f578a0-7376-46ec-949f-79ed337e8cd6','山甫遊嵊拜戴安道墓而歸新年過我鳳棲作此贈別','舒岳祥','宋','宋诗','song-poetry','','[]','尚謁死安道，寧忘生閬風。',48,'全唐诗/poet.song.227000.json','["尚謁死安道，寧忘生閬風。", "千巖幾尊酒，百歲一枝筇。", "且可耽甜黑，何須醉軟紅。", "謝公高卧處，明月在巖松。"]'),
('386d33bf-ffec-4361-8da0-064bce14a6b1','正仲過鳳棲臨行贈別','舒岳祥','宋','宋诗','song-poetry','','[]','甲子春晴好，鳳棲理去鞍。',48,'全唐诗/poet.song.227000.json','["甲子春晴好，鳳棲理去鞍。", "江湖一葉小，風雨對床寒。", "鼻鼾聲何壯，燈花夜未闌。", "紛紛多盜日，吾黨敢求安。"]'),
('bbf60f78-567e-4c8f-b3c4-421e44faba03','贈正仲別','舒岳祥','宋','宋诗','song-poetry','','[]','一年三過我，此去定經年。',48,'全唐诗/poet.song.227000.json','["一年三過我，此去定經年。", "雪壓登魚渚，雲生落鴈田。", "壯遊今已矣，老別自潸然。", "心事有難說，斯文屬子傳。"]'),
('3e2a340a-c8af-46d1-90a5-14a6452fccc7','再贈','舒岳祥','宋','宋诗','song-poetry','','[]','不惜此時別，毋忘別後音。',48,'全唐诗/poet.song.227000.json','["不惜此時別，毋忘別後音。", "相隨溪上影，共息樹邊陰。", "水落行田蟹，霜晴出谷禽。", "何須拘改歲，有興即相尋。"]'),
('3fa230ff-251c-45cc-b812-df28e61971f8','四月六日絕糧用銀盞易穀作詩別之','舒岳祥','宋','宋诗','song-poetry','','[]','從此與君別，臨行更一傾。',48,'全唐诗/poet.song.227000.json','["從此與君別，臨行更一傾。", "縱令愁作海，誰送酒如澠。", "已悟興亡理，空留物我情。", "不知陶靖節，何物了平生。"]'),
('05e560d6-c8dc-4bd6-bd5c-3755b2a68145','十六夜月蝕既','舒岳祥','宋','宋诗','song-poetry','','[]','蝦蟆新食月，金餠曲如鈎。',48,'全唐诗/poet.song.227000.json','["蝦蟆新食月，金餠曲如鈎。", "天道終還舊，書生自隠憂。", "星辰秋後爛，河漢夜深流。", "我欲騎鵬背，乘風閲九州。"]'),
('ae62e2fa-3224-40c7-a932-25d4b27b5641','八月二十五日聞布新條','舒岳祥','宋','宋诗','song-poetry','','[]','民命無魂鹿，烹庖幾日休。',48,'全唐诗/poet.song.227000.json','["民命無魂鹿，烹庖幾日休。", "紛紛渾未悟，炯炯爲深憂。", "並和隣舂相，分漁步網收。", "聊爲目前計，甆椀汲新篘。"]'),
('a9a7c634-0648-4474-99f2-e9d60e8a30cc','過劉允叔故居','舒岳祥','宋','宋诗','song-poetry','','[]','流水孤村裏，先生此故居。',48,'全唐诗/poet.song.227000.json','["流水孤村裏，先生此故居。", "風流今已矣，天道竟何如。", "古屋前朝檜，薌巖萬卷書。", "蒼苔封瓦礫，野燐出丘墟。"]'),
('6381c048-bbbd-442b-8cf1-8befeecfd86b','安住寺松聲','舒岳祥','宋','宋诗','song-poetry','','[]','晴日千竿籟，春風萬鼓鼙。',48,'全唐诗/poet.song.227000.json','["晴日千竿籟，春風萬鼓鼙。", "清和兼怨適，細大雜高低。", "釋子聆眠石，行人聽過溪。", "曾於天竺寺，爲爾駐遊藜。"]'),
('197e37c3-a49a-4fa8-9bff-99aaa059e7de','聞鄞兵入仙居二首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','獨嶺斜陽笠，深溪夜雨燈。',48,'全唐诗/poet.song.227000.json','["獨嶺斜陽笠，深溪夜雨燈。", "多憂未歸客，萬事不言僧。", "兵甲今如此，台明昔未曾。", "欲言徵斂數，天遠有誰能。"]'),
('df2c800a-edf7-49d7-9f30-1c0e9c94bd3c','聞鄞兵入仙居二首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','細雨殘陽外，孤村亂水中。',48,'全唐诗/poet.song.227000.json','["細雨殘陽外，孤村亂水中。", "饑年才半菽，白髮聽疎舂。", "世事何曾了，吾生會有窮。", "深衣斂形日，嗟我一枝筇。"]'),
('97e5613a-86b5-4867-857f-76fbc677d7c9','悲來','舒岳祥','宋','宋诗','song-poetry','','[]','竹簡千年夢，楸枰萬古爭。',48,'全唐诗/poet.song.227000.json','["竹簡千年夢，楸枰萬古爭。", "推敲渾細事，著述亦虛名。", "春艷無長好，秋吟恨短生。", "乃知天壤內，各以一時鳴。"]'),
('31368687-90cb-423f-94de-cf0d217da88b','健洐僕有書五千卷藏明恩山房亂後幸存胡山甫寄一榻爲吟所聞已遷入作唐律寄題','舒岳祥','宋','宋诗','song-poetry','','[]','歲久殘僧屋，吾書故不塵。',48,'全唐诗/poet.song.227000.json','["歲久殘僧屋，吾書故不塵。", "持經入深竹，分韻與閑人。", "花氣聞慈像，松凉施四隣。", "細思貧最好，懷璧每戕身。"]'),
('19ce293d-669a-462c-b522-888614b02c09','雪後喜晴和正仲近詩  其一','舒岳祥','宋','宋诗','song-poetry','','[]','今朝天氣好，寒減煖初增。',48,'全唐诗/poet.song.227000.json','["今朝天氣好，寒減煖初增。", "微醉無灰酒，閑居有髮僧。", "芳情花下月，艷眼雪中燈。", "久廢賡酬事，新詩忽啟縢。"]'),
('79e9c1cf-35de-4d66-9d52-bef44ff6d9eb','雪後喜晴和正仲近詩  其二','舒岳祥','宋','宋诗','song-poetry','','[]','雲開青鏡曉，病起白頭人。',48,'全唐诗/poet.song.227000.json','["雲開青鏡曉，病起白頭人。", "陽洞林光動，晴簷鳥語真。", "黄花修故事，新酒接比隣。", "火急輸官米，寒舂連夜頻。"]'),
('c7e6dccf-3afc-4a90-978d-4d679d5c0553','十一月初三日夜有興尋梅','舒岳祥','宋','宋诗','song-poetry','','[]','樹下春來往，窗間月死生。',48,'全唐诗/poet.song.227000.json','["樹下春來往，窗間月死生。", "尋梅何處好，隨意自溪行。", "酒債應無數，燈花各有情。", "明朝江上路，風雪一詩成。"]'),
('29a548f2-e443-4d62-bb85-80afd1080148','送潘少白遊桐柏宮','舒岳祥','宋','宋诗','song-poetry','','[]','桐柏舊題句，方瀛新記文。',48,'全唐诗/poet.song.227000.json','["桐柏舊題句，方瀛新記文。", "因君重拂拭，爲我致殷勤。", "仙過峰停鶴，龍藏井閟雲。", "金丹如可鍊，此去訪方聞。"]'),
('18da2a69-4707-4275-b69c-f2383d1535c2','曝書庭中即事有作因思正仲在鴈蒼山南爲我作小楷雜以和篇當大有可觀因以寄之','舒岳祥','宋','宋诗','song-poetry','','[]','稍覺干戈定，聊寬旦夕憂。',48,'全唐诗/poet.song.227000.json','["稍覺干戈定，聊寬旦夕憂。", "黍黄鷄應喌，草遠犢呼牟。", "匣畫乘陽展，庭書值雨收。", "漳濱想公幹，小楷作銀鈎。"]'),
('07adb572-3b60-4d15-ace5-3000bc0ee042','賤生之日邀正仲子堂小酌','舒岳祥','宋','宋诗','song-poetry','','[]','開歲恰七十，吾衰病已頻。',48,'全唐诗/poet.song.227000.json','["開歲恰七十，吾衰病已頻。", "從今數正旦，一月有三晨。", "甲子添新誌，乾坤寄老身。", "晚年方學易，此意爲誰陳。"]'),
('cd6dd8be-89f5-4377-bcb7-a60d81a91118','次正仲訪山中留別韻','舒岳祥','宋','宋诗','song-poetry','','[]','及此真知老，吾初不謂然。',48,'全唐诗/poet.song.227000.json','["及此真知老，吾初不謂然。", "相期無別事，不朽要千年。", "過我論新句，留君訂舊篇。", "胡爲趨歸騎，忙似趁潮船。"]'),
('4d1a741b-2597-49d5-8691-603fda8a3413','挽董知鎮','舒岳祥','宋','宋诗','song-poetry','','[]','曾行栲源路，相訪竹溪頻。',48,'全唐诗/poet.song.227000.json','["曾行栲源路，相訪竹溪頻。", "事帝清心旦，於人笑面春。", "升堂驚挂影，下榻憶延賓。", "風雪深尊夜，梅花滿座茵。"]'),
('3695d9f0-067c-4c06-8b67-b70fa9934918','花鳥','舒岳祥','宋','宋诗','song-poetry','','[]','色與聲俱妙，鳥啼花亂開。',48,'全唐诗/poet.song.227000.json','["色與聲俱妙，鳥啼花亂開。", "此時無事惱，有酒待誰來。", "漂泊迷歸路，昏花恣覆杯。", "已聞雷迸筍，不怕雹驚梅。"]'),
('23b00b93-5a69-4042-9350-043c129539b9','四月二十四日雨中分酒餉山友','舒岳祥','宋','宋诗','song-poetry','','[]','欲言林下趣，思共澗邊行。',48,'全唐诗/poet.song.227000.json','["欲言林下趣，思共澗邊行。", "細雨枇杷熟，空江杜若生。", "離居非遠道，向夕自含情。", "偶此開松酒，分將一榼傾。"]'),
('2286e11b-3b43-43dc-887c-37764a4c897e','楝花','舒岳祥','宋','宋诗','song-poetry','','[]','蒸入黄梅雨，寒收苦楝風。',48,'全唐诗/poet.song.227000.json','["蒸入黄梅雨，寒收苦楝風。", "團團羽葆盖，疊疊繡熏籠。", "文錦財堪用，金鈴實有功。", "小畦留一樹，斤斧幸相容。"]'),
('7c0c9db4-25a7-490a-aae1-f2b1bbd7b9ed','山齋夜坐','舒岳祥','宋','宋诗','song-poetry','','[]','新歲纔三日，春風便不同。',48,'全唐诗/poet.song.227000.json','["新歲纔三日，春風便不同。", "花前雙鬢白，雪後一燈紅。", "老去心無術，愁來佛亦空。", "吾儒真實在，千古獲麟翁。"]'),
('7e99596f-7418-4f77-b0f6-ce903ee75c28','用正仲茅字韻','舒岳祥','宋','宋诗','song-poetry','','[]','月白溪頭石，霜清屋上茅。',48,'全唐诗/poet.song.227000.json','["月白溪頭石，霜清屋上茅。", "歲行天自運，人老志還勞。", "冬菊忘年友，寒梅耐久交。", "向來金椀醉，今日對陶匏。"]'),
('4f040f7a-9065-4c17-92ad-a0175f8c8226','次張幼學見寄韻','舒岳祥','宋','宋诗','song-poetry','','[]','何必羨商顔，幽奇出嶮艱。',48,'全唐诗/poet.song.227000.json','["何必羨商顔，幽奇出嶮艱。", "歸舟天際樹，宿鳥屋頭山。", "畏虎長危坐，尋僧更不閑。", "酬詩無好句，奚錦得空還。"]'),
('7fa11230-380e-4942-9274-6a9e398b24b8','九月朔晨起憶故園晚易','舒岳祥','宋','宋诗','song-poetry','','[]','晚易圖書燼，篆畦花木新。',48,'全唐诗/poet.song.227000.json','["晚易圖書燼，篆畦花木新。", "承平三世積，喪亂一朝貧。", "清曉憑欄意，空山袖手人。", "平生欲學杜，漂泊始成真。"]'),
('c7056acc-2a5b-46a1-8f6e-9bcdb05f7015','賦山庵梅花','舒岳祥','宋','宋诗','song-poetry','','[]','水石生來瘦，乾坤孕此情。',48,'全唐诗/poet.song.227000.json','["水石生來瘦，乾坤孕此情。", "寒谿千尺照，殘雪數枝橫。", "光射霜髯逼，酥浮玉面爭。", "何人夜吹笛，故作斷腸聲。"]'),
('a5034b51-590e-443b-9a22-04f120abda43','簡胡山甫','舒岳祥','宋','宋诗','song-poetry','','[]','門外月誰敲，花開醉遠郊。',48,'全唐诗/poet.song.227000.json','["門外月誰敲，花開醉遠郊。", "自尋幽寺宿，不耐俗人交。", "裘替疏泉洗，詩添續紙抄。", "一身舟不繫，萬事柱難膠。"]'),
('49e7b76d-28ef-4162-ab3f-7e28e162d379','臘月朔第二孫繩祖彌月喜其與翁同十一月而又皆乙亥時也因賦以祝之','舒岳祥','宋','宋诗','song-poetry','','[]','繩祖初彌月，清晨抱見翁。',48,'全唐诗/poet.song.227000.json','["繩祖初彌月，清晨抱見翁。", "頗憐頭額大，兼愛月時同。", "句法何時就，家聲待汝洪。", "吾年八十二，方見汝成童。"]'),
('e014bf38-724b-4839-bf53-279ebd7f4cc9','送潘少白赴連山館','舒岳祥','宋','宋诗','song-poetry','','[]','桐木深坑嶺，菊田高弟家。',48,'全唐诗/poet.song.227000.json','["桐木深坑嶺，菊田高弟家。", "聞渠能館致，去我使人嗟。", "箬長潛沙笋，蘭開傍石花。", "古琴留掛壁，此意澹無邪。"]'),
('4756e8f2-8915-4bd7-9673-1e793acc6fe0','還龍舒舊隠','舒岳祥','宋','宋诗','song-poetry','','[]','今朝歸小隠，隣里喜還悲。',48,'全唐诗/poet.song.227000.json','["今朝歸小隠，隣里喜還悲。", "亡國誰修史，遺民自採詩。", "鼠營新穴壤，鶴理舊巢枝。", "見說寅年泰，冥心待運移。"]'),
('b3b96eb8-2d3b-408b-ae1e-643bf056f09f','懷昔','舒岳祥','宋','宋诗','song-poetry','','[]','淮海新封國，東南望止戈。',48,'全唐诗/poet.song.227000.json','["淮海新封國，東南望止戈。", "紗衣秋意早，石枕雨聲多。", "白露皺紅棗，西風擺老荷。", "昔年遊萬里，今日興如何。"]'),
('bc591998-e5fb-4ebf-a941-0eb0b9ecd0e3','暮春山居呈山甫正仲','舒岳祥','宋','宋诗','song-poetry','','[]','逕盤如繆篆，石浄可橫琴。',48,'全唐诗/poet.song.227000.json','["逕盤如繆篆，石浄可橫琴。", "好鳥連朝在，蒼苔一寸深。", "撥泥尋筍脈，掃地引蕉陰。", "三客誰家有，風流壓晉林。"]'),
('5e6c3b72-41c7-4602-b2bf-a3d326b0f1c2','十七日夜村市','舒岳祥','宋','宋诗','song-poetry','','[]','今歲梅誰待，因遲却未殘。',48,'全唐诗/poet.song.227000.json','["今歲梅誰待，因遲却未殘。", "新泉生暗谷，遠燒照前灘。", "圓景終難久，殘燈未肯闌。", "沉吟思往事，猶自倚闌干。"]'),
('c063614b-89c6-423b-ba24-94cd1099afce','喜見早梅花','舒岳祥','宋','宋诗','song-poetry','','[]','朔雪吹吟屋，春風駐酒家。',48,'全唐诗/poet.song.227000.json','["朔雪吹吟屋，春風駐酒家。", "野塘冰上鴈，官柳月中鴉。", "玉饌寒沙筍，金虀夜雨芽。", "開窗有新事，喜見早梅花。"]'),
('97e47375-0368-4609-89bb-99d68722f74f','戲作','舒岳祥','宋','宋诗','song-poetry','','[]','莫笑山居僻，山居號令明。',48,'全唐诗/poet.song.227000.json','["莫笑山居僻，山居號令明。", "芭蕉工報雨，鴝鵒解知更。", "樵長專封拜，詩壇擁甲兵。", "開窗一壺酒，新句賞新晴。"]'),
('564ad8c5-0066-4a91-88f3-08a6b71d8168','秋夕寄周鍊師','舒岳祥','宋','宋诗','song-poetry','','[]','蟲聲疊哀思，樹影弄清輝。',48,'全唐诗/poet.song.227000.json','["蟲聲疊哀思，樹影弄清輝。", "休恨催年老，私慚昧昨非。", "倦童眠自語，驚鶴定還飛。", "遠念周高志，華顛坐翠微。"]'),
('3bc5d271-84ca-4131-8d28-3e5e4bc5396b','易庵道人歸鴈蒼兩月矣作詩趣之','舒岳祥','宋','宋诗','song-poetry','','[]','一入鴈蒼山，山蒼鴈落灣。',48,'全唐诗/poet.song.227000.json','["一入鴈蒼山，山蒼鴈落灣。", "石螿鳴杼下，沙鳥宿窗間。", "吾子動多悔，老夫今稍閑。", "密雲疎雨裏，心事極相關。"]'),
('cc99b10c-b0ac-41a6-9d1e-88506c446809','甲申正月二十日遊盤谷道院贈石澗鍊師','舒岳祥','宋','宋诗','song-poetry','','[]','滄海連雲族，青山遠驛塵。',48,'全唐诗/poet.song.227000.json','["滄海連雲族，青山遠驛塵。", "回旋成小隠，想像著幽人。", "桃樹偏臨水，梅花諱說春。", "扶輿穿犖确，空翠濕衣巾。"]'),
('752aed09-5848-4f37-8d8e-f95adddb69bf','過明智寺','舒岳祥','宋','宋诗','song-poetry','','[]','每過明智寺，小寺在山前。',48,'全唐诗/poet.song.227000.json','["每過明智寺，小寺在山前。", "老衲分雲坐，山猿抱子眠。", "巖花紅雜雨，野水綠平田。", "火後傷心處，青山響杜鵑。"]'),
('c9b5cdf6-872f-4be4-a15a-6be268e0b99a','春晚寄二林','舒岳祥','宋','宋诗','song-poetry','','[]','穀雨秧芽動，楝風花信來。',48,'全唐诗/poet.song.227000.json','["穀雨秧芽動，楝風花信來。", "蟹奔沙上火，筍長地中雷。", "燕子巢重定，主人門早開。", "二林詩敵手，先著一篇催。"]'),
('55b5038a-c371-4ee0-81ad-14d5536a78de','辛卯正月二日蝶軒蚤作','舒岳祥','宋','宋诗','song-poetry','','[]','鴉背閃晴天，輕明紫翠烟。',48,'全唐诗/poet.song.227000.json','["鴉背閃晴天，輕明紫翠烟。", "年將人老大，形與影周旋。", "鳥語催晨枕，梅花照夜編。", "池塘春草句，此意有誰傳。"]'),
('a004acfc-01ed-463b-bec3-0066ad1ef213','吾道','舒岳祥','宋','宋诗','song-poetry','','[]','聞惡休三唾，懷賢賦七哀。',48,'全唐诗/poet.song.227000.json','["聞惡休三唾，懷賢賦七哀。", "衰年催白髮，細雨足紅梅。", "江海歸詩卷，乾坤換劫灰。", "老儒何所用，吾道自須回。"]'),
('7674c31d-7ff3-442d-81a1-a970024ef17a','八月二十八日與潘少白劉君英草酌耕養堂時劉正仲以求免役入城予亦爲羣小見厄者也','舒岳祥','宋','宋诗','song-poetry','','[]','二子論秋夜，秋蛩是四隣。',48,'全唐诗/poet.song.227000.json','["二子論秋夜，秋蛩是四隣。", "葉黄狐下隴，燈暗鼠欺人。", "借譽門多客，臨危俗少親。", "平生劉正仲，於此見情真。"]'),
('0db4d5d7-89bc-46b3-a57e-6f2bc8fc0714','約諸友九日遊東山','舒岳祥','宋','宋诗','song-poetry','','[]','語石雙蛩碎，鳴軒一葉鏘。',48,'全唐诗/poet.song.227000.json','["語石雙蛩碎，鳴軒一葉鏘。", "黄花無舊客，白髮又重陽。", "日月雙飛翼，乾坤幾戰場。", "人生一百歲，不飲自堪傷。"]'),
('6ed54c6c-adf2-47fd-870a-ee9489aae5e2','山甫病中歸峽作此問之','舒岳祥','宋','宋诗','song-poetry','','[]','山甫病歸峽，僧言藥有瘳。',48,'全唐诗/poet.song.227000.json','["山甫病歸峽，僧言藥有瘳。", "自憐三歲長，多白幾分頭。", "水鳥工吟夜，陰蛩苦話秋。", "詩人多病瘧，彊飯更何憂。"]'),
('a244c029-db63-47b5-8468-fb5a0f142369','送帥初遊浙西','舒岳祥','宋','宋诗','song-poetry','','[]','吳下吾遊地，因君思又飄。',48,'全唐诗/poet.song.227000.json','["吳下吾遊地，因君思又飄。", "水花香外雨，沙鳥夢邊潮。", "載酒浮官舫，吟詩上驛橋。", "三高祠下過，爲賦楚辭招。"]'),
('ca0d4e96-c395-4b7f-8844-089af60394d8','松花','舒岳祥','宋','宋诗','song-poetry','','[]','偃蹇不入俗，隨春也作花。',48,'全唐诗/poet.song.227000.json','["偃蹇不入俗，隨春也作花。", "高攀許樵子，輕掃落僧家。", "功用雖非藥，風標正似茶。", "秋風收子食，辟穀勝胡麻。"]'),
('8d2fc168-8f6c-4236-9af9-2cb1c7f82b9b','消憂','舒岳祥','宋','宋诗','song-poetry','','[]','鳳棲塘上路，春草思悠悠。',48,'全唐诗/poet.song.227000.json','["鳳棲塘上路，春草思悠悠。", "綠樹雙黄鳥，青山一白頭。", "詩書自有厄，盜賊本非仇。", "天道知難問，吾貧不肯憂。"]'),
('522cb3de-2dfc-48dc-a0f1-69f58ec53b2a','宿龜石寺','舒岳祥','宋','宋诗','song-poetry','','[]','朅來誰主我，野寺得閑行。',48,'全唐诗/poet.song.227000.json','["朅來誰主我，野寺得閑行。", "借屋安書庋，就巖搘飯鐺。", "山晴分鴈轉，水煖見魚生。", "無事人情好，相逢總笑迎。"]'),
('636e664c-7639-4248-8aae-a00a941a5d19','遊龜石寺','舒岳祥','宋','宋诗','song-poetry','','[]','舊說龜爲石，今知石化龜。',48,'全唐诗/poet.song.227000.json','["舊說龜爲石，今知石化龜。", "溪分剡溪秀，亭近鎮亭遺。", "沙鳥穿青樾，巖花覆碧漪。", "逢僧如雅素，携看古廊碑。"]'),
('59ca04ae-b478-4667-ace8-9e5e1395ea06','重遊龜石寺','舒岳祥','宋','宋诗','song-poetry','','[]','一龜先過水，更有一龜尋。',48,'全唐诗/poet.song.227000.json','["一龜先過水，更有一龜尋。", "鳥出石潭底，筍穿沙樹心。", "平橋連斷岸，古佛坐喬林。", "竹裏何人住，時聞嘯咏音。"]'),
('f5981a63-206c-4f8e-8063-381a4a87240a','曉凉','舒岳祥','宋','宋诗','song-poetry','','[]','秋風萬里清，客子最含情。',48,'全唐诗/poet.song.227000.json','["秋風萬里清，客子最含情。", "山路殘星在，柴門野水鳴。", "平田聞鴈起，落月有人行。", "破篋無書冊，何須眼復明。"]'),
('972426f4-68f2-44ec-a4d9-d45854a446c9','題汪日賓西樓附山甫達之','舒岳祥','宋','宋诗','song-poetry','','[]','不忘西來意，開窗西復西。',48,'全唐诗/poet.song.227000.json','["不忘西來意，開窗西復西。", "柳懸魚怒頰，蒲縛蟹團臍。", "縣近更傳信，寺圍鐘到齊。", "山翁出山處，放杖得新題。"]'),
('3165e029-26fd-4e16-80e0-2e71d4b3d439','山窗即事思正仲有寄','舒岳祥','宋','宋诗','song-poetry','','[]','相憐不相見，不見自情親。',48,'全唐诗/poet.song.227000.json','["相憐不相見，不見自情親。", "野水僧無影，斜陽樹半身。", "嬾蜂偷柏蜜，饑雀啄窗塵。", "吟就懷人杳，書成訪驛頻。"]'),
('6e58f634-e71e-469e-872b-8bac5c88e9b8','獨坐遣興','舒岳祥','宋','宋诗','song-poetry','','[]','昏眼迷煙雨，修眉隠樹林。',48,'全唐诗/poet.song.227000.json','["昏眼迷煙雨，修眉隠樹林。", "杜鵑知夜半，蟋蟀俟秋音。", "靜悟平生事，閒思萬古心。", "嗟跎七十五，既往莫追尋。"]'),
('e91e9f99-5a01-4c3c-bd72-cf4e5b8e9687','十月初七日山中感興','舒岳祥','宋','宋诗','song-poetry','','[]','日暮空歸里，時艱未到家。',48,'全唐诗/poet.song.227000.json','["日暮空歸里，時艱未到家。", "稼收遷野鼠，柿熟亂慈鴉。", "冬煖生蘆笋，人閒對菊花。", "亡書何處補，無用自咨嗟。"]'),
('f88a7a4a-f8cc-4328-9396-f33cc7195ec8','二月初二日山中感興','舒岳祥','宋','宋诗','song-poetry','','[]','山合風多急，江寒潮易殘。',48,'全唐诗/poet.song.227000.json','["山合風多急，江寒潮易殘。", "艱虞渾未息，漂泊若爲安。", "脫葉投沙井，吹花點石闌。", "故園歸夢切，雪潦幾時乾。"]'),
('7ecdf77a-7590-4bf8-8a44-7d202e4517ff','贈星翁','舒岳祥','宋','宋诗','song-poetry','','[]','星翁言我壽，更壽復何求。',48,'全唐诗/poet.song.227000.json','["星翁言我壽，更壽復何求。", "老病花生眼，愁吟雪滿頭。", "髀消經萬險，面皺積千憂。", "十載不看鏡，今朝見自羞。"]'),
('7e587644-39b0-4cc4-a7c1-50a5eedca6a1','春日與正仲坐山齋余隠几就睡既覺而正仲端坐誦書未已此意似更勝淵明卿且去之語也','舒岳祥','宋','宋诗','song-poetry','','[]','坐睡吾知味，觀書客更嘉。',48,'全唐诗/poet.song.227000.json','["坐睡吾知味，觀書客更嘉。", "柴門桑舊曲，石逕筍新斜。", "花飽蜂歸國，巢成燕著家。", "此中真有意，高柳兩三鴉。"]'),
('364ecb65-479d-4bdc-93a3-e6db852cadad','晝睡','舒岳祥','宋','宋诗','song-poetry','','[]','生平慕睡鄉，逃暑最爲良。',48,'全唐诗/poet.song.227000.json','["生平慕睡鄉，逃暑最爲良。", "渴愛煎茶響，饑聞煮粥香。", "百年依白社，一枕熟黄粱。", "童嬾呼難動，貪眠到夕陽。"]'),
('b669d44b-9b8f-4c86-8ba4-3d49b4f44f24','別銀瓶','舒岳祥','宋','宋诗','song-poetry','','[]','年凶人賣子，吾亦賣銀瓶。',48,'全唐诗/poet.song.227000.json','["年凶人賣子，吾亦賣銀瓶。", "送老無留物，因貧總割情。", "捐軀資我飽，覆斗餞君行。", "正是花香日，憑誰細細傾。"]'),
('22b30a2e-930a-409d-a594-28928c895078','臨水送將歸','舒岳祥','宋','宋诗','song-poetry','','[]','落葉秋江外，孤鐙遠樹中。',48,'全唐诗/poet.song.227000.json','["落葉秋江外，孤鐙遠樹中。", "片帆天上下，明月水西東。", "岐渚潮來白，晴霞暝更紅。", "一尊臨水驛，莫忘寄詩筒。"]'),
('9e648488-1e8d-4ad9-a91e-34582d3cb635','送俞宜民歸馬耳峰','舒岳祥','宋','宋诗','song-poetry','','[]','晴雪集林薄，朝陽熙隴苗。',48,'全唐诗/poet.song.227000.json','["晴雪集林薄，朝陽熙隴苗。", "青天堪數雁，白路自通樵。", "愁我未歸客，別君還過橋。", "何時燒短燭，軟語更終宵。"]'),
('5e01b4ea-7934-4376-b145-d8f8b0c311b3','十月初三日追記丙子歲以此日風雪中度平坑嶺入馬耳峰','舒岳祥','宋','宋诗','song-poetry','','[]','歲窮常鮮裕，人老更多悲。',48,'全唐诗/poet.song.227000.json','["歲窮常鮮裕，人老更多悲。", "白日無閒客，青山有了時。", "乾坤馬跡滿，風雨鶴巢危。", "去歲來坑嶺，移家度嶮巇。"]'),
('57387f5c-f175-4c5e-b0d3-eaf5b568f92c','古漁父詞二首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','烟雨一葉小，江湖大厦寬。',48,'全唐诗/poet.song.227000.json','["烟雨一葉小，江湖大厦寬。", "全家足風月，高枕恣波瀾。", "白雪披蓑立，青山揭笠看。", "莫將文叔事，溷我釣魚竿。"]'),
('773a7f8b-b9b5-42d4-80d3-69c531859cfc','古漁父詞二首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','是店皆賒酒，無家只有船。',48,'全唐诗/poet.song.227000.json','["是店皆賒酒，無家只有船。", "燒魚岩下火，吹笛水中天。", "楓葉霜鋪地，蘆花月滿川。", "風波何處靜，收釣即安眠。"]'),
('1bae8a81-23f6-4a6b-beca-0e5f8f6973ac','衰至和王達善','舒岳祥','宋','宋诗','song-poetry','','[]','衰來知已漸，老去不容遲。',48,'全唐诗/poet.song.227000.json','["衰來知已漸，老去不容遲。", "居長常先導，徐行且遠期。", "相看飄鶴髮，久坐綻烏皮。", "百歲休嫌短，修名千載垂。"]'),
('cd107bdc-cc4f-4dd0-9983-1c7fb07f5b8b','詠赬桐花','舒岳祥','宋','宋诗','song-poetry','','[]','朱草文明瑞，茲花上品朱。',48,'全唐诗/poet.song.227000.json','["朱草文明瑞，茲花上品朱。", "巧瑳紅象珥，闊製紫雲襦。", "麗奪炎精盛，名霑御賜殊。", "且貪顔色好，鶴頂似他無。"]'),
('69a6bbd1-6665-4854-80e1-014fef50d901','因黄甘人便問訊帥初','舒岳祥','宋','宋诗','song-poetry','','[]','茇舍干戈後，班荆薦莽餘。',48,'全唐诗/poet.song.227000.json','["茇舍干戈後，班荆薦莽餘。", "何人騎有鶴，顧我食無魚。", "孤憤向誰說，倦游休上書。", "時時問甘嶺，戴子近何如。"]'),
('e5e12d75-b68b-43db-8c38-40f49c2fd497','七月初四日賦紫薇花','舒岳祥','宋','宋诗','song-poetry','','[]','蹙羅紅線緊，鎔蠟粉鬚黄。',48,'全唐诗/poet.song.227000.json','["蹙羅紅線緊，鎔蠟粉鬚黄。", "野寺花開日，平疇稻熟香。", "曾陪紅藥省，相對紫薇郎。", "尚憶絲綸閤，新秋雨露凉。"]'),
('308a9baa-748f-43c7-9778-a9e516c5968f','謝劉文伯惠好翁牋','舒岳祥','宋','宋诗','song-poetry','','[]','春膏誇瑩浄，雲母鬭輕明。',48,'全唐诗/poet.song.227000.json','["春膏誇瑩浄，雲母鬭輕明。", "吾子誠不俗，老夫安用名。", "雖非時態尚，猶見故人情。", "雅興因君動，新吟憑几成。"]'),
('0f4e1892-d5fb-4497-aa86-d23a9ac05a56','秋日書事貽潘少白','舒岳祥','宋','宋诗','song-poetry','','[]','樹色已非昨，蟲聲不忍聞。',48,'全唐诗/poet.song.227000.json','["樹色已非昨，蟲聲不忍聞。", "亂鴉投急景，老樹淰長雲。", "百頃青黄半，一村晴雨分。", "憑闌新得句，書贈特山君。"]'),
('be47af9a-b11a-4a2b-b42b-ed8f4e50a599','貽正仲','舒岳祥','宋','宋诗','song-poetry','','[]','月生鯨海上，人在鴈蒼中。',48,'全唐诗/poet.song.227000.json','["月生鯨海上，人在鴈蒼中。", "一巘環村轉，雙溪到海同。", "百年能幾見，七十有三翁。", "爲此當心惻，詩成走遞筒。"]'),
('348d6bd4-5f96-4a86-b248-7f1d751cf164','貽山甫','舒岳祥','宋','宋诗','song-poetry','','[]','多病空餘老，勞生爲苦思。',48,'全唐诗/poet.song.227000.json','["多病空餘老，勞生爲苦思。", "偶然新得句，長是不眠時。", "鼠攪歉無肉，傭逃怨食糜。", "此懷誰可訴，只恐則山知。"]'),
('4ee37321-83df-4454-b9d5-fd0cb2e98b6e','梅所將別夜坐敘懷','舒岳祥','宋','宋诗','song-poetry','','[]','相見豈無期，前年亦此時。',48,'全唐诗/poet.song.227000.json','["相見豈無期，前年亦此時。", "青山吾有約，白髮子能醫。", "石室誰看鼎，巖泉似散絲。", "老人偏重別，去路渺相思。"]'),
('b0eadf4e-6b68-4178-929f-ae01e323bdd0','去春帥初嘗約爲榆林遊欲烹羊釀酒爲小孟嘗既而僕歸鳳棲後帥初亦往西浙遂不果今帥初已歸當踐前言但同游之客達善已下世矣因黄甘便作詩以敘其懷','舒岳祥','宋','宋诗','song-poetry','','[]','戴子遊西浙，藕花香滿船。',48,'全唐诗/poet.song.227000.json','["戴子遊西浙，藕花香滿船。", "因思今日日，又是去年年。", "楊果珍閩荔，榆林下剡川。", "烹羊曾有約，已失碧桃仙。"]'),
('f3abf225-b214-453f-9cb5-cde9cc7746a3','記夢  其一','舒岳祥','宋','宋诗','song-poetry','','[]','春夢是耶非，終慚戀祿微。',48,'全唐诗/poet.song.227000.json','["春夢是耶非，終慚戀祿微。", "整冠騎馬出，欹枕聽鷄回。", "食蘗風霜入，還丹志願違。", "未能忘習氣，安得寸心灰。"]'),
('d2c10e83-05c8-4470-953a-a972bfa13f09','記夢  其二','舒岳祥','宋','宋诗','song-poetry','','[]','梅花清入夢，詩骨定非常。',48,'全唐诗/poet.song.227000.json','["梅花清入夢，詩骨定非常。", "半樹原遮蘚，無風也自香。", "籃輿衝暮雪，茅舍带晨霜。", "傍竹依松處，無心肯向陽。"]'),
('9410bf3e-509f-46c1-a242-38736fd37d29','八月初三日五更夢覺追記','舒岳祥','宋','宋诗','song-poetry','','[]','林下青衫卸，尊前白髮欹。',48,'全唐诗/poet.song.227000.json','["林下青衫卸，尊前白髮欹。", "少年行樂事，暮景感傷時。", "鍊藥嫌長嬾，觀書悔已遲。", "惜花心性在，時復一吟詩。"]'),
('1f492f54-4fd3-4dba-9563-aaa74c454616','夢回','舒岳祥','宋','宋诗','song-poetry','','[]','月上芙蓉浦，船依杜若洲。',48,'全唐诗/poet.song.227000.json','["月上芙蓉浦，船依杜若洲。", "歲行人冉冉，川永夢悠悠。", "天地回青眼，江山養白頭。", "老生如朽木，安識有悲秋。"]'),
('f0912436-4584-4ba6-8e46-aa992ff9e32f','題存思庵壁','舒岳祥','宋','宋诗','song-poetry','','[]','香飯炊魚白，新醅擘蟹黄。',48,'全唐诗/poet.song.227000.json','["香飯炊魚白，新醅擘蟹黄。", "秋風元不惡，鄉思自難忘。", "田水閑無用，山雲薄有光。", "篆畦消息好，一路木樨香。"]'),
('16e14487-3178-4bed-aaf7-1a1e96093f34','巾山題客舍壁','舒岳祥','宋','宋诗','song-poetry','','[]','曉行風露清，夾徑草蟲鳴。',48,'全唐诗/poet.song.227000.json','["曉行風露清，夾徑草蟲鳴。", "虎近常行市，鷄啼早出城。", "路長終是到，世險自難平。", "學得王陽術，黄金可立成。"]'),
('85bac825-ddee-4666-bdb8-5f0a901e4ca3','四月初四日正仲子堂可大及梅所周鍊師會耕養堂','舒岳祥','宋','宋诗','song-poetry','','[]','白月一家好，青山四坐迎。',48,'全唐诗/poet.song.227000.json','["白月一家好，青山四坐迎。", "短筇看虎跡，高枕聽蛙聲。", "草具枇杷足，瓜廬熠燿行。", "相逢總佳士，更喜著彌明。"]'),
('006c16c9-3929-464d-812f-60e9e4965b50','含笑花','舒岳祥','宋','宋诗','song-poetry','','[]','半面羞藏袂，回頭嬾向人。',48,'全唐诗/poet.song.227000.json','["半面羞藏袂，回頭嬾向人。", "清凉生夜氣，冷淡見天真。", "此物慳開口，他花怯效顰。", "莫嫌容易落，笑罷總成塵。"]'),
('36e338ff-a2e9-410a-a6b1-4c57dde94ca5','詠竹拂子謝潘可大','舒岳祥','宋','宋诗','song-poetry','','[]','天封竹拂子，贈我意何勤。',60,'全唐诗/poet.song.227000.json','["天封竹拂子，贈我意何勤。", "白馬惟餘鬣，蒼蠅合避人。", "柄雙疑共産，身粉止留筋。", "可鄙椶毛賤，堪同麈尾珍。", "書齋添道氣，入室許嘉賓。"]'),
('f018e0df-1132-44d5-b97a-2c3973cf1515','壬辰正月胡子持孫平叔劉正仲諸友於鴈蒼建赤城先生祠賦唐律一十韻以紀其事','舒岳祥','宋','宋诗','song-poetry','','[]','句讀從朱老，經書本釋翁。',120,'全唐诗/poet.song.227000.json','["句讀從朱老，經書本釋翁。", "於藍青所出，他石玉堪攻。", "文啟吾鄉秀，心知百代崇。", "推尊非苟合，議論自難同。", "名節道鄉峻，詞章淮海雄。", "諸公交贊譽，此老定磨礲。", "舊祀儒宮側，新祠佛寺東。", "開山猶別子，傳鉢許宗風。", "俎豆干戈後，詩書煨燼中。", "千年期勿壞，印印此心通。"]'),
('109ad07a-bdf9-4c90-aa46-acd80442582f','評花','舒岳祥','宋','宋诗','song-poetry','','[]','我欣牟莟重，君喜菜花黄。',60,'全唐诗/poet.song.227000.json','["我欣牟莟重，君喜菜花黄。", "露浥虀菹味，風摇餠餌香。", "均爲資食品，乍可少羹湯。", "若論充冬蓄，何如續夏糧。", "書生有定祿，百罋亦須嘗。"]'),
('3b30dbfb-1be1-4d0e-bab0-afc2acc6160f','詠紫荆花','舒岳祥','宋','宋诗','song-poetry','','[]','自古惟聞棠棣詠，後人多感紫荆回。',64,'全唐诗/poet.song.227000.json','["自古惟聞棠棣詠，後人多感紫荆回。", "固知天理隨機觸，亦本詩人起興來。", "枯條誰綴桃花米，嫩蕊初挼撒酒媒。", "野老門前栽一樹，纔開桐角此花開。"]'),
('68068af1-38a4-4f38-8602-f0f947a5ef51','登樓','舒岳祥','宋','宋诗','song-poetry','','[]','千年日月藏丹鼎，萬里乾坤著白頭。',64,'全唐诗/poet.song.227000.json','["千年日月藏丹鼎，萬里乾坤著白頭。", "落木斷虹天渺渺，閒雲倦鳥日悠悠。", "開門碧海通諸島，極目青山是別州。", "我欲便騎黄鶴去，回頭還有故鄉愁。"]'),
('5c6d28e6-d14a-4464-ba57-28ab41089535','和正仲送達善歸錢塘韻','舒岳祥','宋','宋诗','song-poetry','','[]','二客論交自有時，篆畦相會不相期。',64,'全唐诗/poet.song.227000.json','["二客論交自有時，篆畦相會不相期。", "家如元亮貧更好，學抵申公老未衰。", "好詩甚似無聲畫，昏眼羞同沒字碑。", "買地近來聞闢圃，樊侯種桼未爲遲。"]'),
('499baf1a-980b-43bf-b3a7-18dc1b6d883f','水金蓮','舒岳祥','宋','宋诗','song-poetry','','[]','波心隠隠金椎出，只道馮夷先導來。',64,'全唐诗/poet.song.227000.json','["波心隠隠金椎出，只道馮夷先導來。", "笑口漸開黄玉罋，丹心初見小蓮胎。", "步花想見江妃佩，燒燭那從水殿回。", "傳記無聞今始著，莫嫌閑客少詩才。"]'),
('9f3ec013-7bdf-4440-a59b-999389f577e8','題巾山翠微','舒岳祥','宋','宋诗','song-poetry','','[]','逆水遊鯤去不迴，兩鬐插背尚崔嵬。',64,'全唐诗/poet.song.227000.json','["逆水遊鯤去不迴，兩鬐插背尚崔嵬。", "月將塔影和峯轉，風作潮花入寺來。", "星斗四垂雙闕壯，乾坤一覽八窗開。", "山僧高卧還知否，人世如今換劫灰。"]'),
('7abcf91f-613f-4300-be9e-1c37ba5ef677','梨花','舒岳祥','宋','宋诗','song-poetry','','[]','新葉輕柔宜與藉，芳心疎散不須茸。',64,'全唐诗/poet.song.227000.json','["新葉輕柔宜與藉，芳心疎散不須茸。", "象床骨冷驚春夢，霧閣神清怯曉風。", "雨裏多情危有淚，月中澄瑩望如空。", "清明寒食人何處，金谷昭陽事不同。"]'),
('9e1de52a-f0b2-48b1-b9ba-0a36d2912573','牽牛花','舒岳祥','宋','宋诗','song-poetry','','[]','卉中深碧斯爲最，繡蝶紅蜻宿近枝。',64,'全唐诗/poet.song.227000.json','["卉中深碧斯爲最，繡蝶紅蜻宿近枝。", "巧補疎籬陰漠漠，善緣高竹實纍纍。", "滿承秋露瑶杯瑩，半斂朝陽翠袖欹。", "入藥性寒君莫棄，良醫疎滯用隨宜。"]'),
('b463182b-9395-430a-a31d-70b99b78921b','石上種劍蒲其脊成矣非陶隠居所謂溪蓀者耶','舒岳祥','宋','宋诗','song-poetry','','[]','崑山片玉天生潤，鴈蕩移來手自栽。',64,'全唐诗/poet.song.227000.json','["崑山片玉天生潤，鴈蕩移來手自栽。", "禪客久親清少病，山童勤拂浄無埃。", "葉端灑灑通心露，根畔疎疎引水苔。", "必有事焉還勿助，此方端自養原來。"]'),
('754ccbcb-53b6-47d1-bf52-0c333ab831ad','菖蒲最難養置而弗省則弗滋勤勤拂拭則病矣余性甚嗜之往往不特人病苗而苗亦病人矣講求其法至備嘗爲之作譜書留南郭楊建處建攝令黄巖死於兵無從問矣端午日尋石菖蒲偶成一律','舒岳祥','宋','宋诗','song-poetry','','[]','多忘昏昏久廢書，閑來石上採菖蒲。',64,'全唐诗/poet.song.227000.json','["多忘昏昏久廢書，閑來石上採菖蒲。", "瘦鞭走石蛟龍窟，細葉穿苔虎豹鬚。", "陰洞容光明復晦，乳泉盈坎潤難枯。", "試拈九節風前嗅，已覺登仙不用扶。"]'),
('ff9bbe08-1937-4144-bb7e-af6e3978ecfa','六月十一日山窗散愁','舒岳祥','宋','宋诗','song-poetry','','[]','平生志大孔文舉，牢落依然不可羈。',64,'全唐诗/poet.song.227000.json','["平生志大孔文舉，牢落依然不可羈。", "茨闔小窗巢燕子，菰蒲新雨試鵝兒。", "胸襟大悶書不讀，口吻微吟人未知。", "安得一簑江海去，持螯作鱠卧鴟夷。"]'),
('856a8d03-a2bb-414d-a882-02e0756d1fef','賦眼昏','舒岳祥','宋','宋诗','song-poetry','','[]','不爲吟哦苦苦頻，老逢憂患損精神。',64,'全唐诗/poet.song.227000.json','["不爲吟哦苦苦頻，老逢憂患損精神。", "見人依約近方省，認字微茫久未真。", "漠漠江山渾水墨，冥冥草樹隔烟塵。", "何人解呪楊枝水，洗浄從前業障因。"]'),
('a3fc4854-4a12-45ef-82cc-40276182a639','次韻正仲秋晚感興','舒岳祥','宋','宋诗','song-poetry','','[]','舉頭無路見長安，十月江南有朔寒。',64,'全唐诗/poet.song.227000.json','["舉頭無路見長安，十月江南有朔寒。", "岩瀑飛來雲影濕，溪霜著處葉聲乾。", "相思一夜心先醉，欲話前冬鼻已酸。", "愛爾和詩添記事，愁來時解錦囊看。"]'),
('e30d4216-9e11-4c29-8192-f0672769387a','次韻答胡山甫避地述懷時予有結茅馬奧之意','舒岳祥','宋','宋诗','song-poetry','','[]','兔迒鹿町便爲家，不怕飛騰萬仞崖。',63,'全唐诗/poet.song.227000.json','["兔迒鹿町便爲家，不怕飛騰萬仞崖。", "此日披榛尋細路，他年買地卜幽齋。", "山風索索鳴林籜，野水洄洄汎柴。", "到此冥心齊物理，藉茅枕石氏無懷。"]'),
('7a166d21-38f0-4d1a-866a-b54c57c09811','有感','舒岳祥','宋','宋诗','song-poetry','','[]','風雨翛翛花事闌，餘寒迤邐麥秋天。',63,'全唐诗/poet.song.227000.json','["風雨翛翛花事闌，餘寒迤邐麥秋天。", "一春不見飛蝴蝶，幾夜初聞叫杜鵑。", "林外畫眉誰嫵媚，花繡眼自便翾。", "上林還有嚶鳴否，此日春歸一黯然。"]'),
('c33ccc0b-d64a-441c-800d-295b3190f33f','玉毬花','舒岳祥','宋','宋诗','song-poetry','','[]','花開壓逕枝堪挽，花落鋪階雪不飄。',64,'全唐诗/poet.song.227000.json','["花開壓逕枝堪挽，花落鋪階雪不飄。", "繭老蛾成投綠水，香乾蝶散離長條。", "滿地月明濃不掃，無人梅落怨難銷。", "老人別有心中事，愧爾投瓜乏報瑶。"]'),
('fdf98365-56aa-42c9-bb7b-5bd7b30495bf','問信','舒岳祥','宋','宋诗','song-poetry','','[]','鳳棲老子近何如，骨格崚嶒久病餘。',64,'全唐诗/poet.song.227000.json','["鳳棲老子近何如，骨格崚嶒久病餘。", "新酒得時招近局，小樓無事憶亡書。", "眼昏長道青燈暗，頭癢空將短髮梳。", "昨夜西風吹海動，磨刀準擬膾鱸魚。"]'),
('e5960d5b-ed43-4bce-b53a-10477f46e912','蜜蜂','舒岳祥','宋','宋诗','song-poetry','','[]','官課有嚴投急影，公衙未退沸繁聲。',64,'全唐诗/poet.song.227000.json','["官課有嚴投急影，公衙未退沸繁聲。", "香材聚斂千家圃，兵衛森凝百雉城。", "額上粉輕春尚早，股間金重日初晴。", "百蟲未敢梅花近，唯有渠來蹴雪英。"]'),
('f4b96efa-fc12-4cb2-9278-9222a8e5beda','題劉君英石屏','舒岳祥','宋','宋诗','song-poetry','','[]','天碑萬古閟嶙峋，自我來追此日新。',64,'全唐诗/poet.song.227000.json','["天碑萬古閟嶙峋，自我來追此日新。", "旭日小村鳩喚婦，寒霜疎木鴈來賓。", "路長橋斷誰家店，天遠舟行何處人。", "萬頃黄蘆秋色裏，是中著我坐垂緡。"]'),
('8df7c649-d01a-48e6-a37d-5facd000e74e','次韻記馬耳峰舊遊','舒岳祥','宋','宋诗','song-poetry','','[]','牙軸珠聯祕籥縢，曉窗開卷見詩朋。',64,'全唐诗/poet.song.227000.json','["牙軸珠聯祕籥縢，曉窗開卷見詩朋。", "曲渠荷葦鳴新雨，深院茶梅響落冰。", "山市雪晴邀試酒，溪橋月好近燒燈。", "玉泓不放花流出，聞有潜魚解避罾。"]'),
('69045660-dc63-4675-ad13-ea33b5e6d209','次韻酬正仲','舒岳祥','宋','宋诗','song-poetry','','[]','絲窠鼠跡鎖書縢，老去斯文屬友朋。',64,'全唐诗/poet.song.227000.json','["絲窠鼠跡鎖書縢，老去斯文屬友朋。", "凍芋共煨須熟火，寒葅對嚼欲生冰。", "山深有客傳詩藁，庵小無僧上佛燈。", "西去薌巖才半里，有蛟寒蟄得沉罾。"]'),
('d75a8445-6000-4921-8cde-e07557650034','周梅所携正仲再和借書韻見示次韻報之','舒岳祥','宋','宋诗','song-poetry','','[]','少日從軍輝綠縢，如今一室與雲朋。',64,'全唐诗/poet.song.227000.json','["少日從軍輝綠縢，如今一室與雲朋。", "低眉深閉車中婦，背俗空懸木上罾。", "何幸傳衣歸六祖，莫忘受記出燃燈。", "相期何止詩篇事，大節無虧誓飲冰。"]'),
('46841826-aa9d-4e86-a391-5aac8bb7e1ca','七月十五日競傳有鐵騎八百來屠寧海人懼罹仙居禍僦船入海從鴟夷子遊余在龍舒精舍事定而後聞之幸免奔竄深有羨于漁家之樂也作漁父一首','舒岳祥','宋','宋诗','song-poetry','','[]','年來避世羨漁郎，全載妻兒雲水鄉。',64,'全唐诗/poet.song.227000.json','["年來避世羨漁郎，全載妻兒雲水鄉。", "隔葦鳴榔分細火，带苔收網曬斜陽。", "一絲寒雨鱸腮紫，半箔歸潮蟹斗黄。", "欲逐鴟夷江海去，西風無奈稻花香。"]'),
('cf02e6f5-0df3-4de6-b753-54a6d0e9d2af','次和楊中齋讀閬風菊譜因覓本植齋前韻','舒岳祥','宋','宋诗','song-poetry','','[]','爲愛寒花晚節香，故栽松逕與茅堂。',64,'全唐诗/poet.song.227000.json','["爲愛寒花晚節香，故栽松逕與茅堂。", "壽思園綺眠商嶺，清想夷齊遁首陽。", "俗眼只貪金带紫，丹心惟喜御袍黄。", "先生遠覓陶潛種，急作山書寄孟光。"]'),
('472a2fc7-571b-4390-b050-a1ea335cb986','端午感懷','舒岳祥','宋','宋诗','song-poetry','','[]','曾飲昌陽七十三，老來大布當輕衫。',64,'全唐诗/poet.song.227000.json','["曾飲昌陽七十三，老來大布當輕衫。", "豫儲當採三年艾，緩計空尋六日蟾。", "楚俗舊時沉黍恨，唐宮此日賜衣霑。", "梔香滿院人如玉，尚想薰風半捲簾。"]'),
('dfdabfce-f870-4fc9-9a3b-f2794aedfa34','正仲入鄞敘懷送別二首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','遇事無心心自放，如今心事放尤難。',64,'全唐诗/poet.song.227000.json','["遇事無心心自放，如今心事放尤難。", "酒開愁緒湯澆雪，書潤枯腸火養丹。", "欹枕啼鴉分曉色，把杯歸鴈破春寒。", "君來訪我連朝雨，三日新晴理去鞍。"]'),
('10cb3272-10d5-4c57-97ea-02bfa1b28eeb','正仲入鄞敘懷送別二首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','此別未知長與短，一春風雨助凄然。',64,'全唐诗/poet.song.227000.json','["此別未知長與短，一春風雨助凄然。", "欲隨流水入城去，更繫扁舟話柳邊。", "芳草斜陽新住蝶，落花飛絮亂啼鵑。", "鴈蒼山好須回首，便見秋風在眼前。"]'),
('ebdd8739-12df-4932-9a58-64305e73a914','正仲有詩因次和再別','舒岳祥','宋','宋诗','song-poetry','','[]','好客分明爲我來，不嫌茅舍似鷄棲。',64,'全唐诗/poet.song.227000.json','["好客分明爲我來，不嫌茅舍似鷄棲。", "歸雲古樹如新畫，久雨蒼崖失舊題。", "別我此行正月盡，懷君老眼兩行啼。", "丈夫出處有常度，不爲黄金顔色低。"]'),
('6ab99ea1-9307-43c7-91bb-092379c5be56','夢笑','舒岳祥','宋','宋诗','song-poetry','','[]','過盡江山十萬鴻，梅花昨夜笑東風。',64,'全唐诗/poet.song.227000.json','["過盡江山十萬鴻，梅花昨夜笑東風。", "客行草樹綿綿外，夢覺烏鴉渺渺中。", "天道難知龜不信，人生有恨水無窮。", "今年厄閏有如此，萬事繩牀俯仰空。"]'),
('4d8409c1-1b76-4617-bf8f-7decb356595b','十二月初八日曉夢歸故園','舒岳祥','宋','宋诗','song-poetry','','[]','紅藤枕上到家園，花木蕭疎可若干。',64,'全唐诗/poet.song.227000.json','["紅藤枕上到家園，花木蕭疎可若干。", "陋巷夕陽人悄悄，舊牆新雨竹娟娟。", "數聲啼鳥春愁破，幾點殘星夜話闌。", "世事旋消還旋積，只留青史得千年。"]'),
('7341649e-65b8-463e-8e47-5f4490bd0cd5','野老','舒岳祥','宋','宋诗','song-poetry','','[]','野老巢居江上成，相親幽事遠浮名。',64,'全唐诗/poet.song.227000.json','["野老巢居江上成，相親幽事遠浮名。", "近村飲酒携孫去，遠寺尋蘭領犬行。", "麥老秧高關念慮，花開果熟有將迎。", "舊時風俗今誰有，見爾令人憶太平。"]'),
('8323b4e1-d930-4b60-8fb2-35ddad735580','有懷正仲還鴈峰詩','舒岳祥','宋','宋诗','song-poetry','','[]','松聲夜半如傾瀑，憶坐西齋共不眠。',64,'全唐诗/poet.song.227000.json','["松聲夜半如傾瀑，憶坐西齋共不眠。", "一鼓輕雷驚蟄後，細篩微雨落梅天。", "臨流欲渡還休笑，送客歸來始惘然。", "掩卷有誰知此意，一窗新綠待啼鵑。"]'),
('f74880ac-160e-48d6-be94-90966f2e74c8','戲述任翻詩句酬儲梅癯見和之作','舒岳祥','宋','宋诗','song-poetry','','[]','我愛巾山去復迴，城中平地起崔嵬。',64,'全唐诗/poet.song.227000.json','["我愛巾山去復迴，城中平地起崔嵬。", "前村清景何人占，絕頂新凉幾夜來。", "鶴起露翻松磴響，僧吟月上竹房開。", "任翻鍊得清新字，想見斯人百念灰。"]'),
('bf71ac38-e8d7-4811-9d56-1073cb48c3c4','四月初一日積雨新霽偶成','舒岳祥','宋','宋诗','song-poetry','','[]','渺然清興憶江湖，縛住此心安破廬。',64,'全唐诗/poet.song.227000.json','["渺然清興憶江湖，縛住此心安破廬。", "新綠池塘魚散子，落紅園徑鳥將雛。", "青梅成後少佳果，苦蕒出來無好蔬。", "老疾已艱登陟具，誰能爲作卧遊圖。"]'),
('369e659b-3d0e-433a-88ae-9728179e5c77','挽愛山李德夫','舒岳祥','宋','宋诗','song-poetry','','[]','不爲時新刺繡紋，鵠袍鶴髮自相親。',64,'全唐诗/poet.song.227000.json','["不爲時新刺繡紋，鵠袍鶴髮自相親。", "襄陽須有漢耆舊，彭澤終爲晉隠淪。", "往往名場躋後輩，時時相衮問斯人。", "如今天道平如槩，得失榮枯一幻塵。"]'),
('ee85e936-ee6a-46c5-8ff0-6323edaf4f38','即事','舒岳祥','宋','宋诗','song-poetry','','[]','麥熟南風挂衲畦，山禽快活曉來啼。',64,'全唐诗/poet.song.227000.json','["麥熟南風挂衲畦，山禽快活曉來啼。", "中分草色柴車路，半壓藤花石步谿。", "茅屋數家深避馬，竹林三里遠聞雞。", "荒村得句將誰贈，牆壁還隨即事題。"]'),
('f430ff23-cc0d-4dbc-afa4-2f224ffa5ef2','次韻和正仲南風','舒岳祥','宋','宋诗','song-poetry','','[]','有客披襟曰快哉，豈知元自舜絃來。',64,'全唐诗/poet.song.227000.json','["有客披襟曰快哉，豈知元自舜絃來。", "但令酷吏暑先去，足想蒼生慍自開。", "樹影縱橫流院落，荷香來往護池臺。", "公權只賦生凉句，不道閭閻正苦哀。"]'),
('336007c0-5c07-4b1c-b314-462793df6556','十月十八日聞鴈','舒岳祥','宋','宋诗','song-poetry','','[]','一聲空杳分千響，萬里荒凉月正明。',64,'全唐诗/poet.song.227000.json','["一聲空杳分千響，萬里荒凉月正明。", "共說江南舊來處，還思沙漠遠行程。", "如哀如怨知何事，相應相呼也有情。", "驚起蘆花不成夢，江城應是報嚴更。"]'),
('93a0ba2b-1802-4abc-adf4-35bb751ded0c','新歷未頒遺民感愴二首貽王達善曹季辯胡山甫戴帥初諸君皆避地客也  其一','舒岳祥','宋','宋诗','song-poetry','','[]','故國山河成斷絕，孤臣江海自飄零。',64,'全唐诗/poet.song.227000.json','["故國山河成斷絕，孤臣江海自飄零。", "窗間取月離離白，樹下窺天碎碎青。", "一鴈不來山驛靜，千梅欲動客愁醒。", "新來未賜王春歷，三尺堯階自有蓂。"]'),
('04c07470-9d74-46e4-9e58-a96c7952268f','新歷未頒遺民感愴二首貽王達善曹季辯胡山甫戴帥初諸君皆避地客也  其二','舒岳祥','宋','宋诗','song-poetry','','[]','寒氣著人身似病，世塗多故鬢如銀。',64,'全唐诗/poet.song.227000.json','["寒氣著人身似病，世塗多故鬢如銀。", "劫灰今信胡僧說，野燐多應戰鬼新。", "兵甲縱橫滿天地，衣冠顛倒走風塵。", "古今歷數歸仁義，河洛圖書屬聖神。"]'),
('1e7b651a-719a-4366-a7c4-d97644b8703d','自和前韻答達善  其一','舒岳祥','宋','宋诗','song-poetry','','[]','一字不輕王達善，忽看唾玉落鈎銀。',64,'全唐诗/poet.song.227000.json','["一字不輕王達善，忽看唾玉落鈎銀。", "共評中說躋尊魏，誰草玄經飾美新。", "大澤深山容避地，蓬萊弱水歎揚塵。", "與君同勘丹經訣，長飯青精養谷神。"]'),
('cfb1fe81-a789-44c0-ab48-7720749eecfd','自和前韻答達善  其二','舒岳祥','宋','宋诗','song-poetry','','[]','幽幽叢薄無塵到，渺渺菅茅有露零。',64,'全唐诗/poet.song.227000.json','["幽幽叢薄無塵到，渺渺菅茅有露零。", "松曲似腰元自直，潭澄如眼向誰青。", "千愁淟涊那能浣，萬事凄迷不欲醒。", "陰晦終逢開霽日，宮槐移影度階蓂。"]'),
('1c867d82-bbd0-48b8-88a8-f12a7569627f','再和前韻答達善季辯  其一','舒岳祥','宋','宋诗','song-poetry','','[]','屝屨送人征影遠，布裘知我涕痕零。',64,'全唐诗/poet.song.227000.json','["屝屨送人征影遠，布裘知我涕痕零。", "初愁凍雪無狐白，忽喜晴霄現卵青。", "欲向華山成穩睡，不禁楚澤自長醒。", "桃源自昔無秦歷，草木榮枯是瑞蓂。"]'),
('7c1bcb72-70a6-46c9-ae19-8514d119523c','再和前韻答達善季辯  其二','舒岳祥','宋','宋诗','song-poetry','','[]','北固漫誇城立鐵，錢塘休說浪翻銀。',64,'全唐诗/poet.song.227000.json','["北固漫誇城立鐵，錢塘休說浪翻銀。", "江山不改英雄泯，宇宙無窮戰伐新。", "過眼煙花空似錦，到頭富貴總成塵。", "舊時都下逢除夕，果食花餳祭竈神。"]'),
('29663dcd-3a17-49c6-a2a8-e042c38aeef6','綠陰','舒岳祥','宋','宋诗','song-poetry','','[]','野色蒙茸翠羽蓋，山光澹蕩碧油幢。',64,'全唐诗/poet.song.227000.json','["野色蒙茸翠羽蓋，山光澹蕩碧油幢。", "午煙時引煎茶竈，曉霧還霑讀易窗。", "隠映擲金鶑點點，分明藉玉鷺雙雙。", "莫疑蛇動杯中影，一笑開襟釣大江。"]'),
('2228b8b4-dcdb-492d-b5a7-b4ba47d5f133','詠鸂鶒','舒岳祥','宋','宋诗','song-poetry','','[]','雙雙遊戲水仙宮，著錦衣裳舞鏡空。',63,'全唐诗/poet.song.227000.json','["雙雙遊戲水仙宮，著錦衣裳舞鏡空。", "晴浴桃花紅影裏，雨眠蓮葉翠香中。", "文禽自是風情別，野鷺休將品格同。", "寄語虞羅須取，莫令失侶各西東。"]'),
('ecc8e34c-7fb4-465f-941a-34f27309fda7','謝御史王素行免里正之役','舒岳祥','宋','宋诗','song-poetry','','[]','繡衣御史當霄立，星次周流到上台。',64,'全唐诗/poet.song.227000.json','["繡衣御史當霄立，星次周流到上台。", "萬里東隅觀出日，十年幽蟄聽驚雷。", "頓令絕學知書貴，解使貪官覺賄災。", "恩及老生何以報，只將頌語獻行臺。"]'),
('529c5de9-0ff7-44c3-b206-3bcbfecb272c','感懷','舒岳祥','宋','宋诗','song-poetry','','[]','時事傳來日日新，信疑相半向誰詢。',64,'全唐诗/poet.song.227000.json','["時事傳來日日新，信疑相半向誰詢。", "一寒一暑成吾老，多雨多愁過却春。", "酒畔暫休無限事，花前難買自由身。", "百年猶有四十在，須見昇平作幸民。"]'),
('a6c59891-0788-44d9-9b17-4d3cf3ee3e43','對紅藥有感','舒岳祥','宋','宋诗','song-poetry','','[]','牡丹過後賣芍藥，清曉天街頻叫時。',64,'全唐诗/poet.song.227000.json','["牡丹過後賣芍藥，清曉天街頻叫時。", "傳世園林鶑自占，有名花草蝶先知。", "百年富貴一場夢，千古英雄幾局棋。", "世上興亡總如此，我今嘆老復嗟衰。"]'),
('1c37b441-d7a1-468e-9408-a1d3dff19b0c','百合','舒岳祥','宋','宋诗','song-poetry','','[]','收合千紅不上枝，綠莖丹萼稱施爲。',64,'全唐诗/poet.song.227000.json','["收合千紅不上枝，綠莖丹萼稱施爲。", "燈籠翠幹從高揭，火繖流蘇直下垂。", "文豹翻身騰綵仗，赤龍奮爪擺朱旗。", "莫疑衰老多誇語，漬蜜蒸根潤上池。"]'),
('e5411fa2-07f6-45c5-8544-a0254c349ad1','梔子花','舒岳祥','宋','宋诗','song-poetry','','[]','六出臺成一寸心，銀盤裏許貯金簪。',64,'全唐诗/poet.song.227000.json','["六出臺成一寸心，銀盤裏許貯金簪。", "月中不著蠅點璧，春過翻疑蝶滿林。", "陸地水光山院靜，炎天冰片石壇深。", "揚州只說瓊花好，漠漠風沙何處尋。"]'),
('21e78191-42b6-43f9-9415-61e33fc8f83e','和王達善碧桃詩','舒岳祥','宋','宋诗','song-poetry','','[]','石階無罅誰銜子，燒地成焦豈復芽。',64,'全唐诗/poet.song.227000.json','["石階無罅誰銜子，燒地成焦豈復芽。", "千歲分根染天水，單臺五出異朝霞。", "朝紳濟濟水蒼佩，仙袂盈盈萼綠華。", "作記不嫌人事晚，來年潤筆到山家。"]'),
('c3a03f69-b2db-4cea-b176-cef92b9ca847','同正仲賦赬桐彩蝶','舒岳祥','宋','宋诗','song-poetry','','[]','守著赬桐不爲香，翩如鳳子往來忙。',64,'全唐诗/poet.song.227000.json','["守著赬桐不爲香，翩如鳳子往來忙。", "徘徊最愛真紅色，摇曳偏垂五彩裳。", "寧號孟蟬隨鬢裊，莫爲鬼蝶幻身藏。", "惜花却似詩人性，日舞中間夜宿房。"]'),
('8eb394f8-6e02-4a4d-b1b1-9decad8c8f71','一葉','舒岳祥','宋','宋诗','song-poetry','','[]','欲排江渚千鴻陣，先舞庭皋一葉秋。',63,'全唐诗/poet.song.227000.json','["欲排江渚千鴻陣，先舞庭皋一葉秋。", "細路桑麻高下屋，平湖風雨往來舟。", "人間酒熟花爲客，夢覺殘燈月上樓。", "故舊凋零我老矣，少年安肯與同。"]'),
('17102932-db8f-4bbf-807d-3605f7bd9db3','枕上聞蛩有感','舒岳祥','宋','宋诗','song-poetry','','[]','桑鳥催耕緣底事，草蟲促織竟何成。',64,'全唐诗/poet.song.227000.json','["桑鳥催耕緣底事，草蟲促織竟何成。", "春風秋月祗垂淚，北斗南箕空得名。", "有客悲歌持筑擊，何時至治以韶鳴。", "吾儕吟詠還如此，哀樂不知何處生。"]'),
('414b4d35-37d1-4d48-8ae6-a91c7928e5ac','小閣省心','舒岳祥','宋','宋诗','song-poetry','','[]','避地逃名花裏居，春風何事轉桑樞。',64,'全唐诗/poet.song.227000.json','["避地逃名花裏居，春風何事轉桑樞。", "退藏小閣收心靜，閑下危階放步徐。", "身到衰時方學道，眼當昏處始觀書。", "一生日力悠悠度，總悔從前作計疎。"]'),
('e8b4f081-a566-4ba0-99f2-c0b0bfcfd5e4','詠蝶','舒岳祥','宋','宋诗','song-poetry','','[]','前身曾學昭儀舞，時樣工爲京兆眉。',64,'全唐诗/poet.song.227000.json','["前身曾學昭儀舞，時樣工爲京兆眉。", "揀盡好枝無可意，倦尋芳草歇多時。", "曉畦霧重狂須減，風檻花飛悞與隨。", "不但蛛絲深著避，更知紅袖亦堪疑。"]'),
('d9fce0b8-77ff-46a0-a472-81f686630210','春日即事','舒岳祥','宋','宋诗','song-poetry','','[]','燈夕花朝都已過，石泉槐火又將新。',64,'全唐诗/poet.song.227000.json','["燈夕花朝都已過，石泉槐火又將新。", "故鄉失業荆榛滿，客子長饑雨雪頻。", "底處桃源堪避世，何人橘裏得藏身。", "朝家細核丁黄籍，食指雖多無絹銀。"]'),
('23686bc5-d4af-4d8c-8450-2a52f453c389','次正仲賦桃花韻','舒岳祥','宋','宋诗','song-poetry','','[]','紅紅白白好容顔，笑日臨風錦裹山。',64,'全唐诗/poet.song.227000.json','["紅紅白白好容顔，笑日臨風錦裹山。", "且引綵雲來洞口，莫隨流水去人間。", "憶遊夢得嗟重到，訪異驎之擬不還。", "自是劉郎有緣會，一千年後重來攀。"]'),
('752765b8-3ccc-4024-8df5-748c10bdaf56','詠篆畦垂絲海棠','舒岳祥','宋','宋诗','song-poetry','','[]','奪胎錦带仍添麗，借面芙蓉特太癯。',64,'全唐诗/poet.song.227000.json','["奪胎錦带仍添麗，借面芙蓉特太癯。", "睡去不禁春露壓，醉來誰倩曉風扶。", "長條莫恨無新葉，纖瓣還能著細鬚。", "火急提魚花下飲，明朝千點亂青蕪。"]'),
('b295c216-1db0-47a5-b8e6-75dfcd4d0f53','正月十四日小園偶坐','舒岳祥','宋','宋诗','song-poetry','','[]','天地元從雪後新，開簾閑坐看回春。',64,'全唐诗/poet.song.227000.json','["天地元從雪後新，開簾閑坐看回春。", "謝公夢覺池生草，杜老羹成澗有芹。", "正是泰和嘉氣象，好調寒煖養精神。", "花前不著多憂客，百舌何妨報事頻。"]'),
('7708719e-2b2e-429d-a270-d72494274eb8','次韻答達善','舒岳祥','宋','宋诗','song-poetry','','[]','道不能鳴假物鳴，數篇詩見故人情。',64,'全唐诗/poet.song.227000.json','["道不能鳴假物鳴，數篇詩見故人情。", "重經喪亂成南北，多謝交遊訪死生。", "我始欲愁將老至，公須少忍待時平。", "古來毀棄連城璧，不恨沈埋百世英。"]'),
('f8c87006-8340-4d42-bcad-0a762b8e432c','試楊日新筆次韻答戴帥初','舒岳祥','宋','宋诗','song-poetry','','[]','聞爾又歸青嶂住，四明西畔越東頭。',64,'全唐诗/poet.song.227000.json','["聞爾又歸青嶂住，四明西畔越東頭。", "山當籬外偏環屋，水到門前總合流。", "得句苦遲難附置，懷人不見更登樓。", "掃除兒女相思話，好作閬風十日遊。"]'),
('ae198ca4-fefb-4115-bc8e-07e900830f2a','寄慈林交講師','舒岳祥','宋','宋诗','song-poetry','','[]','有意西林尋小隠，無田東瀼可隣家。',64,'全唐诗/poet.song.227000.json','["有意西林尋小隠，無田東瀼可隣家。", "聞師投謁不入巷，知我無人能點茶。", "山色一谿連雨色，雪花十里糝松花。", "秋聲正與公相似，相對忘言定不差。"]'),
('df3b5c48-148d-48be-89cd-8087c5096d4b','詠密囿花','舒岳祥','宋','宋诗','song-poetry','','[]','繁枝密密宜樊圃，以此能當密囿名。',64,'全唐诗/poet.song.227000.json','["繁枝密密宜樊圃，以此能當密囿名。", "不信嫩莖藏勁刺，試將纖手觸紅英。", "毛身秦女自正色，鳥爪麻姑無俗情。", "方朔竊桃何處入，只應列子御風行。"]'),
('78963541-ebea-4deb-bad2-a74698b84e2f','攬秋','舒岳祥','宋','宋诗','song-poetry','','[]','讀書瞪視眼花亂，力穡作勞足繭休。',64,'全唐诗/poet.song.227000.json','["讀書瞪視眼花亂，力穡作勞足繭休。", "尊俎風流容鴨脚，語言滋味許鴻頭。", "蘆根繫艇誰敲火，木末開扉獨攬秋。", "壯日貂裘無恙不，浩歌聊爲解牢愁。"]'),
('4e242c37-5a72-4fcf-a8a1-2f9498e111a1','詠佛見笑','舒岳祥','宋','宋诗','song-poetry','','[]','錦堂得此添春色，金屋從他著麗人。',64,'全唐诗/poet.song.227000.json','["錦堂得此添春色，金屋從他著麗人。", "老佛見之憐且笑，少年休以妄爲真。", "梵天寶相宜方駕，海島金沙合效顰。", "可是好花多刺手，漢濱游女禮防身。"]'),
('ba4ed76a-e9f7-4a94-9179-acb7c5dc478a','蓼花','舒岳祥','宋','宋诗','song-poetry','','[]','曾向江湖久釣遊，極憐紅蓼滿汀洲。',64,'全唐诗/poet.song.227000.json','["曾向江湖久釣遊，極憐紅蓼滿汀洲。", "清秋欲近先開眼，小雨纔鳴急點頭。", "翡翠忽來機事動，蜻蜓不定晚風遒。", "拒霜未放菡萏謝，點綴中間一段愁。"]'),
('df49b377-0774-4bbd-ad2c-528a8b7ae52c','約平叔高秋泛海','舒岳祥','宋','宋诗','song-poetry','','[]','乘桴欲看日生東，借子門前一席風。',64,'全唐诗/poet.song.227000.json','["乘桴欲看日生東，借子門前一席風。", "白石鑿餘雲補穴，青峯開處月浮宮。", "持螯斫鱠萬事足，踞殻食蜊千劫空。", "剩欲作詩招酒社，恐君戶小趣難同。"]'),
('93bac320-9ea6-4322-84bf-7eb62ce6cd49','冬至前一日小史自溪上獻梅四枝寘之書案奇奇怪怪爲賦長句志喜也','舒岳祥','宋','宋诗','song-poetry','','[]','中有黄金白玉姝，莫欺紅粒綴茱萸。',64,'全唐诗/poet.song.227000.json','["中有黄金白玉姝，莫欺紅粒綴茱萸。", "曉風吹面成冰腦，夜雪流脂結玉酥。", "凍蘂未期春鳥啄，寒香不上暖蜂鬚。", "一生欲壓孤山句，囊錦空垂氣浪麤。"]'),
('870fc633-e058-4b3a-9494-a41f72406acb','木芙蓉','舒岳祥','宋','宋诗','song-poetry','','[]','溪山瀟灑最宜秋，緩步何須百尺樓。',64,'全唐诗/poet.song.227000.json','["溪山瀟灑最宜秋，緩步何須百尺樓。", "亂後見花如故舊，老來得酒更風流。", "幽蓀暗折誰知處，好鳥一啼人舉頭。", "欲對黄花開口笑，茫然消息也堪愁。"]'),
('2350cd79-a848-46bd-b58b-204f774fd32e','贈敏求','舒岳祥','宋','宋诗','song-poetry','','[]','抄書滿架筆無塵，自是餐霞洞裏人。',64,'全唐诗/poet.song.227000.json','["抄書滿架筆無塵，自是餐霞洞裏人。", "性癖貪吟如好色，話終更僕尚留賓。", "愛花更縮栽蔬地，開徑還通指竹鄰。", "不是不貧貧得雅，如今金塢總輸貧。"]'),
('4226376a-01cd-4ef4-85fd-5ef898e63667','戲贈牛女','舒岳祥','宋','宋诗','song-poetry','','[]','擲果久憐潘岳好，投梭不放幼輿癡。',64,'全唐诗/poet.song.227000.json','["擲果久憐潘岳好，投梭不放幼輿癡。", "彩雲似扇羞郎面，新月如弓學婦眉。", "喜鵲成橋終有別，陽烏出海且教遲。", "如何自古占天者，不說經躔有動移。"]'),
('72811568-5352-43e2-add0-9a001053999e','三月二十三日效樂天體','舒岳祥','宋','宋诗','song-poetry','','[]','習習東風白苧裘，餘寒未盡滯清愁。',64,'全唐诗/poet.song.227000.json','["習習東風白苧裘，餘寒未盡滯清愁。", "柳疑楚舞腰偏細，鶑學吳音舌更柔。", "好景良辰千古在，騷人墨客幾時休。", "一年佳致惟春莫，可惜花飛人白頭。"]'),
('9fac2d73-6452-4c03-bbda-f4210d8c42ee','小酌送春','舒岳祥','宋','宋诗','song-poetry','','[]','春風元逐土牛來，欲去金錢買不回。',64,'全唐诗/poet.song.227000.json','["春風元逐土牛來，欲去金錢買不回。", "莫道鶑花拋白髮，且將蠶豆伴青梅。", "落花流水辭梁苑，芳草斜陽上楚臺。", "孝子不嫌閑寂坐，綠陰如屋兩三杯。"]'),
('9e865aaa-c94b-40b9-802d-c2a16c3e1cef','次韻答孫平叔感春之作  其一','舒岳祥','宋','宋诗','song-poetry','','[]','從教鑿石置官場，不怕滄溟地脈傷。',64,'全唐诗/poet.song.227000.json','["從教鑿石置官場，不怕滄溟地脈傷。", "薜荔斸開山鬼泣，莓苔迸出水精凉。", "東周以後一春夢，西晉于今幾夕陽。", "自有青天開豁處，高秋買棹泛蒼茫。"]'),
('0e0ea8a0-1b28-4f2c-a167-67bf20f3dece','次韻答孫平叔感春之作  其二','舒岳祥','宋','宋诗','song-poetry','','[]','五陵三輔少年場，往事歡娛總不傷。',64,'全唐诗/poet.song.227000.json','["五陵三輔少年場，往事歡娛總不傷。", "閲世鶑花見興廢，隨時蜂蝶有炎凉。", "原嘗館寂生春草，田竇門荒掩夕陽。", "漢殿唐宮亦如此，由來天道本茫茫。"]'),
('7696da63-de6f-4608-aa87-52974c7605e2','次韻答孫平叔感春之作  其三','舒岳祥','宋','宋诗','song-poetry','','[]','江湖處處尋春去，每到芳時醉不歸。',64,'全唐诗/poet.song.227000.json','["江湖處處尋春去，每到芳時醉不歸。", "簾幙生香花欲語，池塘細雨燕交飛。", "閒思此事真難得，或恐他生願不違。", "欲作三門終老計，買山囊罄值年饑。"]'),
('1015bc36-a55a-4285-8b62-5d0b9ca7e907','寄王真人','舒岳祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','象簡銀冠覲冕旒，一清沆瀣九天秋。',64,'全唐诗/poet.song.227000.json','["象簡銀冠覲冕旒，一清沆瀣九天秋。", "西湖處士梅花屋，太乙真人蓮葉舟。", "聞道遼東來白鶴，不知函谷度青牛。", "人間天上無拘束，且駕長螭賦遠遊。"]'),
('cd393586-6e82-4f8c-b6a0-6266a15bc29d','梅花二首遺正仲少見折贈之意','舒岳祥','宋','宋诗','song-poetry','','[]','晴暖不妨臨石瀨，清寒多是傍柴關。',64,'全唐诗/poet.song.227000.json','["晴暖不妨臨石瀨，清寒多是傍柴關。", "香鬚蜂咬應知苦，斜影僧眠得占閑。", "數點稀星枝上下，一痕殘雪樹中間。", "入冬冷落愁眉結，見爾鮮明故展顔。"]'),
('8170400b-940a-4192-8631-879e9e3d1655','三月十七日食櫻桃蠶豆知麥熟日至矣示家人爲我進一杯也','舒岳祥','宋','宋诗','song-poetry','','[]','清明已自斷百果，櫻豆從頭次第嘗。',64,'全唐诗/poet.song.227000.json','["清明已自斷百果，櫻豆從頭次第嘗。", "青山四面欲春晚，白髮千丈照溪長。", "偶然坐石雲離次，久不窺園竹亂行。", "甔石屢空惟食粥，平臯聞道麥鬚黄。"]'),
('38d9beb7-6d60-42c3-96a9-873704ca2710','郭似山道士寄惠竹筆兩束啟緘乃羊毫也作詩戲之','舒岳祥','宋','宋诗','song-poetry','','[]','似山惠我筍絲筆，乃是長鬚公子毫。',63,'全唐诗/poet.song.227000.json','["似山惠我筍絲筆，乃是長鬚公子毫。", "竹簡固應同祓滌，琅函寧肯近腥臊。", "若非月裏霜㕙，恐是仙家雲鹿毛。", "潤筆定須三百束，爲君滴露注莊騷。"]'),
('4fff3bc8-dd37-48f7-940b-425f3135b1ff','賦素馨花','舒岳祥','宋','宋诗','song-poetry','','[]','小蕊清香真有韻，柔條纖葉不勝春。',64,'全唐诗/poet.song.227000.json','["小蕊清香真有韻，柔條纖葉不勝春。", "承平時節移新主，離亂風塵見故人。", "淚重闌干添婀娜，香殘篤耨駐絪縕。", "舊恩深淺君自會，莫問誰家時與親。"]'),
('80827751-e3a0-437c-94bd-3e1bfba0f1aa','賦橘花次正仲韻','舒岳祥','宋','宋诗','song-poetry','','[]','璘娥琢月剪冰花，著葉團團更不斜。',64,'全唐诗/poet.song.227000.json','["璘娥琢月剪冰花，著葉團團更不斜。", "只把青葱爭玉樹，不將夭冶鬭金沙。", "吹香自滿騷人國，成實還宜野叟家。", "老我真成被花惱，尊前坐嘆復行嗟。"]'),
('19a1c866-86a8-421e-907c-b12ab5a99026','遊潘墺魏都冶墓菴','舒岳祥','宋','宋诗','song-poetry','','[]','弄日微陰駕筍輿，柴桑五子共携扶。',64,'全唐诗/poet.song.227000.json','["弄日微陰駕筍輿，柴桑五子共携扶。", "雲門鍾鼓先朝賜，丞相門庭近日殊。", "綠樹兩行溪貫串，青巒百摺路縈紆。", "惟餘守塚鷹窠在，採捕令嚴無牧芻。"]'),
('f61a3e09-50ae-49b6-a8ad-f1fcc6c221a1','螢','舒岳祥','宋','宋诗','song-poetry','','[]','熠熠孤光闔復開，黄金一點亦微哉。',64,'全唐诗/poet.song.227000.json','["熠熠孤光闔復開，黄金一點亦微哉。", "凌風欲作炎雲助，入屋翻疑夜雨來。", "本爲微明生腐草，誰知殘照落莓苔。", "暗飛只合藏形影，羅扇收來却是災。"]'),
('efc3150b-b3c9-44c8-8a4a-411e63fd0b9a','正仲過我一宿蓐食而行敘懷追餞之','舒岳祥','宋','宋诗','song-poetry','','[]','又見王師下海夷，書生筆硯自非宜。',64,'全唐诗/poet.song.227000.json','["又見王師下海夷，書生筆硯自非宜。", "風塵宇內成百戰，花塢山中自四時。", "故舊凋零今已矣，江山寂寞子何之。", "籃輿載雨怱怱去，一飯無因話別離。"]'),
('4652a2a7-f813-461a-b2ac-ebe57af3d72a','楊花','舒岳祥','宋','宋诗','song-poetry','','[]','斷茸冉冉青樓外，浮影悠悠紫陌間。',64,'全唐诗/poet.song.227000.json','["斷茸冉冉青樓外，浮影悠悠紫陌間。", "晴日暖風真得所，遊絲野馬與俱閒。", "舞經林苑鶑銜去，飛去簾櫳燕掠還。", "莫把蘆花來比擬，秋深客子更愁顔。"]'),
('b5081526-f0c5-42bf-aebf-0bce0af41e28','三月之朔邑庠請僕升講席說詩泮水正仲用前韻紀之因次其韻','舒岳祥','宋','宋诗','song-poetry','','[]','春服初成冠與童，聚觀王式一衰翁。',64,'全唐诗/poet.song.227000.json','["春服初成冠與童，聚觀王式一衰翁。", "圓冠方屨還吾道，續衽鈎邊見古風。", "投戈猶待漢符赤，藏壁不隨秦火紅。", "寧可短衣充博士，莫令城旦屬司空。"]'),
('c8f42076-7c61-4163-8914-f89ad69dfbb9','次和正仲詠荷花月露二景  其一','舒岳祥','宋','宋诗','song-poetry','','[]','天香夜氣兩交加，艇子欹眠宿妙花。',64,'全唐诗/poet.song.227000.json','["天香夜氣兩交加，艇子欹眠宿妙花。", "誰展銀泥鋪水色，更調汞粉拂霜華。", "即空是色非二景，有象無聲別一家。", "此際含羞花正斂，明朝一片落驚嗟。"]'),
('1e1fcf38-200c-4769-9741-f99d425b22a3','次和正仲詠荷花月露二景  其二','舒岳祥','宋','宋诗','song-poetry','','[]','風清月白天垂碧，有恨如羞半歛花。',64,'全唐诗/poet.song.227000.json','["風清月白天垂碧，有恨如羞半歛花。", "紅袖粉痕晨带濕，翠盤珠影夜生華。", "楊枝灑潤菩提雨，薇水流香仙子家。", "幾度曉風過麴院，七年不見使人嗟。"]'),
('cccbea89-e467-4178-9360-1440bf2ee313','謝彌大惠萬歲藤杖','舒岳祥','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','青山節節皆龍冢，蛻骨崚嶒幻此藤。',64,'全唐诗/poet.song.227000.json','["青山節節皆龍冢，蛻骨崚嶒幻此藤。", "栗楖生來呼上座，獼猴拾得奉胡僧。", "子能致此鬚牙具，我試携之氣力增。", "欲上泰山賓出日，便須著脚共猱升。"]'),
('e21b4cee-7928-4395-8f86-1e359d4f29d7','又詠萬歲藤杖酬正仲併謝元惠主人潘少白','舒岳祥','宋','宋诗','song-poetry','','[]','不求海上千金藥，且覓山中萬歲藤。',64,'全唐诗/poet.song.227000.json','["不求海上千金藥，且覓山中萬歲藤。", "潘子入林親揀得，舒翁履險力扶能。", "乞君瘦硬蒼龍節，伴我清羸病鶴形。", "莫向潭邊令照影，忽然變化老誰憑。"]'),
('d6dfbd7d-b99f-498e-99c0-d26cef91d367','正仲訪余棠溪帥初來會正仲時余欲歸閬風未能决書呈三友','舒岳祥','宋','宋诗','song-poetry','','[]','晴雲高舉雪雲低，日日占天候不齊。',64,'全唐诗/poet.song.227000.json','["晴雲高舉雪雲低，日日占天候不齊。", "菘白僵成茭白筍，麥黄淹作韭黄虀。", "江湖吐日黿晞甲，山路成泥獸印蹄。", "老去欲休官不許，夜來魂夢舊山谿。"]'),
('5f07b081-fa1c-4415-a45e-4e14749195f8','暮春書懷寄董正翁寺正','舒岳祥','宋','宋诗','song-poetry','','[]','尋春曾作太平民，說著花時淚濕巾。',64,'全唐诗/poet.song.227000.json','["尋春曾作太平民，說著花時淚濕巾。", "風雨差池桃杏過，山林牢落鳥烏親。", "書中悶見傷心事，畫裏思逢避世人。", "霄漢故交今隠遁，有山堪買願爲鄰。"]'),
('560429d6-e6b2-4ec9-96e7-7d122edd15b0','賦水仙花','舒岳祥','宋','宋诗','song-poetry','','[]','冷淡不生桃李徑，只將素艷伴紅梅。',64,'全唐诗/poet.song.227000.json','["冷淡不生桃李徑，只將素艷伴紅梅。", "冰清玉潤檀心炯，日暮天寒翠袖迴。", "似倚蘭舟并桂楫，羞稱金盞共銀臺。", "誰將六出天花種，移向人間妙奪胎。"]'),
('6e9f3545-8d62-45d6-b674-6b8d9b927e16','同正仲賦鳳仙花','舒岳祥','宋','宋诗','song-poetry','','[]','本愛真紅一種奇，後來紫白自繁滋。',64,'全唐诗/poet.song.227000.json','["本愛真紅一種奇，後來紫白自繁滋。", "青冠輕舉真仙子，彩羽來儀瑞鳳兒。", "石竹通家分異樣，園葵附譜亦多姿。", "莫嫌性急難攖觸，我以爲規勝佩韋。"]'),
('ef0312b3-f660-4980-9b19-69bcada4df78','七夕呈正仲','舒岳祥','宋','宋诗','song-poetry','','[]','金風璧月清凉境，紅蓼青蘋迤邐秋。',64,'全唐诗/poet.song.227000.json','["金風璧月清凉境，紅蓼青蘋迤邐秋。", "漠漠蛛絲穿露重，微微螢火學星流。", "何年才子誣躔象，幾度佳人候女牛。", "一局爛柯經數代，人間隔歲未悠悠。"]'),
('3affa50f-9a81-4040-b1e1-057271731ef3','剪春羅','舒岳祥','宋','宋诗','song-poetry','','[]','誰裁婺女輕羅段，我有并州快剪刀。',64,'全唐诗/poet.song.227000.json','["誰裁婺女輕羅段，我有并州快剪刀。", "色似山丹殊少肉，形如石竹亦多毫。", "臙脂初褪黄先露，蝴蝶才成翅未高。", "欲向小窗成扇面，世無陶縝倩誰描。"]'),
('0f7afa0b-aae0-4cae-af5f-68879f15d433','又戲和正仲賦剪春羅','舒岳祥','宋','宋诗','song-poetry','','[]','昔時剪綵聊爲假，今見裁羅却是真。',64,'全唐诗/poet.song.227000.json','["昔時剪綵聊爲假，今見裁羅却是真。", "葉底綵窠本機戶，花邊線草是鍼人。", "獨客書齋思拆補，靜姝繡閣學縫紉。", "晚花開遍幽畦草，石竹山丹及麗春。"]'),
('7987d3d5-687b-47a0-a28f-4675ee73ae50','示兒','舒岳祥','宋','宋诗','song-poetry','','[]','蛻蝶將舒魄尚凝，如癡如夢復如醒。',64,'全唐诗/poet.song.227000.json','["蛻蝶將舒魄尚凝，如癡如夢復如醒。", "風吹海水飛成雪，月入梅花膠作冰。", "有口勿言唯飲酒，無家可著不如僧。", "眼前喜見行王政，已有添丁充踐更。"]'),
('7798ae84-ccbe-4f1a-9e39-63d8f8238a0d','九日與正仲子堂君英舉酒于篆畦璋萬二姪男庭堅仲容仲堪叔獻季臨與焉','舒岳祥','宋','宋诗','song-poetry','','[]','登高勝具何人有，重九佳名此日臨。',64,'全唐诗/poet.song.227000.json','["登高勝具何人有，重九佳名此日臨。", "老眼已昏空悵望，壯心猶在惜銷沉。", "天真呈露青山瘦，世故流離白髮侵。", "漢水沈碑今出否，古來賢達共沾襟。"]'),
('45e63103-c4f3-4fb7-9c77-2aedf7beded9','九日觀萬堂小酌懷正仲及梅所鍊師','舒岳祥','宋','宋诗','song-poetry','','[]','極目冥鴻顥氣初，人生快意食鱸魚。',64,'全唐诗/poet.song.227000.json','["極目冥鴻顥氣初，人生快意食鱸魚。", "剪來萸菊觴新酒，麾去蚊蠅俯舊書。", "騷雅劉郎今健否，清修周老近何如。", "篆畦雨裏青蒿長，寂寞無人過草廬。"]'),
('ebcc9fdd-8468-4006-93fc-a90faeb89707','新凉','舒岳祥','宋','宋诗','song-poetry','','[]','慚愧秋風慰白鬚，夜凉早已入籧篨。',64,'全唐诗/poet.song.227000.json','["慚愧秋風慰白鬚，夜凉早已入籧篨。", "白蓮社裏幾人在，黄菊尊前萬事疏。", "老婦自欣瓶有粟，兒童休恨食無魚。", "故園紅桂通消息，定有新詩一起予。"]'),
('31731caa-daf6-43af-9950-8cd545ad77dd','六月甲申雨後凉氣如秋','舒岳祥','宋','宋诗','song-poetry','','[]','蘋花消息入踈櫺，六月何曾有此清。',64,'全唐诗/poet.song.227000.json','["蘋花消息入踈櫺，六月何曾有此清。", "晚飯出門新雨過，深衣臨水早蟬鳴。", "月西人影如鴻影，風裏松聲带鶴聲。", "此意寂寥誰會得，沉沉默默自含情。"]'),
('20f2648e-a63f-4a8d-a4dd-aa2c466b0f9d','鬢邊嬌','舒岳祥','宋','宋诗','song-poetry','','[]','天工施巧亦無窮，開盡枝頭入草中。',64,'全唐诗/poet.song.227000.json','["天工施巧亦無窮，開盡枝頭入草中。", "先借豆花來作樣，旋將槐蘂綴成叢。", "淡勻弄色薔薇紫，深蒂含胎豆蔻紅。", "可是夏英無勝汝，鬢雲一朵愛瓏鬆。"]'),
('87219537-8ae2-4a9f-b7e2-ec51ef833fb2','免役後登山園小飲書懷','舒岳祥','宋','宋诗','song-poetry','','[]','深憑歌酒送流紅，岸幘披襟萬頃風。',64,'全唐诗/poet.song.227000.json','["深憑歌酒送流紅，岸幘披襟萬頃風。", "一斗白鷗蒼靄上，數篇黄鳥綠陰中。", "不辭老疾餘年在，已付歡哀萬事空。", "新荷使家除戶役，安居從此異征鴻。"]'),
('9e81a6f7-1466-4602-95eb-9bd31880eafe','辛巳自壽','舒岳祥','宋','宋诗','song-poetry','','[]','六十三翁自荷天，亂餘骨肉幾家全。',64,'全唐诗/poet.song.227000.json','["六十三翁自荷天，亂餘骨肉幾家全。", "不材幸度龍蛇歲，多病休催犬馬年。", "我老思親空有恨，人生不飲更堪憐。", "差池九子森童冠，屢舞交酬且眼前。"]'),
('7e4646f2-7fec-46c1-b531-015341afb74b','詠芭蕉','舒岳祥','宋','宋诗','song-poetry','','[]','虛明旱藕千絲透，清泠寒泉百脈來。',64,'全唐诗/poet.song.227000.json','["虛明旱藕千絲透，清泠寒泉百脈來。", "綠燭怕燒先自障，青牋欲寄倩誰裁。", "正憐夜雨敲篷響，只恐秋風裂扇開。", "月下徘徊清影動，却疑翠鳳下瑶臺。"]'),
('7c76b166-a0b0-46c7-ad68-061cb5f73f98','詩訣','舒岳祥','宋','宋诗','song-poetry','','[]','蕢桴土鼓爲聲始，天球河圖非琢工。',64,'全唐诗/poet.song.227000.json','["蕢桴土鼓爲聲始，天球河圖非琢工。", "欲自柳州參靖節，將邀東野適盧仝。", "平原駿馬開黄霧，下水輕舟遇快風。", "歷歷瑶琴怨遥夜，泠泠玉佩度秋空。"]'),
('9180f659-ca59-431b-a95f-83a4239dfd05','寒食書懷二首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','曉寒颯颯侵駝褐，山色盈盈入酒杯。',64,'全唐诗/poet.song.227000.json','["曉寒颯颯侵駝褐，山色盈盈入酒杯。", "人物風流隨逝水，故都文憲沒蒼苔。", "黄鸝杜宇怱忙過，盧橘楊梅次第來。", "氣運總隨時節變，人逢寒食自須哀。"]'),
('d116f193-d6dc-4c70-bc4a-602bdb756f05','寒食書懷二首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','天機妙處莫形容，難把丹青寫太空。',64,'全唐诗/poet.song.227000.json','["天機妙處莫形容，難把丹青寫太空。", "萬古碧山留色在，千江皓月此心同。", "烏紗燕子開門雨，白髮楊妃掠面風。", "欲問清明休檢歷，杜鵑啼血滴巖紅。"]'),
('c26d56c3-bf56-43e6-83f1-d8a28d83af37','和正仲月季花','舒岳祥','宋','宋诗','song-poetry','','[]','風流天下真難似，惜向籬邊砌下栽。',64,'全唐诗/poet.song.227000.json','["風流天下真難似，惜向籬邊砌下栽。", "依舊風情三月在，斬新花葉四時開。", "莫嫌綠刺傷人手，自有妍姿勸客杯。", "不擬折來輕落去，坐看顔色總塵埃。"]'),
('aa3e2f60-3613-4936-b641-8d0effac7ec0','詠凌霄花','舒岳祥','宋','宋诗','song-poetry','','[]','凌空千尺走龍蛇，隠映柴門野老家。',64,'全唐诗/poet.song.227000.json','["凌空千尺走龍蛇，隠映柴門野老家。", "拚把長纓縻落月，亂飄丹粉染晴霞。", "猿猴升慣能收葯，蝴蝶低飛不到花。", "最愛豹林种處士，紫英香裏岸烏紗。"]'),
('b66114de-452e-4385-af91-424ef0d3194d','卜居','舒岳祥','宋','宋诗','song-poetry','','[]','丹青不用畫吾廬，小小茅茨住近湖。',64,'全唐诗/poet.song.227000.json','["丹青不用畫吾廬，小小茅茨住近湖。", "欲探春風先插柳，要看雪景更栽蘆。", "野船摇處沙成疊，海鴈眠來草似鋪。", "粧點箇中新景致，藤冠布褐老癯儒。"]'),
('37dc1b2c-06b1-4cdd-b0d1-f236decf2c63','田家紀事','舒岳祥','宋','宋诗','song-poetry','','[]','濛濛土霧連三日，父老傳經十七年。',64,'全唐诗/poet.song.227000.json','["濛濛土霧連三日，父老傳經十七年。", "蠶月人家多忌諱，麥秋時候好安眠。", "桑鳩逐婦應嫌雨，社燕依人不避烟。", "短策綠陰新似沃，頃筐朱實寫來圓。"]'),
('58d56c36-f94a-4a11-9459-5446864053e1','山齋觀物','舒岳祥','宋','宋诗','song-poetry','','[]','自古詩人皆格物，山齋觀物意如何。',64,'全唐诗/poet.song.227000.json','["自古詩人皆格物，山齋觀物意如何。", "額塗金粉蜂歸穴，腹吐銀絲蟢布羅。", "雞母載雛行啄黍，雀羣欺燕坐爭窠。", "紛紛擾擾爲形役，閒補涪翁演雅歌。"]'),
('56d55366-5ada-4d22-b9e8-e9ecac9da9dd','次韻和正仲種菜種麥二首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','賸欲栽蔬抵食魚，蠹繁骨立謾長吁。',64,'全唐诗/poet.song.227000.json','["賸欲栽蔬抵食魚，蠹繁骨立謾長吁。", "畦丁傴背揮叢篲，雞母將鶵啄淺蕪。", "菜字元修須雨長，菁名諸葛待霜腴。", "閉門欲喫無憂飯，已戒應門早了租。"]'),
('208e4b5c-ef37-4cc2-8ec7-50a8a81619b0','次韻和正仲種菜種麥二首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','稻畦已改翻泥細，麥隴初分趁勢斜。',64,'全唐诗/poet.song.227000.json','["稻畦已改翻泥細，麥隴初分趁勢斜。", "觳觫倦耕眠樹下，畢逋得食下天涯。", "嫩晴微雨調時序，臘雪春風潤土砂。", "避地山村成保社，倚需湯餠及鄰家。"]'),
('098e8d52-cae4-4ddd-97fe-538c8c089def','賦葦','舒岳祥','宋','宋诗','song-poetry','','[]','山居種葦意如何，相見滄江渺渺波。',64,'全唐诗/poet.song.227000.json','["山居種葦意如何，相見滄江渺渺波。", "窗外近移秋色早，夜來偏覺雨聲多。", "微風動葉蜻蜓立，暗浪衝根郭索過。", "誰解寫成團扇面，蕭蕭殘雪卧漁蓑。"]'),
('d1a2da1b-04ec-48f2-90f6-5f3319346820','三月三日欲過小園聞海棠未開翦韭獨酌有懷','舒岳祥','宋','宋诗','song-poetry','','[]','尋芳自是少閑身，世故紛紛更咈人。',64,'全唐诗/poet.song.227000.json','["尋芳自是少閑身，世故紛紛更咈人。", "一筯小園初韭脆，三杯荒舍晚醅新。", "雲藏柳葉裁難斷，月入梨花辨不真。", "每歲海棠時候近，今年寒重殿餘春。"]'),
('3c73a065-d028-41ff-bf2b-42e08cbd0de6','九日懷故人留燕京者','舒岳祥','宋','宋诗','song-poetry','','[]','青山淡佇半簾雨，碧樹嬋娟一院陰。',64,'全唐诗/poet.song.227000.json','["青山淡佇半簾雨，碧樹嬋娟一院陰。", "醉舞狂歌前日事，微吟淺酌此時心。", "菊花儘晚秋有味，楓葉尚彊霜著林。", "萬里故人關塞隔，賓鴻應有寄來音。"]'),
('345cafbb-5df6-4a59-a076-d842b52cfc38','苦牙動詩','舒岳祥','宋','宋诗','song-poetry','','[]','身心自縛似芭蕉，安得凌風歷九霄。',64,'全唐诗/poet.song.227000.json','["身心自縛似芭蕉，安得凌風歷九霄。", "閑戶人隨春去老，倚闌花向雨中消。", "病牙臲卼活書板，童頂羸垂倒藥瓢。", "善謔偶然成句子，叢談聊以永今朝。"]'),
('97c5d3ee-a5a0-4c5b-8257-6e7d02ba9d8f','八月初十日瘧起行園','舒岳祥','宋','宋诗','song-poetry','','[]','瘧鬼自與詩人謔，小兒狡獪弄炎凉。',64,'全唐诗/poet.song.227000.json','["瘧鬼自與詩人謔，小兒狡獪弄炎凉。", "蔬肥夜雨園丁逸，果熟秋風稚子忙。", "枕臂閒思新藥竈，扶頭欲起候茶槍。", "故園青桂華如水，歸汎天風浩蕩香。"]'),
('785f4963-dc7c-4c71-a186-cdc05dd89f35','喜聞鄰家食早麥','舒岳祥','宋','宋诗','song-poetry','','[]','七十三翁飲上池，始知糠籺也生肥。',64,'全唐诗/poet.song.227000.json','["七十三翁飲上池，始知糠籺也生肥。", "麥鬚似筆山雌下，荷葉如錢海鳦飛。", "天運無窮人自老，川流不返志多違。", "舊時此日嘗新日，蚤筍窗前一尺圍。"]'),
('3c6d1160-7a77-4008-91cd-d5d94aef1c15','正月十日新晴觀正仲所寫篆畦藁','舒岳祥','宋','宋诗','song-poetry','','[]','亂離又活十年身，帝閔吾徒已甚仁。',64,'全唐诗/poet.song.227000.json','["亂離又活十年身，帝閔吾徒已甚仁。", "近厚施爲回世運，至和涵養合天真。", "花間醉客能騎馬，柳外鳴禽似喚人。", "酬唱小編情性好，伊祁留得一分春。"]'),
('1fba0872-1379-451d-812b-0afc20b8e9ca','寶相花','舒岳祥','宋','宋诗','song-poetry','','[]','春風不到上林花，流落民間日又斜。',64,'全唐诗/poet.song.227000.json','["春風不到上林花，流落民間日又斜。", "曾向玉堂承雨露，可堪金屋委塵沙。", "生來富貴由天分，到底風流出內家。", "莫訝綠繁傷手刺，幽貞難犯可吁嗟。"]'),
('a9c07ed4-c7ba-4701-bab6-0d5ce47a9d12','兒曹請賦草間黄花','舒岳祥','宋','宋诗','song-poetry','','[]','樹頭綠葉無花看，樹下黄花带葉開。',64,'全唐诗/poet.song.227000.json','["樹頭綠葉無花看，樹下黄花带葉開。", "火化新錢忘鑄字，金成小盞欠施臺。", "貴人亭館何曾識，野客園林不用栽。", "鬭草兒曹求入詠，蒼苔留坐獨徘徊。"]'),
('eaed72f1-4908-4742-bd27-a16b850bb005','賦杜若花','舒岳祥','宋','宋诗','song-poetry','','[]','汀州春晚樂忘歸，野草幽花興趣微。',64,'全唐诗/poet.song.227000.json','["汀州春晚樂忘歸，野草幽花興趣微。", "翠葉參差舒鳳翮，斑心點綴戲兒衣。", "掌中玉燕翩將舞，釵上銀蛾亂欲飛。", "便想此身爲釣叟，滄江煙雨白鷗磯。"]'),
('6b505da9-c372-4c6a-9d0d-3252f25a1726','喻客','舒岳祥','宋','宋诗','song-poetry','','[]','踏雪相過客定嘉，瓦燈何事凍成花。',64,'全唐诗/poet.song.227000.json','["踏雪相過客定嘉，瓦燈何事凍成花。", "捕螳者雀雀憂彈，甘带爲且且畏蟆。", "寒拾相逢成一笑，觸蠻互勝足長嗟。", "人生只是爭名利，名利看來細似麻。"]'),
('1c357ccf-e6b1-46bc-8c37-3bb465937941','晚晴','舒岳祥','宋','宋诗','song-poetry','','[]','九十日春長雨雪，喜君今日詠新晴。',64,'全唐诗/poet.song.227000.json','["九十日春長雨雪，喜君今日詠新晴。", "綠陰四面招人坐，芳草前頭試我行。", "少駐飛花終有別，愛聽啼鳥忽無聲。", "東坡已作秋陽賦，欲賦春陽恨未成。"]'),
('45856c27-2460-4d6f-a492-640440f13a2f','歸故園  其一','舒岳祥','宋','宋诗','song-poetry','','[]','千家桑梓兵餘痛，十世松楸火後悲。',64,'全唐诗/poet.song.227000.json','["千家桑梓兵餘痛，十世松楸火後悲。", "瓦礫成灘無鳥雀，荆蒿如杖有狐狸。", "咸平樹在枝柯損，晚易書亡目錄遺。", "半樹瑶花微雨裏，向誰寂寞淚將垂。"]'),
('4784af8a-9dd5-4127-9629-8f98b741b35d','歸故園  其二','舒岳祥','宋','宋诗','song-poetry','','[]','辟兵辟寇走他方，六遍移家路轉長。',64,'全唐诗/poet.song.227000.json','["辟兵辟寇走他方，六遍移家路轉長。", "百醉與君同出處，五窮隨我共行藏。", "柳花暗度誰家竹，燕子寒歸何處梁。", "最羨劉家好男女，穩拋家事客原嘗。"]'),
('5b15c635-7a82-49e4-bfcc-c7439f126ab0','四月一日霖潦新霽痼疾稍瘳乍歸故園拂剔叢莽','舒岳祥','宋','宋诗','song-poetry','','[]','衰翁病起頭初裹，拄杖穿林探笋生。',64,'全唐诗/poet.song.227000.json','["衰翁病起頭初裹，拄杖穿林探笋生。", "悄悄菰蒲看鳥下，疎疎楊柳見人行。", "一春長雨花全瘦，半日佳晴蝶便輕。", "小立綠陰青子下，穠華洗盡總幽情。"]'),
('165ede96-dc19-4bf8-abe0-4ac8f75b74a8','和正仲詠荷','舒岳祥','宋','宋诗','song-poetry','','[]','曾聞畫史傳真訣，一葉旁邊定一花。',64,'全唐诗/poet.song.227000.json','["曾聞畫史傳真訣，一葉旁邊定一花。", "莫把風晴拘格範，好於月露寫精華。", "耶溪舴艋花間屋，苕水鴛鴦葉底家。", "浙水東西江路絕，坐吟濂說自咨嗟。"]'),
('556a9c17-2baf-4553-bee0-49442cc50a81','夜讀達善燒痕漫抄次來韻奉謝','舒岳祥','宋','宋诗','song-poetry','','[]','桓桓松柏歲寒知，白髮相逢也自奇。',64,'全唐诗/poet.song.227000.json','["桓桓松柏歲寒知，白髮相逢也自奇。", "猶記小儒曾共勘，絕憐後藁未全窺。", "斯文定價何必我，自古趨名存者誰。", "惟有立言差不朽，夫君此計未應癡。"]'),
('17987d52-f91c-4704-bf61-356d65f47ee4','次韻山甫松石','舒岳祥','宋','宋诗','song-poetry','','[]','浮榮流潦一盈科，獨此堅貞歲月多。',64,'全唐诗/poet.song.227000.json','["浮榮流潦一盈科，獨此堅貞歲月多。", "入土同時成琥珀，爲槎何日到天河。", "英靈真是隨星隕，磥砢誰能把劍磨。", "今日尚疑龍蛻骨，當年曾見鶴成窠。"]'),
('7d186282-90cc-42fe-aa2d-6407997516b5','次正仲別後見寄韻','舒岳祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','同聽精舍對牀雨，憶著西湖一舸天。',64,'全唐诗/poet.song.227000.json','["同聽精舍對牀雨，憶著西湖一舸天。", "何必錢神能使鬼，只須酒聖與逃禪。", "作文自昔少稱意，種學何時大有年。", "凍餓一生祇百歲，聲名須在後來傳。"]'),
('72487f4e-15e7-4299-94ed-e6defacca47e','庚辰冬帥初與正仲約過閬風既而予坐病二友亦不果至辛巳四月帥初特來訪予時尚在病中爲予留山庵一宿而去似不欲勞予應酬耳歸至中涂有詩見寄予次韻因貽正仲也','舒岳祥','宋','宋诗','song-poetry','','[]','杜宇啼時多是雨，酴醿開後便無春。',64,'全唐诗/poet.song.227000.json','["杜宇啼時多是雨，酴醿開後便無春。", "惜花底學千金子，對酒還思兩玉人。", "良藥草中閑長葉，幽禽花裏巧藏身。", "青山百里通來往，衰病何曾厭客頻。"]'),
('3307816e-8ad3-4e42-b20f-2c7018821114','正仲次帥初前韻見示數日相訪再次韻酬之','舒岳祥','宋','宋诗','song-poetry','','[]','絕憐幽谷此相親，屋角來禽作小春。',64,'全唐诗/poet.song.227000.json','["絕憐幽谷此相親，屋角來禽作小春。", "梅笑故知情熟客，犬迎不是眼生人。", "青燈知子別來意，烏几扶吾病後身。", "莫怪柴門長日掩，俗交正復厭頻頻。"]'),
('3563708e-ad4a-4141-b030-dd0e5bb09d71','次韻','舒岳祥','宋','宋诗','song-poetry','','[]','兒時人道是奇童，末路翻成毦𦗵翁。',64,'全唐诗/poet.song.227000.json','["兒時人道是奇童，末路翻成毦𦗵翁。", "燕去燕來催歲月，花開花落共春風。", "有金斑鬢難重綠，無酒衰顔肯更紅。", "夢境如今親歷過，何須學佛更談空。"]'),
('b1581918-79e4-42e9-87a0-be13dd04475c','金線草','舒岳祥','宋','宋诗','song-poetry','','[]','金線比方渾未盡，玉函收錄尚多遺。',96,'全唐诗/poet.song.227000.json','["金線比方渾未盡，玉函收錄尚多遺。", "盈盈蜂蝶菩提葉，裊裊蜻蜓菡萏枝。", "寒女有針縫不得，山人無衮補何爲。", "芝莖底事生庭砌，蓴葉胡爲上井湄。", "剪綵不香難作實，垂絲著石便生兒。", "莫輕小草沿幽僻，也有凌霜傲雪姿。"]'),
('0e268de6-7dbc-4669-92b6-3ada14a9643f','綠陰','舒岳祥','宋','宋诗','song-poetry','','[]','穉綠藉老紅，政爾有餘妍。',24,'全唐诗/poet.song.227000.json','["穉綠藉老紅，政爾有餘妍。", "萬慮不作時，清朗見堯天。"]'),
('e68a008a-5bc4-4473-a1e2-c2ffd21cd4a0','荷亭','舒岳祥','宋','宋诗','song-poetry','','[]','影浸蒼凉月，香隨澹蕩風。',24,'全唐诗/poet.song.227000.json','["影浸蒼凉月，香隨澹蕩風。", "露華初汎汎，秋思莫匆匆。"]'),
('5f74d641-7403-467c-9743-3bb684bc3bb3','丙子兵禍台溫爲烈寧海雖經焚掠然耕者不廢丁丑粗爲有秋但種秫者少以醉人爲瑞物吾亦似陶靖節時或無酒雅詠不輟也八月初九日連日雷雨溪路阻絕山房岑寂此夕初霽濁酒新漉數酌竟步秋樹陰潭魚可數望前峰老楓數十株已無色白鳥飛翻去來是中有惠崇大年筆家人遣兩力來迎因倒坐籃輿而歸人或問之戲答曰吾日莫途遠故倒行也記以三絕  其一','舒岳祥','宋','宋诗','song-poetry','','[]','事過清眠足，心寬緩步宜。',24,'全唐诗/poet.song.227000.json','["事過清眠足，心寬緩步宜。", "古人無限事，煙蹙幾修眉。"]'),
('19afa1af-de16-46e0-83a2-48669461ae31','丙子兵禍台溫爲烈寧海雖經焚掠然耕者不廢丁丑粗爲有秋但種秫者少以醉人爲瑞物吾亦似陶靖節時或無酒雅詠不輟也八月初九日連日雷雨溪路阻絕山房岑寂此夕初霽濁酒新漉數酌竟步秋樹陰潭魚可數望前峰老楓數十株已無色白鳥飛翻去來是中有惠崇大年筆家人遣兩力來迎因倒坐籃輿而歸人或問之戲答曰吾日莫途遠故倒行也記以三絕  其二','舒岳祥','宋','宋诗','song-poetry','','[]','去鳥仍回白，殘陽更借紅。',24,'全唐诗/poet.song.227000.json','["去鳥仍回白，殘陽更借紅。", "傷今兵亂後，人醉不如楓。"]'),
('7c257c92-d52a-4fa4-b24e-40496cc725dc','丙子兵禍台溫爲烈寧海雖經焚掠然耕者不廢丁丑粗爲有秋但種秫者少以醉人爲瑞物吾亦似陶靖節時或無酒雅詠不輟也八月初九日連日雷雨溪路阻絕山房岑寂此夕初霽濁酒新漉數酌竟步秋樹陰潭魚可數望前峰老楓數十株已無色白鳥飛翻去來是中有惠崇大年筆家人遣兩力來迎因倒坐籃輿而歸人或問之戲答曰吾日莫途遠故倒行也記以三絕  其三','舒岳祥','宋','宋诗','song-poetry','','[]','白兔秋毫綻，青蟲樹色并。',24,'全唐诗/poet.song.227000.json','["白兔秋毫綻，青蟲樹色并。", "興亡誰與弔，聊復快新晴。"]'),
('0c24364f-4813-4353-ade1-1871d30697b3','花下','舒岳祥','宋','宋诗','song-poetry','','[]','掃石坐花陰，花陰復滿襟。',24,'全唐诗/poet.song.227000.json','["掃石坐花陰，花陰復滿襟。", "此時真晝錦，富貴亦何心。"]'),
('6fc6272e-dba4-48ce-a786-43bb47adc574','八月初十日夜露坐場圃新月半破前溪夜舂俯仰寥泬小兒子周在側忽引翁袖曰月照山重也聊記其語','舒岳祥','宋','宋诗','song-poetry','','[]','露葉墮清響，隔烟聞暝舂。',24,'全唐诗/poet.song.227000.json','["露葉墮清響，隔烟聞暝舂。", "夕嵐那可撥，月照山重重。"]'),
('1f438d53-5f3b-4f87-89a8-603deb817d6b','柘溪道中有感','舒岳祥','宋','宋诗','song-poetry','','[]','得勢茅欺蕙，安居爵笑鴻。',24,'全唐诗/poet.song.227000.json','["得勢茅欺蕙，安居爵笑鴻。", "吾年已如此，役役又西東。"]'),
('7457f139-9ec7-4284-8d8b-362b89dccade','即事','舒岳祥','宋','宋诗','song-poetry','','[]','菜花隨麥長，田水入池平。',24,'全唐诗/poet.song.227000.json','["菜花隨麥長，田水入池平。", "此景尋常有，何人自在行。"]'),
('b5cc3941-7393-4b18-9339-ff053465a591','題李唐松月','舒岳祥','宋','宋诗','song-poetry','','[]','明月青松枝，幽人巖下步。',24,'全唐诗/poet.song.227000.json','["明月青松枝，幽人巖下步。", "勸君早歸來，草頭已多露。"]'),
('34d4f9f5-7538-4842-8e98-9163c2bce971','懶出','舒岳祥','宋','宋诗','song-poetry','','[]','飛霧不成雨，幽人懶出谿。',24,'全唐诗/poet.song.227000.json','["飛霧不成雨，幽人懶出谿。", "落紅雙雉過，新綠一鵑啼。"]'),
('2d968fb0-3866-4914-bb4b-ca2bcceb6da5','宿龜石寺','舒岳祥','宋','宋诗','song-poetry','','[]','山深無橫吏，客至氣和平。',24,'全唐诗/poet.song.227000.json','["山深無橫吏，客至氣和平。", "野寺鳴鐘罷，安眠到五更。"]'),
('cdf1acba-e5c9-4679-8bd4-751fdd023d2b','齒酬舌贈','舒岳祥','宋','宋诗','song-poetry','','[]','子任調和逸，吾當噬嗑勞。',24,'全唐诗/poet.song.227000.json','["子任調和逸，吾當噬嗑勞。", "生年雖後子，未老得先焦。"]'),
('3807eb9b-bbc3-4c98-ab8f-e2c9dcf86b32','齒酬唇贈','舒岳祥','宋','宋诗','song-poetry','','[]','剛柔君不吐，冷熱我須當。',24,'全唐诗/poet.song.227000.json','["剛柔君不吐，冷熱我須當。", "鐵石還銷毀，吾今已久長。"]'),
('61199e91-baa6-40d1-9eb2-005400d03931','白雪詞四首  其一','舒岳祥','宋','宋诗','song-poetry','','[]','一雪林屋浄，二雪臯隰新。',24,'全唐诗/poet.song.227000.json','["一雪林屋浄，二雪臯隰新。", "三雪爲瑞應，伊耆氏作春。"]'),
('5ec54ef8-044e-408a-9a8a-71b0e0772627','白雪詞四首  其二','舒岳祥','宋','宋诗','song-poetry','','[]','濛濛接白雲，皎皎混清月。',24,'全唐诗/poet.song.227000.json','["濛濛接白雲，皎皎混清月。", "長歌古人句，山明望松雪。"]'),
('5defa5f5-6d89-4501-a396-d108869b8424','白雪詞四首  其三','舒岳祥','宋','宋诗','song-poetry','','[]','半空紛下鶴，千尺矯遊龍。',24,'全唐诗/poet.song.227000.json','["半空紛下鶴，千尺矯遊龍。", "再歌古人句，晴雪落長松。"]'),
('5d0e6499-1109-49e6-bfa6-697b4237f566','白雪詞四首  其四','舒岳祥','宋','宋诗','song-poetry','','[]','古人不可見，物色故依然。',24,'全唐诗/poet.song.227000.json','["古人不可見，物色故依然。", "二麥何人種，忍凍及豐年。"]'),
